
import React, { useState, useEffect, useRef, useReducer, useCallback, useMemo } from "react";
import { Preferences } from "@capacitor/preferences";

// ─── window.storage → Capacitor Preferences shim ─────────────────────────────
// Menjaga semua kode lama (window.storage.get/set/delete) tetap berjalan
// di Android native via Capacitor, dengan fallback ke in-memory jika gagal.
window.storage = {
  async get(key) {
    try {
      const { value } = await Preferences.get({ key });
      return value != null ? { key, value } : null;
    } catch { return null; }
  },
  async set(key, value) {
    try {
      await Preferences.set({ key, value: String(value) });
      return { key, value };
    } catch { return null; }
  },
  async delete(key) {
    try {
      await Preferences.remove({ key });
      return { key, deleted: true };
    } catch { return null; }
  },
  async list(prefix) {
    try {
      const { keys } = await Preferences.keys();
      const filtered = prefix ? keys.filter(k => k.startsWith(prefix)) : keys;
      return { keys: filtered };
    } catch { return { keys: [] }; }
  }
};
