(function installL0Shield() {
  const SHIELD_ID = "__yuyu_l0_shield";

  function showShield(msg, src, lineno, colno) {
    if (window.__yuyuMounted) return;
    let el = document.getElementById(SHIELD_ID);
    if (!el) {
      el = document.createElement("div");
      el.id = SHIELD_ID;
      el.style.cssText = [
        "position:fixed","inset:0","z-index:2147483647",
        "background:#060208","color:#e8d5f0",
        "font-family:'Courier New',monospace",
        "display:flex","flex-direction:column",
        "align-items:center","justify-content:center",
        "padding:24px 16px","overflow-y:auto","text-align:center",
      ].join(";");

      const root = document.getElementById("root") || document.body;
      root.appendChild(el);
    }
    const loc = (src || "") + (lineno ? ":" + lineno : "") + (colno ? ":" + colno : "");
    const isParse = msg && (msg.includes("Unexpected token") || msg.includes("SyntaxError") || msg.includes("Unexpected end"));
    const color   = isParse ? "#facc15" : "#f87171";
    const cat     = isParse ? "Parse / Syntax Error" : "Fatal Load Error";
    el.innerHTML = [
      "<div style='max-width:480px;width:100%'>",
      "  <div style='font-size:36px;margin-bottom:12px'>💔</div>",
      "  <p style='font-size:15px;color:" + color + ";font-family:Georgia,serif;font-style:italic;margin-bottom:6px'>Ada yang crash sebelum Yuyu sempat muncul...</p>",
      "  <span style='display:inline-block;padding:4px 14px;border-radius:99px;background:" + color + "18;border:1px solid " + color + "44;color:" + color + ";font-size:9px;letter-spacing:.18em;font-weight:700;margin-bottom:16px'>" + cat.toUpperCase() + "</span>",
      "  <div style='background:rgba(0,0,0,.45);border:1px solid rgba(255,255,255,.08);border-radius:12px;padding:12px 14px;margin-bottom:10px;text-align:left'>",
      "    <p style='font-size:8px;color:rgba(200,140,180,.7);letter-spacing:.2em;margin-bottom:6px'>PESAN ERROR</p>",
      "    <p style='font-size:11px;color:#fde68a;word-break:break-all;line-height:1.7'>" + (msg || "Unknown error") + "</p>",
      "  </div>",
      loc ? "  <div style='background:rgba(0,0,0,.35);border:1px solid rgba(255,255,255,.06);border-radius:12px;padding:10px 14px;margin-bottom:10px;text-align:left'><p style='font-size:8px;color:rgba(200,140,180,.7);letter-spacing:.2em;margin-bottom:4px'>LOKASI</p><p style='font-size:10px;color:#c084fc;word-break:break-all'>" + loc + "</p></div>" : "",
      isParse ? "  <div style='background:rgba(251,191,36,.04);border:1px solid rgba(251,191,36,.15);border-radius:12px;padding:10px 14px;margin-bottom:14px;text-align:left'><p style='font-size:9px;color:rgba(251,191,36,.6);line-height:1.8'>💡 <strong>Parse error</strong> terjadi saat file JSX dikompilasi — sebelum React bisa berjalan sama sekali. Biasanya ada JSX atau template literal yang tidak valid.</p></div>" : "",
      "  <div style='display:flex;gap:8px;justify-content:center;flex-wrap:wrap'>",
      "    <button onclick='window.location.reload()' style='padding:11px 20px;border-radius:12px;cursor:pointer;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.06);color:rgba(220,180,200,.75);font-size:11px;font-family:Courier New,monospace'>🔄 Reload</button>",
      "    <button onclick='(async()=>{try{if(window.storage){await window.storage.delete(\"yuyu-game-v7\");}}catch(e){}window.location.reload()})()' style='padding:11px 20px;border-radius:12px;cursor:pointer;border:1px solid rgba(248,113,113,.2);background:rgba(248,113,113,.06);color:rgba(248,113,113,.65);font-size:11px;font-family:Courier New,monospace'>🗑 Reset Save</button>",
      "  </div>",
      "</div>",
    ].join("");
  }

  const _prevOnError = window.onerror;
  window.onerror = function(msg, src, lineno, colno, error) {
    const m = (error && error.message) || msg || "";
    window.__yuyuEarlyErrors.push({ msg: m, src, lineno, colno, ts: new Date().toISOString() });
    showShield(m, src, lineno, colno);
    if (typeof _prevOnError === "function") _prevOnError.apply(this, arguments);
    return false;
  };

  window.addEventListener("unhandledrejection", function(ev) {
    const msg = (ev.reason && ev.reason.message) || String(ev.reason) || "Unhandled Promise Rejection";
    if (msg.includes("ResizeObserver") || msg.includes("AbortError") || msg.includes("storage")) return;
    window.__yuyuEarlyErrors.push({ msg, ts: new Date().toISOString(), type: "unhandledrejection" });
    showShield(msg, "", 0, 0);
  });

  setTimeout(function() {
    if (!window.__yuyuMounted && !document.getElementById(SHIELD_ID)) {
      showShield("Yuyu tidak muncul dalam 4 detik — mungkin ada error tersembunyi.", "", 0, 0);
    }
  }, 4000);
})();


