const _VALID_MOODS    = new Set(["biasa","senang","malu","mengantuk","playful","lapar","rindu","sakit","kangen","excited"]);
const _VALID_LOCS     = new Set(["kamar","dapur","ruang","teras","kamar_mandi","kafe","taman","pantai"]);
const _VALID_HEALTH   = new Set(["prima","capek","sakit","recovered"]);
const _ARRAY_FIELDS   = ["memories","achievements","questsDone","specialMoments","eventLog",
  "affectionHistory","silenceMoments","missedMoments","failedArcs","repairArcs",
  "memoryThreads","innerWorldLog","arcArtifacts","dialogEchoes","griefLog",
  "sessionMemoirs","kitaDictionary","fingerprintHistory","crystallizedMemories",
  "sedimentLog","streakRewardClaimed","overflowUnlocked","goldenHoursSeen",
  "temporalReflectionsSeen","circadianSessions","arcInheritances","blindspotOccurrences","memoryLog",
  "seasonActionsUsed","offlineCatchupEvents",
  "suppressedLayer","silenceMomentsTyped","sessionHistory","fingerprintObservations"];

function normalizeGameState(gs) {
  if (!gs || typeof gs !== "object") {
    console.warn("[P0 Normalize] Invalid game state input:", typeof gs);
    return null;
  }
  const s = { ...gs };

  const clamp  = (v, lo, hi, fb) => Math.max(lo, Math.min(hi, Number(v) || fb));
  const floor0 = (v, fb)         => Math.max(0, Number(v) || fb);

  s.affection         = clamp (s.affection,         0, 100, 10);
  s.overflowAffection = floor0(s.overflowAffection,        0);
  s.hunger            = clamp (s.hunger,            0, 100, 70);
  s.money             = floor0(s.money,                   100);
  s.yuyuMoney         = floor0(s.yuyuMoney,               500);
  s.day               = Math.max(1, Number(s.day)          || 1);
  s.streak            = floor0(s.streak,                    0);
  s.timeIdx           = clamp (s.timeIdx,           0,   4,  0);
  s.emotionalDistance = clamp (s.emotionalDistance, 0, 100,  0);
  s.moodIntensity     = clamp (s.moodIntensity,     0, 100, 50);
  s.yuyuFatigue       = floor0(s.yuyuFatigue,               0);
  s.papaHunger        = clamp (s.papaHunger,        0, 100, 70);
  s.papaLoneliness    = clamp (s.papaLoneliness,    0, 100,  0);
  s.papaEnergy        = clamp (s.papaEnergy,        0, 100, 70);
  s.silenceCount      = floor0(s.silenceCount,              0);
  s.highDistanceDays  = floor0(s.highDistanceDays,          0);

  if (!_VALID_MOODS.has(s.mood)) {
    console.warn(`[P0] Invalid mood "${s.mood}", resetting to "biasa"`);
    s.mood = "biasa";
  }
  if (!_VALID_LOCS.has(s.locationId)) {
    console.warn(`[P0] Invalid locationId "${s.locationId}", resetting to "kamar"`);
    s.locationId = "kamar";
  }
  if (!_VALID_LOCS.has(s.yuyuLocationId)) {
    console.warn(`[P0] Invalid yuyuLocationId "${s.yuyuLocationId}", resetting to "kamar"`);
    s.yuyuLocationId = "kamar";
  }
  if (!_VALID_HEALTH.has(s.yuyuHealthState)) {
    console.warn(`[P0] Invalid health state "${s.yuyuHealthState}", resetting to "prima"`);
    s.yuyuHealthState = "prima";
  }

  if (typeof s.yuyuWorking !== "boolean") {
    console.debug(`[P0] yuyuWorking is ${typeof s.yuyuWorking}, resetting to false`);
    s.yuyuWorking = false;
  }
  if (typeof s.yuyuTraveling !== "boolean") {
    console.debug(`[P0] yuyuTraveling is ${typeof s.yuyuTraveling}, resetting to false`);
    s.yuyuTraveling = false;
  }

  for (const f of _ARRAY_FIELDS) {
    if (!Array.isArray(s[f])) {
      console.warn(`[P0] Field "${f}" is not an array, resetting`);
      s[f] = [];
    }
  }

  if (!s.weather || typeof s.weather !== "object") {
    console.debug("[P0] Weather object invalid, resetting");
    s.weather = {id:"cerah",label:"Cerah",icon:"☀️",moodBonus:"senang",affectionBonus:2,hungerMod:0};
  }
  if (!s.actionFrequency || typeof s.actionFrequency !== "object") {
    console.debug("[P0] actionFrequency invalid, resetting");
    s.actionFrequency = {};
  }
  if (!s.locationFrequency || typeof s.locationFrequency !== "object") {
    console.debug("[P0] locationFrequency invalid, resetting");
    s.locationFrequency = {};
  }
  if (!s.dayOfWeekBonus || typeof s.dayOfWeekBonus !== "object") {
    console.debug("[P0] dayOfWeekBonus invalid, resetting");
    s.dayOfWeekBonus = {};
  }
  if (!s.emergentScenarioSeen || typeof s.emergentScenarioSeen !== "object") {
    console.debug("[P0] emergentScenarioSeen invalid, resetting");
    s.emergentScenarioSeen = {};
  }
  if (!s.workJobStreak || typeof s.workJobStreak !== "object") {
    console.debug("[P0] workJobStreak invalid, resetting");
    s.workJobStreak = {};
  }
  if (!s.apartments || typeof s.apartments !== "object") {
    console.debug("[P0] apartments invalid, resetting");
    s.apartments = {};
  }
  if (!s.sessionTrajectory || typeof s.sessionTrajectory !== "object") {
    console.debug("[P0] sessionTrajectory invalid, resetting");
    s.sessionTrajectory = {shape:"steady",affDelta:0};
  }

  return s;
}

const _AI_TIMEOUT_MS = 18000;

async function callClaudeAISafe(systemPrompt, userMsg, history = []) {
  const ctrl  = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), _AI_TIMEOUT_MS);
  try {
    const result = await callClaudeAPI(systemPrompt, userMsg, history, ctrl.signal);
    clearTimeout(timer);
    if (typeof result !== "string") throw new Error("AI response bukan string");
    return result;
  } catch (e) {
    clearTimeout(timer);
    if (e?.name === "AbortError") throw new Error("AI timeout — coba lagi");
    throw e;
  }
}

