let rainNode=null;
function startRain(audioContext, gain) {
  if (rainNode) return;
  const rainNoise=createNoise(audioContext,"white",4);
  const rainGain=audioContext.createGain();
  rainGain.gain.value=0;
  rainGain.gain.linearRampToValueAtTime(0.125,audioContext.currentTime+2);
  const rainFilter=audioContext.createBiquadFilter();
  rainFilter.type="lowpass";
  rainFilter.frequency.value=3000;
  rainNoise.connect(rainFilter);
  rainFilter.connect(rainGain);
  rainGain.connect(gain);
  rainNoise.start();
  rainNode={stop:()=>{
    rainGain.gain.linearRampToValueAtTime(0,audioContext.currentTime+1.5);
    setTimeout(()=>{ rainNoise.stop(); rainNode=null; },1700);
  }};
}
function stopRain() {
  if(rainNode){
    const capturedRainNode=rainNode;
    rainNode=null;
    try{capturedRainNode.stop();}catch{}
  }
}

const _AMBIENT_FN_MAP = {
  kamar:       makeAmbientKamar,
  dapur:       makeAmbientDapur,
  ruang:       makeAmbientRuang,
  teras:       makeAmbientTeras,
  kamar_mandi: makeAmbientKamarMandi,
  kafe:        makeAmbientKafe,
  taman:       makeAmbientTaman,
  pantai:      makeAmbientPantai,
};
function startAmbient(locationId, timeId, weather) {
  if (!audioContext||!ambientGain) return; resumeAudio();
  if (currentAmbient){currentAmbient.stop();currentAmbient=null;} stopRain();
  const night = timeId==="malam"||timeId==="tengmalam";
  const fn    = _AMBIENT_FN_MAP[locationId];
  currentAmbient = fn
    ? (locationId==="kamar_mandi" ? fn(audioContext,ambientGain) : fn(audioContext,ambientGain,night))
    : makeAmbientGeneric(audioContext,ambientGain,SCALES.warm);
  if (weather?.id==="hujan") startRain(audioContext,ambientGain);
}
function stopAmbient() { try{if(currentAmbient){currentAmbient.stop();currentAmbient=null;}}catch{} stopRain(); }

