// ============================================================
// PIANO SYSTEM — Synthesized piano, zero external deps
// Uses Web Audio API: triangle+sine harmonics + ADSR envelope
// ============================================================

let pianoGain    = null;
let _pianoActive = false;
let _pianoCurrentId = null;
let _pianoLooping   = true;
let _pianoVol       = 0.35;
let _pianoTimerId   = null;
let _pianoGen       = 0;
const _pianoListeners = new Set();
function _pianoNotify() { _pianoListeners.forEach(fn=>{ try{fn();}catch(_){} }); }

let _pianoReverb = null;


function usePianoState() {
  const [tick, setTick] = React.useState(0);
  React.useEffect(()=>{
    const h = ()=>setTick(t=>t+1);
    _pianoListeners.add(h);
    return ()=>_pianoListeners.delete(h);
  },[]);
  return {active:_pianoActive, id:_pianoCurrentId, vol:_pianoVol, loop:_pianoLooping};
}

function setPianoVolume(v) {
  _pianoVol = Math.max(0, Math.min(1, v));
  if (pianoGain) pianoGain.gain.value = _pianoVol;
  _pianoNotify();
}

function setPianoLoop(v) { _pianoLooping = v; _pianoNotify(); }

function _initPianoGain() {
  if (!audioContext) initAudio();
  if (!pianoGain && audioContext) {
    pianoGain = audioContext.createGain();
    pianoGain.gain.value = _pianoVol;

    // Warm EQ: boost body, cut harshness
    const eq = audioContext.createBiquadFilter();
    eq.type = 'peaking'; eq.frequency.value = 220; eq.Q.value = 0.8; eq.gain.value = 5;
    const hiCut = audioContext.createBiquadFilter();
    hiCut.type = 'highshelf'; hiCut.frequency.value = 3200; hiCut.gain.value = -5;

    // Reverb impulse (small hall, 1.2s)
    _pianoReverb = audioContext.createConvolver();
    try {
      const rate = audioContext.sampleRate;
      const ir = audioContext.createBuffer(2, Math.floor(rate*1.2), rate);
      for (let ch=0;ch<2;ch++){const d=ir.getChannelData(ch);for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/d.length,2.8);}
      _pianoReverb.buffer = ir;
    } catch(_) {}

    const dry = audioContext.createGain(); dry.gain.value = 0.84;
    const wet = audioContext.createGain(); wet.gain.value = 0.16;

    pianoGain.connect(eq);
    eq.connect(hiCut);
    hiCut.connect(dry);
    hiCut.connect(_pianoReverb);
    _pianoReverb.connect(wet);
    dry.connect(masterGain);
    wet.connect(masterGain);
  }
}


// ── Lookahead scheduler state ───────────────────────────────────────────────
const LOOKAHEAD_SEC  = 1.5;   // how far ahead to schedule
const SCHEDULE_MS    = 200;   // how often the scheduler runs
let _pianoNoteIdx    = 0;     // index into current piece's notes array
let _pianoNextTime   = 0;     // audioContext time of next unscheduled note

// ── Lightweight synthesis: 4 harmonics, no convolver per-note ───────────────
function _synthPianoNote(ctx, dest, freq, when, dur, vel) {
  if (!freq || freq <= 0) return;
  vel = vel ?? 0.65;

  // Stereo pan: bass-left / treble-right (log scale, ±0.65)
  let out = dest;
  if (ctx.createStereoPanner) {
    const pan = ctx.createStereoPanner();
    pan.pan.value = Math.max(-0.65, Math.min(0.65, Math.log2(freq / 261.63) * 0.18));
    pan.connect(dest);
    out = pan;
  }

  // Inharmonicity (real string physics)
  const B = 0.00014;
  const fInharm = (n) => freq * n * Math.sqrt(1 + B * n * n);

  // 4 harmonics — enough warmth without CPU overload
  // [ratio, weight]
  const H = [[1,0.58],[2,0.22],[3,0.12],[4,0.06]];
  const bright = 0.55 + vel * 0.45;

  H.forEach(([n, w]) => {
    try {
      const osc = ctx.createOscillator();
      osc.type = n === 1 ? 'triangle' : 'sine';
      osc.frequency.value = fInharm(n);

      const decayMult = 1 + (n - 1) * 0.4;
      const rel   = Math.min(dur * 0.45 / decayMult + 0.1, 1.2 / decayMult);
      const total = dur + rel;

      const g = ctx.createGain();
      const peak = vel * w * (n === 1 ? 1 : bright);
      g.gain.setValueAtTime(0, when);
      g.gain.linearRampToValueAtTime(peak,        when + 0.003);
      g.gain.exponentialRampToValueAtTime(peak * 0.55, when + 0.055);
      g.gain.exponentialRampToValueAtTime(peak * 0.28, Math.max(when + dur * 0.65, when + 0.09));
      g.gain.exponentialRampToValueAtTime(0.0001,  when + total);

      osc.connect(g); g.connect(out);
      osc.start(when); osc.stop(when + total + 0.04);
    } catch(_) {}
  });
}

// ── _schedulePiece: schedules only the window [fromTime, fromTime+LOOKAHEAD] ─
// Returns the audioContext time after the last scheduled note.
function _schedulePieceWindow(piece, fromTime) {
  const beatSec = 60 / piece.bpm;
  let t = _pianoNextTime;
  const until = fromTime + LOOKAHEAD_SEC;

  while (_pianoNoteIdx < piece.notes.length && t < until) {
    const [freq, beats, vel = 0.65] = piece.notes[_pianoNoteIdx];
    if (freq > 0) _synthPianoNote(audioContext, pianoGain, freq, t, beats * beatSec * 0.88, vel);
    t += beats * beatSec;
    _pianoNoteIdx++;
  }
  _pianoNextTime = t;
  return t;
}

const PN = (()=>{
  const semi = {C:0,Cs:1,D:2,Ds:3,E:4,F:5,Fs:6,G:7,Gs:8,A:9,As:10,B:11};
  const out = {R:0};
  for(let oct=2; oct<=6; oct++)
    for(const [n,s] of Object.entries(semi))
      out[n+oct] = 440 * Math.pow(2, (s + (oct-4)*12 - 9) / 12);
  return out;
})();

