// Schedule a full piece and return end time (in seconds)
function _schedulePiece(piece, startTime) {
  const beatSec = 60 / piece.bpm;
  let t = startTime;
  piece.notes.forEach(([freq, beats, vel=0.65])=>{
    _synthPianoNote(audioContext, pianoGain, freq, t, beats * beatSec * 0.88, vel);
    t += beats * beatSec;
  });
  return t;
}
function stopPiano() {
  _pianoGen++;
  if (_pianoTimerId) { clearInterval(_pianoTimerId); _pianoTimerId = null; }
  _pianoActive      = false;
  _pianoCurrentId   = null;
  _pianoNoteIdx     = 0;
  _pianoNextTime    = 0;

  // Gain ramp to silence (40ms — click-free)
  if (pianoGain && audioContext) {
    try {
      const now = audioContext.currentTime;
      pianoGain.gain.cancelScheduledValues(now);
      pianoGain.gain.setValueAtTime(pianoGain.gain.value, now);
      pianoGain.gain.linearRampToValueAtTime(0, now + 0.04);
    } catch(_) {}
  }
  _pianoNotify();
}

function playPianoPiece(id) {
  if (!audioContext) initAudio();
  _initPianoGain();
  if (!audioContext || !pianoGain) return;

  stopPiano();
  resumeAudio();

  // Restore gain after stop zeroed it
  const now = audioContext.currentTime;
  pianoGain.gain.cancelScheduledValues(now);
  pianoGain.gain.setValueAtTime(0, now);
  pianoGain.gain.linearRampToValueAtTime(_pianoVol, now + 0.04);

  const piece = PIANO_PIECES.find(p => p.id === id);
  if (!piece) return;

  _pianoActive    = true;
  _pianoCurrentId = id;
  _pianoNoteIdx   = 0;
  _pianoNextTime  = audioContext.currentTime + 0.06; // tiny start delay
  _pianoNotify();

  const myGen = _pianoGen;

  function tick() {
    if (_pianoGen !== myGen || !_pianoActive) return;

    const now = audioContext.currentTime;
    _schedulePieceWindow(piece, now);

    // Piece finished
    if (_pianoNoteIdx >= piece.notes.length) {
      if (_pianoLooping) {
        // Reset and immediately schedule start of next loop
        _pianoNoteIdx  = 0;
        _pianoNextTime = _pianoNextTime; // continues from where last note ended
        _schedulePieceWindow(piece, now);
      } else {
        // Wait until last note finishes, then stop
        const remaining = (_pianoNextTime - now) * 1000 + 400;
        setTimeout(() => {
          if (_pianoGen === myGen) { _pianoActive = false; _pianoCurrentId = null; _pianoNotify(); }
        }, Math.max(remaining, 0));
        if (_pianoTimerId) { clearInterval(_pianoTimerId); _pianoTimerId = null; }
      }
    }
  }

  // Run immediately (schedule first 1.5s), then every 200ms
  tick();
  _pianoTimerId = setInterval(tick, SCHEDULE_MS);
}

