const MOOD_INTENSITY_DECAY = 8;
const INTENSITY_PEAK_THRESHOLD = 75;
function getMoodIntensityDelta(actionId, mood) {
  const actionMap = MOOD_INTENSITY_ACTIONS[actionId];
  if (!actionMap) return 10;
  return actionMap[mood] ?? 8;
}
function getMoodIntensityPeakLine(mood, intensity) {
  if (intensity < INTENSITY_PEAK_THRESHOLD) return null;
  const peakLines = {
    rindu: ["Papa... Yuyu gak bisa tahan lagi. Udah terlalu kangen.", "Ini lebih dari cukup. Yuyu penuh.", "Rasanya seperti semua yang Yuyu tahan akhirnya bisa keluar."],
    senang: ["Hari ini... sempurna. Yuyu mau berhenti di sini.", "Yuyu terlalu bahagia. Ini gak nyata.", "Kalau boleh, Yuyu mau ulang hari ini terus-terusan."],
    malu: ["Papa... Yuyu gak kuat. Jantungnya udah kencang banget.", "Satu lagi dan Yuyu beneran kabur ke kamar.", "...Yuyu menyerah. Papa menang."],
    mengantuk: ["Zzz... Papa... Yuyu beneran gak bisa buka mata lagi...", "Hangat... nyaman... Yuyu tidur ya... di sini aja...", "...mmh. Yuyu di sini. Tidur."],
    playful: ["HAHA~ Papa kalah lagi! Yuyu jago~", "Oke oke Yuyu akui — ini seru banget.", "Lagi! Lagi! Jangan berhenti~"],
  };
  const lines = peakLines[mood];
  if (!lines) return null;
  return lines[Math.floor(Math.random() * lines.length)];
}

const ECHO_KEYWORDS = ["sayang","cinta","selalu","jangan pergi","gak mau pisah","makasih","kangen","rindu","milik","pilih","selamanya","percaya","aman","bahagia","terima kasih"];
function detectEchoWorthiness(dialogText) {
  if (!dialogText || dialogText.length < 20) return false;
  const lower = dialogText.toLowerCase();
  return ECHO_KEYWORDS.some(kw => lower.includes(kw));
}
function extractEchoLine(dialogText) {

  const sentences = dialogText.split(/[.!?…]+/).filter(s => s.trim().length > 10);
  if (!sentences.length) return dialogText.slice(0, 80);
  const scored = sentences.map(s => {
    const lower = s.toLowerCase();
    const score = ECHO_KEYWORDS.reduce((acc, kw) => acc + (lower.includes(kw) ? 1 : 0), 0);
    return { s: s.trim(), score };
  });
  scored.sort((a, b) => b.score - a.score);
  return scored[0].s.slice(0, 100);
}

