function rollDistanceTexture(emotionalDistance, mood, affection, currentTexture) {
  if ((emotionalDistance||0) < 15) return "menunggu";
  if ((emotionalDistance||0) >= 70) {
    if (["biasa","sakit","mengantuk"].includes(mood)) return "beku";
    return "sembunyi";
  }
  if ((emotionalDistance||0) >= 40) {
    if ((affection||0) > 65) return "sembunyi";
    return "lelah";
  }

  if (Math.random() < 0.18) return "sembunyi";
  return "menunggu";
}
function buildDistanceTextureInjection(distanceTexture, emotionalDistance) {
  if ((emotionalDistance||0) < 15) return "";
  const prompt = DISTANCE_TEXTURE_PROMPTS[distanceTexture||"menunggu"];
  return prompt ? `\n## TEKSTUR JARAK\n${prompt}` : "";
}

function checkMemoryCrystallization(memories, crystallizedMemories) {
  if (!memories || memories.length === 0) return [];
  const newCrystallized = [];
  memories.forEach(m => {
    if ((m.resonanceCount||0) >= 3) {
      const alreadyDone = (crystallizedMemories||[]).some(c => c.id === m.id);
      if (!alreadyDone) {
        const summary = m.summary || m.text || "sebuah kenangan";
        newCrystallized.push({
          id: m.id || `crys_${Date.now()}_${Math.random()}`,
          location: m.location,
          mood: m.mood,
          refPhrase: summary.slice(0, 45),
          crystallizedDay: m.day||1,
          resonanceCount: m.resonanceCount,
        });
      }
    }
  });
  return newCrystallized;
}
function buildCrystallizedMemoryInjection(crystallizedMemories) {
  if (!crystallizedMemories || crystallizedMemories.length === 0) return "";
  if (Math.random() > 0.22) return "";
  const recent = crystallizedMemories.slice(-4);
  const chosen = recent[Math.floor(Math.random() * recent.length)];
  return `\n## KENANGAN KRISTAL\nSatu kenangan yang sudah mengkristal dalam pikiran Yuyu: "${chosen.refPhrase}" (dari ${chosen.location||"suatu tempat"}, hari ke-${chosen.crystallizedDay||"?"}). Bisa muncul sebagai referensi organik — tidak dipaksakan.`;
}
function checkMemoryDecay(memories, currentDay, memoryDecayGriefDay) {
  if ((memoryDecayGriefDay||0) >= (currentDay||1)) return null;
  if (!memories || memories.length < 5) return null;
  const DECAY_AGE_THRESHOLD = 30;
  const decayed = memories.filter(m => {
    const ageDays = (currentDay||1) - (m.day||1);
    return ageDays > DECAY_AGE_THRESHOLD && (m.resonanceCount||0) === 0;
  });
  if (decayed.length === 0) return null;
  if (Math.random() > 0.15) return null;
  return MEMORY_DECAY_LINES[Math.floor(Math.random() * MEMORY_DECAY_LINES.length)];
}

const SEDIMENT_REDUCTION_ACTIONS = new Set(["jaga","diam","langit","bintang","bisik","rambut","peluk","duduk_t2"]);

function computeEmotionalSediment(gameState) {
  const griefWeight  = Math.min((gameState.griefLog||[]).length * 8, 32);
  const uqWeight     = (gameState.unansweredQuestion && !gameState.uqResolved) ? 16 : 0;
  const distWeight   = Math.min((gameState.highDistanceDays||0) * 5, 30);
  const missedWeight = Math.min((gameState.missedMoments||[]).length * 6, 22);
  const total = Math.min(griefWeight + uqWeight + distWeight + missedWeight, 100);
  let texture = "unspoken";
  if (griefWeight >= distWeight && griefWeight >= uqWeight) texture = "grief";
  else if (distWeight > griefWeight) texture = "distance";
  else if (uqWeight > 0) texture = "longing";
  return { weight:total, texture };
}
const SEDIMENT_TEXTURE_LABELS = { grief:"💔 Duka", longing:"🌙 Rindu", unspoken:"🌫 Tak Terucap", distance:"🧊 Jarak" };
function buildSedimentInjection(emotionalSediment) {
  const w = (emotionalSediment||{}).weight||0;
  if (w < 20) return "";
  const t = (emotionalSediment||{}).texture||"unspoken";
  const intensityLabel = w >= 70 ? "DALAM" : w >= 40 ? "TERASA" : "SAMAR";
  const textureDesc = {
    grief:    "Ada lapisan duka kecil yang belum sepenuhnya diproses.",
    longing:  "Ada rasa rindu yang tidak tahu harus pergi ke mana.",
    unspoken: "Ada hal-hal yang belum pernah diucapkan, dan mungkin tidak akan.",
    distance: "Ada jarak yang pernah ada dan meninggalkan bekas.",
  }[t] || "Ada sesuatu yang mengendap.";
  return `\n## ENDAPAN EMOSIONAL — ${intensityLabel}\n${textureDesc} Ini membuat Yuyu lebih dalam, bukan lebih sedih. Dialog boleh mengandung undertone ini — momen di mana dia hampir menyentuh sesuatu lalu tidak jadi. Bukan drama; lebih seperti kedalaman yang diam.`;
}

