function getFingerprintPassiveDialog(fingerprint, locationId, timeIdx) {
  if (!fingerprint) return null;
  if (Math.random() > 0.15) return null;
  const { loveLanguage, dominantNeed } = fingerprint;
  const candidates = [];
  if (loveLanguage === "physical" && timeIdx === 0) candidates.push("Papa... pagi-pagi Yuyu udah pengen peluk. Sini.");
  if (loveLanguage === "physical" && locationId === "kamar") candidates.push("...sini dulu. Sebentar aja.");
  if (loveLanguage === "words") candidates.push("Papa... bilang sesuatu dong. Yuyu mau dengar suara Papa.");
  if (loveLanguage === "acts_of_service" && locationId === "dapur") candidates.push("Tadi Yuyu udah nyiapin sesuatu buat Papa. Coba lihat di meja.");
  if (loveLanguage === "quality_time") candidates.push("Diam bareng aja cukup. Gak perlu ngapa-ngapain.");
  if (dominantNeed === "reassurance") candidates.push("Papa baik-baik aja kan? Yuyu tanya bukan karena khawatir berlebihan. ...oke mungkin sedikit.");
  if (dominantNeed === "comfort" && timeIdx >= 3) candidates.push("Sini duduk dekat Yuyu. Gak usah kemana-mana malam ini.");
  if (dominantNeed === "play") candidates.push("Yuyu bosan! Papa ajak Yuyu ngapain dong~");
  if (!candidates.length) return null;
  return candidates[Math.floor(Math.random() * candidates.length)];
}
function getFingerprintInitiateAction(fingerprint, locationId) {
  if (!fingerprint) return null;
  if (Math.random() > 0.08) return null;
  const { loveLanguage } = fingerprint;
  if (loveLanguage === "physical" && locationId === "kamar") return {id:"fp_init_peluk",label:"Yuyu minta peluk",icon:"🤗",effects:{affection:6}};
  if (loveLanguage === "acts_of_service" && locationId === "dapur") return {id:"fp_init_masak",label:"Yuyu udah masak",icon:"🍲",effects:{hunger:20,affection:8}};
  if (loveLanguage === "words") return {id:"fp_init_bisik",label:"Bisik sesuatu",icon:"💬",effects:{affection:7}};
  return null;
}

function buildMemory(text, gameState) {
  return {
    id: `mem_${Date.now()}`,
    day: gameState.day || 1,
    location: gameState.locationId || "kamar",
    mood: gameState.mood || "biasa",
    affection: Math.round(gameState.affection || 50),
    summary: extractEchoLine(text),
    timestamp: Date.now(),
    intensity: gameState.moodIntensity || 50,
  };
}
const MEMORY_PALACE_MILESTONE_DAYS = [7, 30, 100, 365];
function getMemoryMilestoneText(day) {
  if (day >= MEMORY_PALACE_MILESTONE_DAYS[3]) return { icon:"🎊", title:"Satu Tahun", text:"Setahun sudah. Yuyu hitung setiap harinya." };
  if (day >= MEMORY_PALACE_MILESTONE_DAYS[2]) return { icon:"💯", title:"100 Hari", text:"Seratus hari. Yuyu gak lupa satu pun." };
  if (day >= MEMORY_PALACE_MILESTONE_DAYS[1]) return { icon:"🌙", title:"Sebulan", text:"Sebulan lebih bersama. Waktu cepat kalau sama Papa." };
  if (day >= MEMORY_PALACE_MILESTONE_DAYS[0]) return { icon:"⭐", title:"Seminggu", text:"Seminggu sudah. Yuyu sudah hafal cara Papa." };
  return null;
}

