  if (distance < 20) return { id:"close",    label:"Dekat",      color:"var(--yui-success-color)", desc:"Segalanya terasa natural." };
  if (distance < 45) return { id:"normal",   label:"Normal",     color:"#a5b4fc", desc:"Ada sedikit jarak, tapi masih nyaman." };
  if (distance < 70) return { id:"reserved", label:"Berjarak",   color:"var(--yui-gold-color)", desc:"Yuyu lebih pendiam dari biasanya." };
  return                      { id:"distant",  label:"Menjauh",    color:"var(--yui-danger-color)", desc:"Yuyu butuh waktu untuk kembali." };
