function getHealthRiskFactors(gameState) {
  const risks = [];
  if ((gameState.weather?.id === "hujan") && gameState.yuyuFatigue >= 2) risks.push("hujan_fatigue");
  if ((gameState.yuyuFatigue||0) >= 4) risks.push("overfatigue");
  const hoursSince = (Date.now() - (gameState.lastPlayedTs||0)) / 3600000;
  if (hoursSince > 36) risks.push("long_absence");
  return risks;
}
function rollHealthTransition(currentHealth, risks, day) {
  if (currentHealth === "sakit" && day >= (risks._sickSince||0) + 2) return "recovered";
  if (currentHealth === "recovered" && day >= (risks._recoveredSince||0) + 1) return "prima";
  if (currentHealth === "capek" && risks.includes("overfatigue") && Math.random() < 0.3) return "sakit";
  if (currentHealth === "prima" && risks.includes("overfatigue") && Math.random() < 0.25) return "capek";
  if (currentHealth === "prima" && risks.includes("hujan_fatigue") && Math.random() < 0.15) return "capek";
  return currentHealth;
}

