function pickYuyuSettingsProposal(gameState, proposedBefore=[]) {
  const eligible = YUYU_SETTINGS_PROPOSALS.filter(p =>
    (gameState.day||1) >= p.minDay &&
    !proposedBefore.includes(p.id) &&
    p.triggerMood.includes(gameState.mood||"biasa")
  );
  if (!eligible.length) return null;
  return eligible[Math.floor(Math.random()*eligible.length)];
}

