const getMoodTransition = (mood, actionId, hunger=100) => {
  if (hunger<15) return "lapar";
  const moodState=MOOD_FSM[mood]??MOOD_FSM.biasa;
  for (const [trigger,nextMood] of Object.entries(moodState.on)) {
    if (actionId===trigger) return nextMood;
  }
  return mood;
};

