const QUESTS = [...QUESTS_UTAMA, ...QUESTS_RANTAI, ...QUESTS_RAHASIA, ...QUESTS_MOMEN];

function isQuestVisible(quest, gameState, questsDone=[]) {

  if (quest.type === "utama") {
    if (quest.unlockMinAff && gameState.affection < quest.unlockMinAff) return false;
    if (quest.unlockAfterDay && (gameState.day||1) < quest.unlockAfterDay) return false;
    return true;
  }

  if (quest.type === "rantai") {
    if (quest.unlockMinAff && gameState.affection < quest.unlockMinAff) return false;
    return true;
  }

  if (quest.type === "rahasia") {
    return !!(quest.unlockCondition && quest.unlockCondition(gameState));
  }

  return true;
}

function isQuestDone(quest, questsDone=[], questChainProgress={}) {
  if (quest.type === "rantai") {
    const steps = (questChainProgress[quest.id]||[]);
    return steps.length >= quest.steps.length;
  }
  return questsDone.includes(quest.title);
}

function getChainStep(quest, questChainProgress={}) {
  if (quest.type !== "rantai") return null;
  return (questChainProgress[quest.id]||[]).length;
}

function checkQuestStep(quest, actionId, locationId, timeId, gameState) {
  if (quest.type === "rantai") {
    const currentStep = getChainStep(quest, gameState.questChainProgress);
    if (currentStep >= quest.steps.length) return false;
    const step = quest.steps[currentStep];
    return step.check(actionId, locationId, timeId, gameState);
  }
  if (quest.check) return quest.check(actionId, locationId, timeId, gameState);
  return false;
}

