function checkSpecialDate(locationId, timeId, weather, affection, triggeredDates=[]) {
  return SPECIAL_DATE_TRIGGERS.find(t =>
    t.loc === locationId && t.time === timeId &&
    (!t.weather || weather?.id === t.weather) &&
    affection >= t.minAff && !triggeredDates.includes(t.id) &&
    Math.random() < 0.35
  ) || null;
}

