const DAILY_WISHES = [
  {id:"wish_peluk",actionId:"peluk",label:"Minta pelukan hari ini",check:(actionId)=>actionId==="peluk"},
  {id:"wish_masak",actionId:"masak",label:"Masak sesuatu bareng",check:(actionId)=>["masak","bantu","pancake","bento","kue","ramen"].includes(actionId)},
  {id:"wish_bintang",actionId:"bintang",label:"Lihat bintang malam ini",check:(actionId, locationId)=>actionId==="bintang"&&locationId==="teras"},
  {id:"wish_ngobrol",actionId:"ngobrol",label:"Ngobrol lama bareng Papa",check:(actionId)=>actionId==="ngobrol"},
  {id:"wish_foto",actionId:"foto",label:"Foto bareng Papa",check:(actionId)=>["foto","foto_t"].includes(actionId)},
  {id:"wish_sunset",actionId:"sunset",label:"Lihat sunset hari ini",check:(actionId)=>["sunset","sunset_p"].includes(actionId)},
  {id:"wish_kopi",actionId:"kopi",label:"Minum kopi bareng",check:(actionId)=>["kopi","kopi_t","kopi_k"].includes(actionId)},
  {id:"wish_jalan",actionId:null,label:"Jalan-jalan ke luar",check:(actionId, locationId)=>["taman","pantai","kafe"].includes(locationId)},
  {id:"wish_ciuman",actionId:"ciuman",label:"Ciuman dengan Papa",check:(actionId)=>actionId==="ciuman"},
  {id:"wish_tidur",actionId:"tidur",label:"Tidur lebih awal malam ini",check:(actionId, locationId, timeId)=>actionId==="tidur"&&(timeId==="malam"||timeId==="tengmalam")},
  {id:"wish_onsen",actionId:"onsen",label:"Berendam hangat",check:(actionId)=>actionId==="onsen"},
  {id:"wish_diam",actionId:"diam",label:"Diam bareng Papa",check:(actionId)=>["diam","duduk","jaga"].includes(actionId)},
];
function rollDailyWish(gameState) {
  const availableWishes=DAILY_WISHES.filter(wish=>!gameState.questsDone?.includes(wish.id));
  if(!availableWishes.length) return null;
  return {...availableWishes[Math.floor(Math.random()*availableWishes.length)],fulfilled:false,day:gameState.day||1};
}
function checkWishFulfilled(wish, actionId, locationId, timeId) {
  if(!wish||wish.fulfilled) return false;
  return wish.check(actionId,locationId,timeId);
}

