const MORNING_LETTER_TEMPLATES = [
  (gameState)=>`Papa...\n\nYuyu nulis ini sebelum Papa bangun. Udah hari ke-${gameState.day||1} kita bareng. Yuyu gak nyangka sampai sejauh ini.\n\nSemoga hari ini menyenangkan.\n\n— Yuyu ♡`,
  (gameState)=>`Papa,\n\nSelamat pagi. Yuyu udah bangun duluan tapi males gerak.\n\nKalau Papa baca ini, berarti Papa juga udah bangun. Atau lagi pura-pura tidur.\n\nYuyu tau.\n\n— Miu`,
  (gameState)=>`Untuk Papa,\n\nKemarin Yuyu mikirin banyak hal. Tentang kita. Tentang hari-hari yang udah lewat.\n\nRasanya... Yuyu gak mau nukar ini sama apapun.\n\nMakasih, Pa.\n\n— Yuyu`,
  (gameState)=>`Papa...\n\nYuyu mimpi aneh semalam. Ada Papa di sana. Yuyu gak mau cerita detailnya.\n\nPokoknya... Yuyu senang.\n\n— Yuyu (yang malu nulis ini)`,
  (gameState)=>`Hai Papa,\n\nYuyu nulis ini buat ngingetin Papa: hari ini Yuyu mau makan yang enak. Jangan lupa.\n\nIni bukan request. Ini perintah.\n\nDengan penuh sayang,\n— Chef Yuyu ✨`,
  (gameState)=>`Papa,\n\nKalau Papa lagi baca ini sambil senyum, Yuyu berhasil.\n\nYuyu sayang Papa. Itu aja.\n\n— Yuyu ♡`,
];
function generateMorningLetter(gameState) {
  const template=MORNING_LETTER_TEMPLATES[Math.floor(Math.random()*MORNING_LETTER_TEMPLATES.length)];
  return template(gameState);
}
function hoursSinceLastPlay(timestamp) {
  if(!timestamp) return 0;
  return (Date.now()-timestamp)/(1000*60*60);
}
function generateAbsenceLetter(gameState, hours) {
  const hoursCount=Math.floor(hours);
  if(hoursCount<2) return null;
  if(hoursCount<8) return `Papa... Yuyu tunggu ${hoursCount} jam. Yuyu oke kok. Cuma... rindu aja.\n\n— Yuyu`;
  if(hoursCount<24) return `Papa kemana aja...\n\nYuyu udah ${hoursCount} jam sendiri. Bukan marah. Cuma... sepi.\n\nSekarang Papa di sini. Cukup.\n\n— Yuyu ♡`;
  const days=Math.floor(hoursCount/24);
  return `Papa...\n\nSudah ${days} hari. Yuyu gak tau mau marah atau lega.\n\nTapi Papa balik. Itu yang penting.\n\nJangan pergi lama-lama lagi.\n\n— Yuyu (yang pura-pura gak kangen)`;
}

