function getTodayCalendarEvent() {
  const today=new Date();
  const currentMonth=today.getMonth()+1;
  const currentDay=today.getDate();
  return CALENDAR_EVENTS.find(calendarEvent=>calendarEvent.month===currentMonth&&calendarEvent.day===currentDay)||null;
}

function getRealTimeSlot() {
  const currentHour = new Date().getHours();
  if (currentHour >= 6  && currentHour < 12) return 0;
  if (currentHour >= 12 && currentHour < 16) return 1;
  if (currentHour >= 16 && currentHour < 19) return 2;
  if (currentHour >= 19 && currentHour < 24) return 3;
  return 4;
}
function getRealHour() { return new Date().getHours(); }
function getRealMinute() { return new Date().getMinutes(); }
function getRealDayOfWeek() { return new Date().getDay(); }

