function rollTodayGoldenHours() {
  const shuffled = [...GOLDEN_HOUR_POOL].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, 2).map(goldenHour => ({
    ...goldenHour,
    windowStart: goldenHour.windowMinutes[0],
    windowEnd:   goldenHour.windowMinutes[1],
    seen: false,
    expired: false,
    dayRolled: new Date().toDateString(),
  }));
}
function checkActiveGoldenHour(goldenHours) {
  const currentHour = getRealHour();
  const currentMinute = getRealMinute();
  const currentTimeSlot = getRealTimeSlot();
  const totalMinutesIntoSlot = currentMinute;
  return (goldenHours || []).find(goldenHour =>
    !goldenHour.expired &&
    !goldenHour.seen &&
    goldenHour.timeSlot === currentTimeSlot &&
    totalMinutesIntoSlot >= goldenHour.windowStart &&
    totalMinutesIntoSlot <= goldenHour.windowEnd
  ) || null;
}

