const SEASON_ORDER = ["kemarau","pancaroba1","hujan","pancaroba2"];
function getSeasonFromDay(gameDayNumber) {
  const totalCycleDays = 120;
  const dayInCycle = ((gameDayNumber - 1) % totalCycleDays);
  let accumulated = 0;
  for (const seasonId of SEASON_ORDER) {
    accumulated += SEASONS[seasonId].durationDays;
    if (dayInCycle < accumulated) return SEASONS[seasonId];
  }
  return SEASONS.kemarau;
}
function rollSeasonWeather(season) {
  const biasList = season.weatherBias || ["cerah","mendung","hujan"];
  const biasId = biasList[Math.floor(Math.random() * biasList.length)];
  return WEATHER_TYPES.find(weatherType => weatherType.id === biasId) || WEATHER_TYPES[0];
}

