function buildTemporalMemories(gameState) {
  const currentDay = gameState.day || 1;
  const temporalMemoryLines = [];
  if (currentDay >= 8 && gameState.memories?.includes("masak")) {
    const daysAgo = Math.min(currentDay - 1, 14);
    temporalMemoryLines.push(`Sekitar ${daysAgo} hari lalu kita pertama kali masak bareng.`);
  }
  if (currentDay >= 30) {
    temporalMemoryLines.push(`Udah sebulan lebih kita bareng. Waktu cepet ya...`);
  }
  if (currentDay === 100) {
    temporalMemoryLines.push(`100 hari. Yuyu hitung, lho.`);
  }
  if (currentDay >= 365) {
    temporalMemoryLines.push(`Setahun. Satu tahun penuh. Papa... makasih ya.`);
  }
  return temporalMemoryLines;
}

function analyzeCircadianPattern(sessionTimestamps) {
  if (!sessionTimestamps || sessionTimestamps.length < 5) return null;
  const slotCounts = [0,0,0,0,0];
  sessionTimestamps.forEach(timestamp => {
    const sessionHour = new Date(timestamp).getHours();
    if (sessionHour >= 6  && sessionHour < 12) slotCounts[0]++;
    else if (sessionHour >= 12 && sessionHour < 16) slotCounts[1]++;
    else if (sessionHour >= 16 && sessionHour < 19) slotCounts[2]++;
    else if (sessionHour >= 19 && sessionHour < 24) slotCounts[3]++;
    else slotCounts[4]++;
  });
  const dominantSlotIndex = slotCounts.indexOf(Math.max(...slotCounts));
  const dominantCount = slotCounts[dominantSlotIndex];
  const totalSessions = sessionTimestamps.length;
  if (dominantCount / totalSessions >= 0.4) {
    return { dominantSlot: dominantSlotIndex, confidence: dominantCount / totalSessions };
  }
  return null;
}
function getCircadianDialog(circadianPattern, currentTimeSlot) {
  if (!circadianPattern) return null;
  const isExpected = circadianPattern.dominantSlot === currentTimeSlot;
  const slotLabels = ["pagi","siang","sore","malam","tengah malam"];
  if (isExpected) {
    const expectedDialogs = [
      `Kamu dateng lagi. Tadi aku udah nyiapin teh duluan.`,
      `${slotLabels[currentTimeSlot]}... pas banget. Aku lagi nungguin kamu.`,
      `Kamu selalu ada di jam segini. Yuyu hafal.`,
    ];
    return expectedDialogs[Math.floor(Math.random() * expectedDialogs.length)];
  } else {
    const unexpectedDialogs = [
      `Lho, kok ${slotLabels[currentTimeSlot]}? Biasanya kamu dateng ${slotLabels[circadianPattern.dominantSlot]}.`,
      `Ada apa? Kamu gak biasanya dateng jam segini...`,
      `Hmm. Ini gak biasanya. Semuanya oke kan?`,
    ];
    return unexpectedDialogs[Math.floor(Math.random() * unexpectedDialogs.length)];
  }
}

function inferPlayerStressPattern(gameState) {
  const recentActions = (gameState.eventLog || [])
    .filter(gameEvent => gameEvent.type === "ACTION")
    .slice(-10);
  if (recentActions.length < 5) return null;
  const uniqueActionIds = new Set(recentActions.map(gameEvent => gameEvent.payload?.id));
  const isScattered = uniqueActionIds.size >= 7;
  const hasRepeatActions = recentActions.length > 0 &&
    recentActions.filter(gameEvent => gameEvent.payload?.id === recentActions[0].payload?.id).length >= 3;
  if (isScattered || hasRepeatActions) return "stressed";
  return "calm";
}
