function checkAgendaFulfilled(agenda, actionId, locationId) {
  if (!agenda || agenda.fulfilled) return false;
  if (agenda.matchActions && agenda.matchActions.includes(actionId)) return true;
  if (agenda.matchLocations && agenda.matchLocations.includes(locationId)) return true;
  return false;
}

function getTemporalDriftMultiplier(affection, mood) {

  if (affection >= 75 && ["senang","excited","playful"].includes(mood)) return 1.3;
  if (affection <= 25 || ["sakit","kangen"].includes(mood)) return 0.7;
  return 1.0;
}

function getTemporalDriftBonus(affection, mood) {
  const driftMultiplier = getTemporalDriftMultiplier(affection, mood);
  if (driftMultiplier > 1.2) return 2;
  if (driftMultiplier < 0.8) return -1;
  return 0;
}

