function detectMemoryPattern(memories) {
  if (!memories || memories.length < 3) return [];
  const counts = {};
  memories.forEach(m => {
    const key = `${m.location}:${m.mood}`;
    counts[key] = (counts[key] || { list: [] });
    counts[key].list.push(m);
  });
  const threads = [];
  for (const [key, data] of Object.entries(counts)) {
    if (data.list.length >= 3) {
      const [location, mood] = key.split(":");
      const sorted = [...data.list].sort((a,b)=>a.day-b.day);
      threads.push({
        id: `thread_${location}_${mood}`,
        pattern: { location, mood },
        count: data.list.length,
        firstDay: sorted[0].day,
        latestDay: sorted[sorted.length-1].day,
        label: `${LOCATIONS[location]?.label||location} di saat ${mood}`,
      });
    }
  }
  return threads.slice(0,5);
}

function detectFingerprintDrift(history) {
  if (!history || history.length < 2) return null;
  const prev = history[history.length-2];
  const curr = history[history.length-1];
  if (!prev || !curr) return null;
  if (prev.loveLanguage !== curr.loveLanguage) {
    return { type:"loveLanguage", from:prev.loveLanguage, to:curr.loveLanguage };
  }
  if (prev.dominantNeed !== curr.dominantNeed) {
    return { type:"dominantNeed", from:prev.dominantNeed, to:curr.dominantNeed };
  }
  return null;
}
function getFingerprintDriftDialog(drift, yuyuName, playerName) {
  if (!drift) return null;
  if (drift.type === "loveLanguage") {
    const map = {
      physical: "banyak menyentuh",
      words: "ingin kata-kata",
      acts_of_service: "sering melakukan hal kecil buat Yuyu",
      quality_time: "hanya ingin ada di sini diam-diam",
    };
    const prev = map[drift.from] || drift.from;
    const curr = map[drift.to] || drift.to;
    return `Dulu ${playerName} lebih ${prev}. Sekarang lebih ${curr}. ${yuyuName} perhatiin, tapi belum bilang.`;
  }
  if (drift.type === "dominantNeed") {
    return `Kebutuhan ${playerName} berubah belakangan ini. ${yuyuName} merasakannya — tapi tidak tahu harus bilang apa.`;
  }
  return null;
}

const BLINDSPOT_CONDITIONS = [
  { mood:"biasa", blindspot:"rindu",   chance:0.18, trigger:(gs)=>gs.streak >= 3 },
  { mood:"senang",blindspot:"takut",   chance:0.12, trigger:(gs)=>gs.affection >= 80 },
  { mood:"playful",blindspot:"kangen", chance:0.15, trigger:(gs)=>(gs.emotionalDistance||0) >= 30 },
  { mood:"biasa", blindspot:"marah",   chance:0.08, trigger:(gs)=>(gs.streak||0)===0 && (gs.emotionalDistance||0)>=40 },
  { mood:"senang",blindspot:"rindu",   chance:0.10, trigger:(gs)=>(Date.now()-(gs.lastPlayedTs||0))/3600000 >= 12 },
];
function rollEmotionalBlindspot(currentMood, gameState) {
  const candidates = BLINDSPOT_CONDITIONS.filter(b => b.mood === currentMood && b.trigger(gameState));
  if (!candidates.length) return null;
  const entry = candidates[Math.floor(Math.random()*candidates.length)];
  if (Math.random() > entry.chance) return null;
  return entry.blindspot;
}
function getBlindspotInstructions(blindspot, yuyuName) {
  const map = {
    rindu: `${yuyuName} sebenarnya rindu tapi tidak mengakuinya bahkan ke dirinya sendiri. Dialog terasa biasa-biasa saja tapi pilihan kata dan arah pembicaraan selalu kembali ke kebersamaan, kehangatan, atau ke hal-hal yang melibatkan ${yuyuName} dan Papa.`,
    takut: `${yuyuName} sebenarnya sedikit takut kehilangan momen ini tapi tidak mau bilang. Terasa dalam kecenderungan untuk memperlambat, meminta "tunggu sebentar", atau tidak ingin berakhirnya sesuatu.`,
    kangen: `${yuyuName} kangen walaupun Papa ada di sini — kangen versi dirinya yang lebih santai, lebih bebas. Ini bocor lewat nostalgia kecil atau referensi ke masa lalu.`,
    marah: `${yuyuName} ada sedikit perasaan ditinggalkan tapi tidak mau akui itu. Dialog terasa netral tapi ada satu atau dua kata yang lebih tajam dari biasanya.`,
  };
  return map[blindspot] || "";
}

