function getPhysicalSubtext(actionId, mood, tensionMode) {

  if (tensionMode === "kontradiksi" && Math.random() < 0.4) {
    const pool = PHYSICAL_SUBTEXT_POOL.kontradiksi;
    return pool[Math.floor(Math.random()*pool.length)];
  }
  const byAction = PHYSICAL_SUBTEXT_POOL[actionId];
  const byMood = PHYSICAL_SUBTEXT_POOL[mood];
  const pool = byAction || byMood || PHYSICAL_SUBTEXT_POOL.default;
  if (Math.random() > 0.35) return null;
  return pool[Math.floor(Math.random()*pool.length)];
}

function checkGriefTriggers(gameState) {
  const events = [];

  const hoursSince = (Date.now()-(gameState.lastPlayedTs||0))/3600000;
  const sceneLayer = (gameState.sceneEvolutionLayers||{});
  if (hoursSince >= 168 && sceneLayer.plant_teras && !sceneLayer.plant_teras_wilted) {
    events.push({ type:"wilt_plant", id:"plant_teras_wilted", msg:"Tanaman di teras... Yuyu lupa siram. Sudah mulai layu." });
  }

  const missCount = (gameState.prophecyMissStreak||0);
  if (missCount >= 3 && gameState.yuyuProject && !gameState.yuyuProject.completed && !(gameState.griefLog||[]).some(g=>g.type==="proj_abandoned")) {
    events.push({ type:"proj_abandoned", id:"proj_abandoned", projectLabel: gameState.yuyuProject.label, msg:`${gameState.yuyuProject.label}... Yuyu sudah tidak melanjutkannya.` });
  }

  const highDistDays = gameState.highDistanceDays || 0;
  if (highDistDays >= 5 && !(gameState.griefLog||[]).some(g=>g.type==="arc_letter_closed")) {
    events.push({ type:"arc_letter_closed", id:"arc_letter_closed", msg:"Surat itu... Yuyu simpan. Belum dibuang. Mungkin nanti." });
  }
  return events;
}
function applyGriefEvent(gameState, event) {
  const next = {...gameState};
  const griefLog = [...(gameState.griefLog||[]), { ...event, day: gameState.day||1, ts: Date.now() }];
  next.griefLog = griefLog.slice(-10);
  if (event.type === "wilt_plant") {
    next.sceneEvolutionLayers = { ...(gameState.sceneEvolutionLayers||{}), plant_teras_wilted: true };
  }
  if (event.type === "proj_abandoned") {
    next.yuyuProject = null;
  }
  if (event.type === "arc_letter_closed") {
    next.closedArcs = [...(gameState.closedArcs||[]), "arc_surat"];
  }
  return next;
}

