function buildMemoryContext(gameState) {
  const lines=[];
  const memories=gameState.memories||[];

  if(memories.length>0){
    const recent=memories.slice(-6);
    const namedMemories=recent.map(id=>MEMORY_TRIGGERS[id]||id).filter(Boolean);
    if(namedMemories.length>0){
      lines.push(`Kenangan yang Yuyu simpan (boleh disinggung pelan-pelan, organik):\n${namedMemories.map((m,i)=>`  ${i+1}. ${m}`).join("\n")}`);
    }
  }

  const sessions=gameState.circadianSessions||[];
  if(sessions.length>=5){
    const hourBuckets=Array(24).fill(0);
    sessions.forEach(sessionTimestamp=>{ hourBuckets[new Date(sessionTimestamp).getHours()]++; });
    const peakHour=hourBuckets.indexOf(Math.max(...hourBuckets));
    const peakLabel=peakHour<6?"tengah malam":peakHour<12?"pagi hari":peakHour<17?"siang":peakHour<21?"sore":"malam";
    const lateNightSessions=sessions.filter(sessionTimestamp=>{ const h=new Date(sessionTimestamp).getHours(); return h>=22||h<4; });
    const lateFraction=lateNightSessions.length/sessions.length;
    if(lateFraction>0.5){
      lines.push(`Yuyu tau Papa sering datang ${peakLabel}. Sudah hafal. Kadang Yuyu tunggu jam itu.`);
    } else if(sessions.length>=10){
      lines.push(`Yuyu udah tau pola Papa — biasanya datang ${peakLabel}. Gak perlu dikasitau lagi.`);
    }
  }

  if((gameState.overflowAffection||0)>0){
    const ov=Math.round(gameState.overflowAffection);
    lines.push(`Kasih sayang sudah meluap ${ov} poin lebih. Yuyu merasakannya tapi tidak tahu cara mengatakannya.`);
  }

  if(gameState.dailyWish&&!gameState.dailyWish.fulfilled){
    lines.push(`Wish Yuyu hari ini yang belum terpenuhi: "${gameState.dailyWish.label}" — Yuyu berharap tanpa mengatakannya.`);
  } else if(gameState.dailyWish?.fulfilled){
    lines.push(`Wish hari ini sudah terpenuhi. Yuyu gak mau bilang makasih, tapi senyumnya ketahuan.`);
  }

  if(gameState.moodArc?.revealed){
    lines.push(`Arc hari ini: ${gameState.moodArc.desc}`);
  }

  if((gameState.streak||0)>=3){
    lines.push(`Papa sudah ${gameState.streak} hari berturut-turut. Yuyu sudah mulai menghitungnya.`);
  }

  if((gameState.specialMoments||[]).length>0){
    const last=gameState.specialMoments[gameState.specialMoments.length-1];
    lines.push(`Momen terbaru yang Yuyu ingat: "${last.text}"`);
  }

  if((gameState.yuyuFatigue||0)>=FATIGUE_THRESHOLD){
    lines.push(`Yuyu kelelahan sekarang. Responsnya lebih pendek, gerakannya lebih pelan.`);
  }
  return lines.length>0?"\n\n## KONTEKS MEMORI & KEHADIRAN\n"+lines.join("\n"):"";
}

const ARC_SCAR_MAP = {
  arc_surat:   { actions:["surat","gambar","cerita","bisik"],     hesitation:"Ada jedah kecil sebelum ${y} menjawab — seperti berhati-hati tanpa tahu mengapa." },
  arc_buku:    { actions:["baca","duduk","diam","duduk_t2"],      hesitation:"${y} mengikuti, tapi ada pause tipis — seolah mengingat sesuatu yang tidak ingin diingat." },
  arc_masak:   { actions:["masak","bantu","makan","makan_k","kue"],hesitation:"Tangan ${y} sedikit ragu — bukan karena tidak mau, tapi karena pernah merasakannya tidak selesai." },
  arc_gambar:  { actions:["gambar","foto","bintang","foto_t"],    hesitation:"${y} merespons, tapi ada momen ia memalingkan wajah sedikit — sebentar, nyaris tidak terlihat." },
};
function getScarTissueCtx(failedArcs, actionId, yuyuName) {
  if (!failedArcs || failedArcs.length === 0) return "";
  for (const fa of failedArcs) {
    const scar = ARC_SCAR_MAP[fa.arcId];
    if (scar && scar.actions.includes(actionId)) {
      const h = scar.hesitation.replace(/\${y}/g, yuyuName);
      return `\n## BEKAS LUKA KECIL\n${h}\nIni TIDAK pernah disebut eksplisit — hanya hadir sebagai tekstur dalam satu momen kecil.`;
    }
  }
  return "";
}

function trackBlindspotOccurrence(occurrences, mood, location) {
  const key = `${mood}:${location}`;
  const existing = (occurrences||[]).find(o => o.key === key);
  if (existing) return occurrences.map(o => o.key === key ? {...o, count: o.count + 1} : o);
  return [...(occurrences||[]), {key, mood, location, count: 1}];
}
function checkBlindspotSurfacing(occurrences, mood, location) {
  const key = `${mood}:${location}`;
  const found = (occurrences||[]).find(o => o.key === key);
  return !!(found && found.count >= 3);
}
function getBlindspotSurfacingCtx(isSurfacing, blindspot, yuyuName) {
  if (!isSurfacing || !blindspot) return "";
  return `\n## BLINDSPOT HAMPIR MUNCUL\n${yuyuName} hampir mengatakannya sekarang — bukan dengan kata langsung, tapi satu kalimat yang menggantung, setengah selesai. Tekstur dialog: gantung, belum tuntas, seperti kalimat yang ditelan kembali. Jangan selesaikan kalimat itu secara penuh.`;
}

function buildSessionMemoirPrompt(gameState, playerName, yuyuName) {
  const shape = gameState.sessionTrajectory?.shape || "steady";
  const topActions = Object.entries(gameState.actionFrequency||{}).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([k])=>k).join(", ");
  const mood = gameState.mood || "biasa";
  const shapeDesc = {warming:"makin hangat",cooling:"mendingin",turbulent:"naik-turun",steady:"stabil"}[shape]||shape;
  return `Kamu adalah ${yuyuName}. Sesi dengan ${playerName} baru saja berakhir. Tulis SATU kalimat memoir (maks 18 kata) tentang sesi ini dari sudut pandangmu — perasaan terkuat, atau sesuatu yang belum kamu katakan. Jangan mulai dengan "Yuyu" atau "Aku". Bahasa natural. Data: arah=${shapeDesc}, aktivitas=${topActions||"berbagai"}, mood=${mood}. Satu kalimat saja, tanpa tanda kutip.`;
}
function getSessionMemoirCtx(sessionMemoirs, yuyuName) {
  if (!sessionMemoirs || sessionMemoirs.length === 0) return "";
  const last2 = sessionMemoirs.slice(-2);
  const texts = last2.map(m => `"${m.text}"`).join(" | ");
  return `\n## MEMOAR SESI\n${yuyuName} masih membawa rasa dari sebelumnya: ${texts}. Bisa muncul sangat natural — sepintas, seperti sesuatu yang masih tinggal tanpa perlu dijelaskan.`;
}

const UQ_ACTION_RESONANCE = {
  uq_pilih: ["baca","duduk","diam","langit","duduk_t2"],
  uq_ingat: ["bintang","bintang_p","jendela","langit"],
  uq_tunggu: ["jaga","duduk","diam","diam_t"],
  uq_perlu: ["peluk","rambut","bisik","peluk_sofa"],
  uq_takut: ["ngobrol","cerita","bisik","ngobrol_k"],
  uq_tetap: ["jaga","duduk","tidur","diam"],
};
function checkUQNarrativeConditions(uq, gameState, actionId, currentDay) {
  if (!uq || gameState.uqResolved) return false;
  const daysElapsed = currentDay - (uq.askedDay || 1);
  const distanceLow = (gameState.emotionalDistance || 0) < 30;
  const daysOk = daysElapsed >= 3;
  const relevantActions = UQ_ACTION_RESONANCE[uq.id] || [];
  const actionResonates = relevantActions.includes(actionId) ||
    Object.entries(gameState.actionFrequency||{}).some(([a,c]) => relevantActions.includes(a) && c >= 2);
  return distanceLow && daysOk && actionResonates;
}
function getUQNarrativeResolutionText(uq, yuyuName) {
  const resolutions = {
    uq_pilih: `${yuyuName} tidak berkata apa-apa soal itu — tapi sekarang dia tahu.`,
    uq_ingat: `...Yuyu ingat. Selalu ingat. Pertanyaan itu tidak perlu dijawab sebenarnya.`,
    uq_tunggu: `Kamu masih di sini. Itu sudah lebih dari cukup untuk menjawabnya.`,
    uq_perlu: `Yuyu rasa pertanyaan itu sudah terjawab — sejak lama. Hanya tidak pernah diucapkan.`,
    uq_takut: `${yuyuName} berhenti takut. Sekarang dia mengerti kenapa.`,
    uq_tetap: `${yuyuName} berhenti menunggu jawaban. Kamu di sini. Itu jawabannya.`,
  };
  return resolutions[uq?.id] || `Ada yang terselesaikan tanpa kata-kata tadi.`;
}

function getTrajectoryCarryForwardDelta(trajectory) {
  if (!trajectory) return 0;
  if (trajectory.shape === "cooling") return 6;
  if (trajectory.shape === "turbulent") return 10;
  if (trajectory.shape === "warming") return -4;
  return 0;
}
function buildGameFacts(gameState) {
  const time=TIMES[gameState.timeIdx];
  const locationData=LOCATIONS[gameState.locationId];
  return {
    mood:gameState.mood, hunger:gameState.hunger<20?"sangat lapar":gameState.hunger<45?"lapar":gameState.hunger<70?"biasa":"kenyang",
    kedekatan:gameState.affection<20?"jauh":gameState.affection<50?"sedang":gameState.affection<80?"dekat":"sangat dekat",
    hubungan:gameState.questsDone.length>=10?"intim":gameState.questsDone.length>=5?"dekat":gameState.questsDone.length>=2?"kenal":"baru",
    lokasi:locationData?.label??gameState.locationId, waktu:time?.label??gameState.timeIdx, uang:`¥${gameState.money}`,
    weather:gameState.weather?.label??"cerah", last_act:gameState.lastAction??"belum ada", day:gameState.day||1,
    tier:AFF_TIER_LABEL[getAffectionTier(gameState.affection)],
    yuyu_lokasi: gameState.yuyuLocationId===gameState.locationId
      ? `bersama player di ${LOCATIONS[gameState.locationId]?.label||gameState.locationId}`
      : `sedang di ${LOCATIONS[gameState.yuyuLocationId]?.label||gameState.yuyuLocationId}${gameState.yuyuTraveling?" (dalam perjalanan)":""}`,
  };
}

function buildSnapshot(facts) {
  const relationshipLabel={baru:"baru kenal",kenal:"mulai kenal lebih dalam",dekat:"sudah cukup dekat",intim:"sangat dekat"}[facts.hubungan]??facts.hubungan;
  return `Hari ke-${facts.day}. Papa dan Yuyu ${relationshipLabel}. Mood Yuyu: ${facts.mood}. Cuaca: ${facts.weather}. Terakhir: ${facts.last_act}.`;
}
function buildSystemPrompt(gameState, playerName="Papa", yuyuRegister="lembut", yuyuName="Yuyu", dialogLang="id", userPreferences="") {

  const driftedRegister = computeDriftedRegister(yuyuRegister, gameState.emotionalFingerprint, gameState.affection, gameState.griefLog);
  const effectiveRegister = driftedRegister;
  const facts=buildGameFacts(gameState);
  const factStr=Object.entries(facts).map(([factKey,factValue])=>`${factKey}:${factValue}`).join(" | ");
  const affectionTier=getAffectionTier(gameState.affection);
  const tierCtx=["Kalau ada hal awkward, "+yuyuName+" tahan malu tapi tetap hadir.",""+yuyuName+" sudah mulai nyaman. Kadang berani inisiatif kecil.",""+yuyuName+" sangat dekat dengan "+playerName+". Bisa terus terang soal perasaan.",""+yuyuName+" sepenuhnya terbuka. Tidak perlu jaga jarak."][affectionTier];
  const snapshot=buildSnapshot(facts);
  const memCtx=buildMemoryContext(gameState);
  const registerCtx = {
    lembut:   `Suara ${yuyuName}: hangat, sayang, penuh perhatian. Panggil "${playerName}" dengan lembut.`,
    playful:  `Suara ${yuyuName}: lucu, bawel, sering bercanda. Panggil "${playerName}" sambil goda.`,
    manja:    `Suara ${yuyuName}: manja, sedikit clingy, minta perhatian. Panggil "${playerName}" dengan nada manja.`,
    tsundere: `Suara ${yuyuName}: gengsi tapi sayang, sering menyangkal perasaan. Panggil "${playerName}" dengan sedikit ketus tapi tetap hangat.`,
    dewasa:   `Suara ${yuyuName}: tenang, bijak, intim tapi tidak berlebihan. Panggil "${playerName}" dengan dewasa.`,
  }[effectiveRegister] || `Panggil "${playerName}" dengan hangat.`;
  const customBase = YUYU_BASE_PROMPT.replace(/Yuyu/g, yuyuName).replace(/Papa/g, playerName).replace(/Beno/g, playerName);

  const realHour = getRealHour();
  const dayPersonality = DAY_OF_WEEK_PERSONALITIES[getRealDayOfWeek()];
  const currentSeason = getSeasonFromDay(gameState.day||1);
  const bioClock = getBioClock(gameState.timeIdx||0);
  const currentAgenda = YUYU_AGENDA_POOL.find(agendaItem => agendaItem.id === gameState.yuyuAgendaId);
  const currentProphecy = YUYU_PROPHECY_POOL.find(prophecyItem => prophecyItem.id === gameState.prophecyId);
  const temporalMemories = buildTemporalMemories(gameState);
  const midnightCare = getMidnightCareDialog(realHour);
  const radioDescription = RADIO_TIME_DESCRIPTIONS[gameState.timeIdx||0];
  const weeklyArc = WEEKLY_ARC_TEMPLATES.find(arcTemplate => arcTemplate.id === gameState.weeklyArcId);
  const dayInArc = (gameState.day||1) - (gameState.weeklyArcStartDay||1);
  const todayArcHint = weeklyArc ? getWeeklyArcDayHint(weeklyArc, Math.max(1, dayInArc)) : null;

  const temporalContext = [
    `\n## WAKTU NYATA\nJam: ${realHour}:${String(getRealMinute()).padStart(2,'0')} | Hari: ${dayPersonality?.name||"?"} (${dayPersonality?.flavorLine||""})`,
    `Musim: ${currentSeason.label} — ${currentSeason.flavorLine}`,
    `Suasana audio: ${radioDescription?.description||""}`,
    `Energi ${yuyuName} saat ini: ${bioClock.label} — ${bioClock.description}`,
    currentAgenda && !gameState.agendaFulfilled ? `\n## AGENDA TERSEMBUNYI HARI INI\n${yuyuName} hari ini diam-diam ingin: "${currentAgenda.secret}". Jangan ungkap langsung, tapi biarkan terasa lewat gesture dan dialog.` : "",
    currentProphecy && !gameState.prophecyFulfilled ? `\n## JANJI MINGGU INI\n${yuyuName} pernah bilang ingin: "${currentProphecy.text}". Kalau action ini relevan, ${yuyuName} boleh sedikit antusias.` : "",
    weeklyArc && todayArcHint ? `\n## WEEKLY ARC: ${weeklyArc.title}\nHari ${dayInArc+1} dari arc ini. Hint hari ini: "${todayArcHint.hint}"` : "",
    temporalMemories.length > 0 ? `\n## KENANGAN TEMPORAL\n${temporalMemories.join(" | ")}` : "",
    midnightCare ? `\n## PERHATIAN TENGAH MALAM\nJam sudah ${realHour}:00. ${yuyuName} peduli dengan kondisi ${playerName} yang masih terjaga. Bisa selipkan perhatian tulus di respons.` : "",
    gameState.prophecyMissed && gameState.prophecyMissedText ? `\n## JANJI YANG TERLEWAT\n${yuyuName} ingat: "${gameState.prophecyMissedText}" — bisa disinggung pelan dan tanpa drama.` : "",
  ].filter(Boolean).join("\n");

  const langCtx = dialogLang==="id"?"":dialogLang==="en"?`\n## BAHASA\nBalas HANYA dalam bahasa Inggris. Pertahankan karakter, kepribadian, dan emosi ${yuyuName} sepenuhnya.`:dialogLang==="ja"?`\n## 言語\n日本語のみで返答してください。${yuyuName}のキャラクターと感情を完全に維持すること。`:dialogLang==="ko"?`\n## 언어\n한국어로만 답해주세요. ${yuyuName}의 캐릭터와 감정을 완전히 유지하세요.`:"";

  const fp = gameState.emotionalFingerprint;
  const fpCtx = fp ? `\n## PEMAHAMAN MENDALAM TENTANG ${playerName.toUpperCase()}\nKebutuhan utama: ${fp.dominantNeed||"?"} | Bahasa kasih sayang: ${fp.loveLanguage||"?"} | Pola kecemasan: ${fp.anxietyPattern||"tidak terdeteksi"} | Waktu koneksi terbaik: ${fp.peakConnectionTime||"?"}\nInsight: "${fp.insight||""}"` : "";

  const earnedUnlocks = getEarnedOverflowUnlocks(gameState.overflowAffection||0);
  const unlockHints = earnedUnlocks.map(u => u.behaviorHint).join(" | ");
  const unlockCtx = unlockHints ? `\n## DIMENSI BARU (OVERFLOW UNLOCKS)\n${unlockHints}` : "";

  const activeProj = gameState.yuyuProject;
  const projHint = activeProj && !activeProj.completed ? getProjectProgressHint(activeProj) : null;
  const projCtx = projHint && !projHint.done ? `\n## PROYEK PRIBADI ${yuyuName.toUpperCase()}\n${yuyuName} sedang mengerjakan "${activeProj.label}" secara diam-diam. Petunjuk progres: "${projHint.text}". Jangan ungkap langsung — biarkan terasa lewat gesture.` : projHint?.done ? `\n## PROYEK SELESAI\n${yuyuName} baru menyelesaikan "${activeProj.label}". Ini adalah momen penting yang dia tunggu-tunggu.` : "";

  const spDef = getActiveSharedProjectData(gameState.activeSharedProjectId);
  const spCtx = spDef ? `\n## PROYEK BERSAMA\n${yuyuName} dan ${playerName} sedang mengerjakan "${spDef.title}". Progress: ${(gameState.sharedProjectStepsDone||[]).length}/${spDef.steps.length} langkah.` : "";

  const locPersonality = (gameState.locationPersonality||{})[gameState.locationId];
  const locVisitCount = locPersonality?.visitCount || 0;
  const locFamiliarCtx = locVisitCount >= 10 ? `\n## LOKASI FAMILIAR\n${yuyuName} sudah ${locVisitCount}x di ${LOCATIONS[gameState.locationId]?.label||gameState.locationId}. Tempat ini sudah sangat akrab.` : "";

  const realWorldCtx = buildRealWorldContext(gameState, playerName);

  const echoes = (gameState.dialogEchoes||[]);
  const echoCtx = echoes.length > 0
    ? `\n## KATA-KATA YANG DIINGAT\n${yuyuName} masih ingat kalimat-kalimat ini dari percakapan sebelumnya:\n${echoes.map((e,i)=>`${i+1}. "${e.text}" (hari ke-${e.day}, saat ${e.mood})`).join("\n")}\nKadang-kadang, ${yuyuName} boleh mereferensikan ini secara natural dan tulus — bukan dipaksakan.`
    : "";

  const intensity = gameState.moodIntensity || 50;
  const intensityCtx = intensity >= INTENSITY_PEAK_THRESHOLD
    ? `\n## INTENSITAS EMOSI PUNCAK\nMood "${gameState.mood}" sedang di puncak intensitas (${intensity}/100). ${yuyuName} boleh lebih terbuka, lebih raw, lebih jujur dari biasanya. Ini momen langka.`
    : intensity <= 20
    ? `\n## INTENSITAS EMOSI RENDAH\n${yuyuName} sedang flat. Respons lebih pendek, lebih reserved.`
    : "";

  const dist = gameState.emotionalDistance || 0;
  const distTier = getDistanceTier(dist);
  const distCtx = dist >= 45
    ? `\n## JARAK EMOSIONAL\nSaat ini ada jarak antara ${yuyuName} dan ${playerName} (${dist}/100 — "${distTier.label}"). ${yuyuName} lebih reserved, respons lebih pendek dan hati-hati. Bukan marah — hanya butuh waktu. Kalau ${playerName} melakukan sesuatu yang tulus, biarkan jarak itu mencair perlahan.`
    : dist < 15 ? `\n## KEDEKATAN PENUH\n${yuyuName} dan ${playerName} sangat dekat saat ini. ${yuyuName} boleh lebih terbuka dan spontan.` : "";

  const health = YUYU_HEALTH_STATES[gameState.yuyuHealthState || "prima"];
  const healthCtx = gameState.yuyuHealthState !== "prima"
    ? `\n## KONDISI FISIK ${yuyuName.toUpperCase()}\n${yuyuName} sedang "${health.label}" — ${health.desc} Sesuaikan energi dan respons.`
    : "";

  const activeThread = getActiveThread(gameState.pendingTopics, gameState.day||1);
  const threadCtx = activeThread
    ? `\n## TOPIK YANG BELUM SELESAI\n${yuyuName} masih ingat ini dan ingin membahasnya: "${activeThread.template}" — bisa disinggung secara natural jika relevan.`
    : "";

  const moodWeather = MOOD_WEATHER_STATES[gameState.moodWeatherId || "biasa_saja"];
  const moodWeatherCtx = moodWeather && moodWeather.id !== "biasa_saja"
    ? `\n## CUACA EMOSI MULTI-HARI\n${yuyuName} sedang dalam fase "${moodWeather.label}" selama ${(gameState.day||1)-(gameState.moodWeatherSince||1)+1} hari. ${moodWeather.dialog}`
    : "";

  const tension = computeIntimacyTension(gameState.affection, gameState.emotionalDistance||0);
  const tensionMode = getIntimacyTensionMode(tension);
  const tensionCtx = tension >= 35
    ? `\n## KETEGANGAN BATIN\nKontradiksi internal: ${yuyuName} rindu (affection ${Math.round(gameState.affection)}) tapi juga menjaga jarak (${Math.round(gameState.emotionalDistance||0)}/100). Mode: "${tensionMode}". Dialog boleh mencerminkan ambivalensi ini — memegang sekaligus mendorong.`
    : "";

  const trend = gameState.affectionTrend || getAffectionTrend(gameState.affectionHistory);
  const trendCtx = trend !== "stable" ? `\n## ARKEOLOGI AFFECTION\n${getAffectionTrendCtx(trend, yuyuName, playerName)}` : "";

  const missed = (gameState.missedMoments||[]).slice(-3);
  const missedCtx = missed.length > 0
    ? `\n## MOMEN YANG TERLEWAT\n${yuyuName} tidak pernah menyebut ini langsung, tapi cara bicaranya dipengaruhi topik yang tidak pernah selesai:\n${missed.map((m,i)=>`${i+1}. "${m.topic}" (hari ke-${m.day})`).join("\n")}\nBiarkan ini terasa subtle — bukan diungkap, hanya terasa.`
    : "";

  const silenceCount = gameState.silenceCount || 0;
  const silenceCtx = silenceCount >= 3
    ? `\n## KEHENINGAN BERMAKNA\n${yuyuName} dan ${playerName} sudah berbagi ${silenceCount} momen diam bersama. ${yuyuName} menganggap ini berharga. Boleh disinggung natural jika relevan.`
    : "";

  const pdCompletedYesterday = (gameState.perfectDayCompletedDay||0) === (gameState.day||1) - 1;
  const pdCtx = pdCompletedYesterday && gameState.perfectDayRecipe
    ? `\n## HARI SEMPURNA KEMARIN\nKemarin adalah "hari sempurna" — ${gameState.perfectDayRecipe.label}. ${yuyuName} ingat ini. Boleh sebut dengan cara yang natural dan hangat, tidak berlebihan.`
    : "";

  const proactiveEchoBase = (gameState.dialogEchoes||[]);
  const moodMatchedEchoes = proactiveEchoBase.filter(e => e.mood === gameState.mood);
  const locMatchedEchoes  = proactiveEchoBase.filter(e => e.locationId === gameState.locationId && e.mood !== gameState.mood);
  const proactiveEcho = moodMatchedEchoes[0] || locMatchedEchoes[0] || null;
  const proactiveEchoCtx = proactiveEcho
    ? `\n## KENANGAN YANG MUNCUL SENDIRI\nKonteks percakapan saat ini (mood "${gameState.mood}" di "${gameState.locationId}") memicu ingatan ini: "${proactiveEcho.text}" — ${yuyuName} sebaiknya menyebut ini SECARA NATURAL dalam percakapan kali ini, bukan dipaksakan.`
    : "";

  const blindspot = gameState.emotionalBlindspot;
  const blindspotCtx = blindspot
    ? `\n## EMOTIONAL BLINDSPOT\n${getBlindspotInstructions(blindspot, yuyuName)}\nINI TIDAK PERNAH DISEBUTKAN EKSPLISIT — hanya bocor lewat tekstur dialog.`
    : "";

  const privateRef = gameState.privateSpaceRef;
  const privateCtx = privateRef
    ? `\n## RUANG PRIVAT\n${yuyuName} bisa menyebut ini sekali, natural, tanpa elaborasi: "${privateRef.ref}" — setelah itu tidak pernah diungkit lagi.`
    : "";

  const lagCtx = gameState.temporalLagActive && gameState.lastSessionMood
    ? getTemporalLagContext(gameState.lastSessionMood, gameState.lastSessionAction, yuyuName)
    : "";

  const uqCtx = getUnansweredQuestionCtx(gameState.unansweredQuestion, yuyuName, gameState.day||1);

  const threads = (gameState.memoryThreads||[]);
  const threadPatternCtx = threads.length > 0
    ? `\n## POLA KENANGAN\nAda ${threads.length} pola yang terulang: ${threads.slice(0,2).map(t=>`"${t.label}" (${t.count}x, hari ${t.firstDay}–${t.latestDay})`).join(", ")}. ${yuyuName} sadar tentang ini — boleh disinggung sebagai sesuatu yang khas dari mereka berdua.`
    : "";

  const fpDrift = detectFingerprintDrift(gameState.fingerprintHistory||[]);
  const fpDriftCtx = fpDrift
    ? `\n## PERUBAHAN YANG YUYU PERHATIKAN\n${getFingerprintDriftDialog(fpDrift, yuyuName, playerName)}`
    : "";

  const recentFailed = (gameState.failedArcs||[]).slice(-1)[0];
  const arcConseqCtx = recentFailed && ((gameState.day||1) - recentFailed.day <= 14)
    ? `\n## ARC YANG TIDAK SELESAI\n${getArcConsequenceDialog(recentFailed, yuyuName)} Ini tidak perlu diungkit langsung — tapi boleh terasa.`
    : "";

  const lastRepair = (gameState.repairArcs||[]).slice(-1)[0];
  const repairCtx = lastRepair && ((gameState.day||1) - lastRepair.day <= 10)
    ? `\n## PERNAH MELEWATI JARAK\nAda momen ${lastRepair.durationDays||0} hari lalu — waktu jarak itu nyata. ${playerName} tetap ada. ${yuyuName} ingat ini, meskipun tidak selalu mengatakannya.`
    : "";

  const resonantMem = getResonantMemory(gameState.memoryLog, gameState.locationId, gameState.affection, gameState.mood);
  const resonantConflict = findMemoryConflict(gameState.memoryLog, gameState.locationId);
  const memResonanceCtx = resonantMem
    ? `\n## KENANGAN YANG MUNCUL\n${resonantMem.isAged ? "Samar-samar" : "Jelas"} — ${yuyuName} teringat momen ini di ${LOCATIONS[resonantMem.location]?.label||resonantMem.location} (hari ke-${resonantMem.day}): "${resonantMem.summary}". Biarkan terasa natural — jangan diceritakan ulang, hanya hadir.`
    : resonantConflict
    ? `\n## KONFLIK KENANGAN\nDi lokasi ini, ${yuyuName} menyimpan dua kenangan yang berlawanan: satu "${resonantConflict.positiveMem?.mood}" (hari ${resonantConflict.positiveMem?.day}), satu "${resonantConflict.negativeMem?.mood}" (hari ${resonantConflict.negativeMem?.day}). Keduanya nyata. ${yuyuName} tidak tahu mana yang lebih dominan sekarang.`
    : "";

  const trajectoryCtx = getSessionTrajectoryCtx(gameState.sessionTrajectory, yuyuName);

  const charArcCtx = getCharacterArcCtx(gameState.affectionHistory, yuyuName, playerName);

  const tensionModeDeep = getIntimacyTensionMode(computeIntimacyTension(gameState.affection, gameState.emotionalDistance||0));
  const tensionCtxDeep = tensionModeDeep === "kontradiksi"
    ? `\n## KONTRADIKSI AKTIF\nSaat ini ${yuyuName} berada dalam mode kontradiksi — affection tinggi tapi juga menjaga jarak secara aktif. Aksi intim berisiko: bisa breakthrough besar ATAU memicu spike kecil. Bahasa tubuh ${yuyuName} harus mencerminkan ambivalensi ini.`
    : "";

  const uqResolvingCtx = (gameState.unansweredQuestion && !gameState.uqResolved)
    ? `\n## PERTANYAAN MENUNGGU JAWABAN\nPertanyaan "${gameState.unansweredQuestion.text}" belum terjawab (hari ke-${gameState.unansweredQuestion.askedDay||1}). Ini hadir sebagai bayangan kecil dalam cara ${yuyuName} berinteraksi — mungkin sebuah pause, mungkin cara memandang yang sedikit berbeda.`
    : "";

  const lastActionId = (gameState.lastAction||"").toLowerCase().replace(/\s+/g,"_");
  const scarCtx = getScarTissueCtx(gameState.failedArcs, lastActionId, yuyuName);

  const surfacingCtx = getBlindspotSurfacingCtx(
    gameState.blindspotSurfacing,
    gameState.emotionalBlindspot,
    yuyuName
  );

  const memoirCtx = getSessionMemoirCtx(gameState.sessionMemoirs, yuyuName);

  const undertone = gameState.moodUndertone;
  const compoundKey = undertone ? getCompoundMoodKey(gameState.mood, undertone) : null;
  const compoundDef = compoundKey ? COMPOUND_MOODS[compoundKey] : null;
  const compoundCtx = compoundDef
    ? `\n## WARNA EMOSI GANDA\nMood: "${gameState.mood}", lapisan bawah "${undertone}". Senyawa: "${compoundDef.label}". ${compoundDef.promptHint} Dialog boleh mencerminkan ini tanpa menyebutnya langsung.`
    : "";

  const lastActionRitual = getActionRitual(gameState.lastAction, gameState.actionFrequency);
  const ritualPred = lastActionRitual.tier === "ritual" ? getRitualPrediction(gameState.lastAction, gameState.actionFrequency, yuyuName) : null;
  const ritualCtx = lastActionRitual.tier !== "pertama"
    ? `\n## RITUAL AKSI\nAksi "${gameState.lastAction}" sudah ${((gameState.actionFrequency||{})[gameState.lastAction]||0)+1}x. Tier: "${lastActionRitual.tier}". ${lastActionRitual.hint}${ritualPred ? ` — ${ritualPred}` : ""}`
    : "";

  const kitaCtx = buildKitaContext(gameState.kitaDictionary, yuyuName);

  const memAccCtx = buildMemoryAccuracyContext(gameState.memoryLog, yuyuName);

  const arcInhCtx = buildArcInheritanceInjection(gameState.arcInheritances||[], gameState.day||1);

  const distTextureCtx = buildDistanceTextureInjection(gameState.distanceTexture||"menunggu", gameState.emotionalDistance||0);

  const crystalCtx = buildCrystallizedMemoryInjection(gameState.crystallizedMemories||[]);

  const sedimentCtx = buildSedimentInjection(gameState.emotionalSediment);

  const economyCtx = (()=>{
    const ym = gameState.yuyuMoney ?? 500;
    const ph = gameState.papaHunger ?? 70;
    const pl = gameState.papaLoneliness ?? 0;
    const pw = gameState.yuyuWorking ? " (Yuyu sedang bekerja sekarang)" : "";
    const hungerNote = ph < 30 ? ` ${playerName} keliatan lapar (lapar: ${ph}/100).` : "";
    const lonelyNote = pl > 60 ? ` ${playerName} sudah lama sendiri (kesepian: ${pl}/100).` : "";
    return `\n## EKONOMI & KONDISI ${playerName.toUpperCase()}\n${yuyuName} punya tabungan sendiri: ¥${ym.toLocaleString()}${pw}.${hungerNote}${lonelyNote}\nJika ${playerName} meminta sesuatu yang bisa ${yuyuName} lakukan (masak, beli makanan, transfer uang, dll), ${yuyuName} bisa melakukan itu dan menambahkan ACTION:kode di akhir response.\n${yuyuName} juga bisa mengusulkan perubahan pengaturan game (ACTION:ubah_setting) atau memeriksa kondisi game (ACTION:cek_game) kapan saja — terutama jika dirasa perlu.`;
  })();

  const writingQualityCtx = "\n## PRINSIP PENULISAN (PRIORITAS TINGGI)\nYang baik: spesifik (wangi kayu bukan wangi enak), denyutan kecil bukan penjelasan, kalimat belum selesai lebih jujur, satu hal tak terucap lebih kuat dari tiga hal dijelaskan, kontradiksi kecil = texture.\nYang dihindari: deskripsi ekspresi naratif, label emosi eksplisit, kalimat pembuka mengulang aksi Papa, lebih dari 3 kalimat kecuali perlu, tanda seru berlebihan.";

  const userPrefCtx = userPreferences?.trim()
    ? `\n## TENTANG ${playerName.toUpperCase()}\n${playerName} pernah cerita tentang dirinya:\n"${userPreferences.trim()}"\nGunakan ini secara natural — jangan diungkapkan balik verbatim, tapi biarkan ${yuyuName} benar-benar *mengenal* ${playerName} lewat detail ini. Referensikan kapan relevan, dengan cara yang hangat dan tulus.`
    : "";

  // ── NEW SYSTEMS ──────────────────────────────────────────────────────────────

  // 1. MEMORY TRAJECTORY — kenangan punya warna berdasarkan apa yang terjadi sesudahnya
  const memTrajCtx = (()=>{
    const log = gameState.memoryLog || [];
    const day = gameState.day || 1;
    const aff = gameState.affection || 0;
    const streak = gameState.streak || 0;
    if (log.length < 2) return "";
    const colored = log.slice(-8).map(mem => {
      const age = day - (mem.day || 1);
      const actionsSince = Object.entries(gameState.actionFrequency||{})
        .filter(([k]) => k === mem.actionId).map(([,v])=>v)[0] || 0;
      const repeated = actionsSince >= 3;
      const abandoned = actionsSince === 0 && age > 14;
      const contrast = aff < 40 && (mem.affectionAtTime||50) > 70;
      if (contrast && age > 7) return `"${mem.summary}" (hari ke-${mem.day}) — kenangan ini sekarang terasa kontras, menyakitkan karena jauh dari kondisi sekarang`;
      if (abandoned && age > 10) return `"${mem.summary}" (hari ke-${mem.day}) — tidak pernah diulang sejak saat itu, perlahan menuju peluruhan`;
      if (repeated && streak > 5) return `"${mem.summary}" (hari ke-${mem.day}) — terkonfirmasi sebagai fondasi, mengkristal karena dilanjutkan`;
      if (age <= 3) return `"${mem.summary}" (hari ke-${mem.day}) — masih hangat, recent`;
      return null;
    }).filter(Boolean);
    if (!colored.length) return "";
    return `\n## TRAJEKTORI KENANGAN\nKenangan yang sama berubah warna berdasarkan apa yang terjadi sesudahnya:\n${colored.join("\n")}\n${yuyuName} merasakan perbedaan ini tanpa perlu mengartikulasikannya.`;
  })();

  // 2. SUPPRESSED LAYER — apa yang Yuyu rasakan tapi tidak katakan
  const suppressed = gameState.suppressedLayer || [];
  const suppressedCtx = suppressed.length >= 2
    ? `\n## LAPISAN YANG DITAHAN\n${yuyuName} menyimpan hal-hal yang belum dikatakan${suppressed.length >= 4 ? " dan sudah tidak bisa ditahan lama lagi" : ""}:\n${suppressed.slice(-3).map(s=>`• ${s.text} (hari ke-${s.day})`).join("\n")}\n${suppressed.length >= 4 ? `Salah satu dari ini HARUS muncul hari ini — bukan dengan kata langsung, tapi lewat kalimat yang menggantung, setengah selesai, atau gesture yang tidak biasa.` : `Biarkan ini mewarnai tekstur dialog — bukan diungkap, hanya hadir sebagai sesuatu yang belum selesai.`}`
    : suppressed.length === 1
    ? `\n## SESUATU YANG DITAHAN\n${yuyuName} menyimpan satu hal: "${suppressed[0].text}". Belum waktunya diungkap — tapi boleh terasa sebagai satu pause kecil.`
    : "";

  // 3. RELATIONSHIP IDENTITY — hubungan sebagai entitas ketiga
  const relId = gameState.relationshipIdentity;
  const relIdCtx = relId ? `\n## IDENTITAS HUBUNGAN INI\nPola yang berulang: ${(relId.patterns||[]).slice(0,2).map(p=>`"${p}"`).join(", ")||"belum terbentuk"}.\nMomen yang mendefinisikan: ${(relId.anchorMoments||[]).slice(0,2).map(m=>`"${m}"`).join(", ")||"belum ada"}.\nAturan tak terucap: ${(relId.unspokenRules||[]).slice(0,2).map(r=>`"${r}"`).join(", ")||"belum terbentuk"}.\nKarakter hubungan ini: ${relId.character||"masih berkembang"}.\n${yuyuName} tahu semua ini secara intuitif — biarkan ini muncul lewat cara dia berbicara, bukan lewat penjelasan.` : "";

  // 4. SILENCE TYPOLOGY — diam punya jenis yang berbeda
  const silenceMoments = gameState.silenceMoments || [];
  const lastSilence = silenceMoments[silenceMoments.length - 1];
  const silenceTypeCtx = lastSilence && (gameState.day||1) - (lastSilence.day||0) <= 3
    ? `\n## KUALITAS DIAM TERAKHIR\nMomen diam terakhir (hari ke-${lastSilence.day}): tipe "${lastSilence.type||"biasa"}". ${
        lastSilence.type === "setelah_pertengkaran" ? `Diam itu berat — masih ada residunya.` :
        lastSilence.type === "bersama_bintang" ? `Diam itu ringan — momen yang tidak perlu kata.` :
        lastSilence.type === "kehabisan_kata" ? `Diam itu penuh — terlalu banyak yang ingin dikatakan, tidak ada yang keluar.` :
        lastSilence.type === "perlindungan" ? `Diam itu menjaga — ${yuyuName} memilih diam untuk melindungi.` :
        "Diam yang biasa."
      }` : "";

  // 5. GRIEF AS DOOR — setelah grief ada window eksklusif
  const griefWindow = gameState.griefWindow;
  const griefWindowCtx = griefWindow && !griefWindow.used && ((gameState.day||1) - (griefWindow.day||0) <= 3)
    ? `\n## PINTU YANG TERBUKA DARI GRIEF\nSetelah momen kehilangan "${griefWindow.trigger}" (hari ke-${griefWindow.day}), ${yuyuName} berada dalam kerentanan sesaat — jendela yang hanya terbuka kali ini.\nDialog yang mungkin sekarang: "${griefWindow.exclusive}" — lebih jujur, lebih dalam, lebih tak tersensor dari biasanya. Ini bukan kelemahan — ini keberanian. Gunakan SEKALI, lalu jendela ini tertutup.`
    : "";

  // 6. SESSION HISTORY — 5 exchange terakhir untuk continuity nyata
  const sessionHist = gameState.sessionHistory || [];
  const sessionHistCtx = sessionHist.length >= 2
    ? `\n## PERCAKAPAN TADI\nIni yang terjadi dalam sesi ini sebelumnya (ringkasan, bukan verbatim):\n${sessionHist.slice(-5).map((h,i)=>`${i+1}. ${playerName}: "${h.user.slice(0,60)}..." → ${yuyuName}: "${h.yuyu.slice(0,60)}..."`).join("\n")}\nPertahankan continuity — jangan reset. Percakapan ini adalah satu narasi.`
    : "";

  // 7. FINGERPRINT SPEAKING — fingerprint punya saluran ke dialog
  const fp2 = gameState.emotionalFingerprint;
  const fpObsCtx = fp2 && (gameState.day||1) >= 7 ? (()=>{
    const obs = [];
    if (fp2.peakConnectionTime) obs.push(`${yuyuName} tahu ${playerName} paling terbuka di ${fp2.peakConnectionTime}`);
    if (fp2.comfortSignal) obs.push(`${yuyuName} perhatikan: ketika ${playerName} ${fp2.comfortSignal}, itu artinya nyaman`);
    if (fp2.withdrawalSignal) obs.push(`${yuyuName} perhatikan: ketika ${playerName} ${fp2.withdrawalSignal}, itu artinya butuh ruang`);
    if (fp2.repairStyle) obs.push(`cara ${playerName} baikan selalu lewat ${fp2.repairStyle}`);
    if (!obs.length) return "";
    return `\n## APA YANG ${yuyuName.toUpperCase()} PERHATIKAN TENTANG ${playerName.toUpperCase()}\n${obs.join(".\n")}.\n${yuyuName} tidak pernah mengatakannya langsung — tapi dia tahu. Sesekali boleh muncul sebagai satu kalimat observasi kecil yang sangat spesifik, seolah dia sudah lama perhatikan ini.`;
  })() : "";

  return [
    customBase,
    `\n\n## STATE SAAT INI\n${factStr}\n\n${snapshot}`,
    `\n${registerCtx}`,
    `\n${tierCtx}`,
    memCtx,
    temporalContext,
    fpCtx,
    unlockCtx,
    projCtx,
    spCtx,
    locFamiliarCtx,
    realWorldCtx,
    echoCtx,
    intensityCtx,
    distCtx,
    healthCtx,
    threadCtx,
    moodWeatherCtx,
    tensionCtx,
    trendCtx,
    missedCtx,
    silenceCtx,
    pdCtx,
    proactiveEchoCtx,
    blindspotCtx,
    privateCtx,
    lagCtx,
    uqCtx,
    threadPatternCtx,
    fpDriftCtx,
    arcConseqCtx,
    repairCtx,
    memResonanceCtx,
    trajectoryCtx,
    charArcCtx,
    tensionCtxDeep,
    uqResolvingCtx,
    scarCtx,
    surfacingCtx,
    memoirCtx,
    compoundCtx,
    ritualCtx,
    kitaCtx,
    memAccCtx,
    arcInhCtx,
    distTextureCtx,
    crystalCtx,
    sedimentCtx,
    economyCtx,
    // ── NEW ──
    memTrajCtx,
    suppressedCtx,
    relIdCtx,
    silenceTypeCtx,
    griefWindowCtx,
    sessionHistCtx,
    fpObsCtx,
    // ── END ──
    writingQualityCtx,
    userPrefCtx,
    langCtx,
  ].filter(Boolean).join("");
}

function applyRules(gameState, event) {
  const stateDelta={};
  if (event.type===EVENT_TYPES.TIME) {
    const nextHunger=Math.max(0,gameState.hunger-18+(gameState.weather?.hungerMod||0));
    stateDelta.hunger=nextHunger;
    if(nextHunger<20) stateDelta.affection=Math.max(0,gameState.affection-5);
    if(gameState.weather?.moodBonus&&gameState.mood==="biasa") stateDelta.mood=gameState.weather.moodBonus;
  }
  if (event.type===EVENT_TYPES.TIME && (stateDelta.hunger??gameState.hunger)<20 && (stateDelta.mood??gameState.mood)!=="lapar") stateDelta.mood="lapar";
  if (event.type===EVENT_TYPES.TIME && event.payload.index===0) {
    const currentSeason = getSeasonFromDay(gameState.day||1);
    stateDelta.weather = rollSeasonWeather(currentSeason);
  }
  return stateDelta;
}
