const ACCENT_PRESETS = [
  {id:"pink",   label:"Merah Muda", main:"#fb7185", soft:"#fecdd3", glow:"rgba(251,113,133,.18)", border:"rgba(251,113,133,.25)", light:"#fff0f3"},
  {id:"purple", label:"Lavender",   main:"#c084fc", soft:"#e9d5ff", glow:"rgba(192,132,252,.18)", border:"rgba(192,132,252,.25)", light:"#faf5ff"},
  {id:"blue",   label:"Biru Langit",main:"#60a5fa", soft:"#bfdbfe", glow:"rgba(96,165,250,.18)",  border:"rgba(96,165,250,.25)",  light:"#eff6ff"},
  {id:"sage",   label:"Hijau Sage", main:"#6ee7b7", soft:"#a7f3d0", glow:"rgba(110,231,183,.18)", border:"rgba(110,231,183,.25)", light:"#ecfdf5"},
  {id:"peach",  label:"Persik",     main:"#fdba74", soft:"#fed7aa", glow:"rgba(253,186,116,.18)", border:"rgba(253,186,116,.25)", light:"#fff7ed"},
  {id:"cream",  label:"Krim Susu",  main:"#e2d9c8", soft:"#f5f0e8", glow:"rgba(226,217,200,.18)", border:"rgba(226,217,200,.3)",  light:"#fdfcfa"},
];
const getAccentPreset = id => ACCENT_PRESETS.find(p=>p.id===id) ?? ACCENT_PRESETS[0];
function getColorTheme(id, customHex){
  if(id==="custom" && customHex){
    const derived = deriveThemeFromHex(customHex);
    if(derived){
      const t = COLOR_THEMES.find(t=>t.id==="custom");
      return {...t, dark:derived.dark, light:derived.light, accent:derived.accent};
    }
  }
  return COLOR_THEMES.find(t=>t.id===id) ?? COLOR_THEMES[0];
}
function detectLoveLanguage(gs) {
  const msgs = (gs.moodHistory||[]).length;
  const gifts = (gs.giftHistory||[]).length;
  const acts = (gs.customActivities||[]).length;
  const days = gs.day||1;
  if (msgs/days > 2) return LOVE_LANGUAGE_THRESHOLDS[0];
  if (days > 10 && (gs.affection||0) > 60) return LOVE_LANGUAGE_THRESHOLDS[1];
  if (acts > 5) return LOVE_LANGUAGE_THRESHOLDS[2];
  if (gifts > 3) return LOVE_LANGUAGE_THRESHOLDS[3];
  return LOVE_LANGUAGE_THRESHOLDS[4];
}


