// VISUAL
// ═══════════════════════════════════════════════════════════════

class YuyuErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      copied: false,
      ts: null,
      retryCount: 0,
      asyncErrors: [],
    };
    this._snap = null;

    this._FATAL_ASYNC_TYPES = ["SyntaxError","TypeError: Cannot","ReferenceError","Unexpected token"];

    this._onError = (event) => {
      const msg = event.message || String(event);
      const isFatal = this._FATAL_ASYNC_TYPES.some(t => msg.includes(t));
      this.setState(s => {
        const asyncErrors = [...s.asyncErrors.slice(-9), {
          type: "window.error", msg, ts: new Date().toISOString(), fatal: isFatal,
        }];

        if (isFatal && !s.hasError) {
          const syntheticError = new Error(msg);
          return { asyncErrors, hasError: true, error: syntheticError, ts: new Date().toISOString() };
        }
        return { asyncErrors };
      });
    };

    this._onUnhandled = (event) => {
      const reason = event.reason;
      const msg = reason?.message || String(reason);
      if (msg.includes("ResizeObserver") || msg.includes("AbortError") || msg.includes("storage")) return;
      const isFatal = this._FATAL_ASYNC_TYPES.some(t => msg.includes(t));
      this.setState(s => {
        const asyncErrors = [...s.asyncErrors.slice(-9), {
          type: "unhandledrejection", msg, ts: new Date().toISOString(), fatal: isFatal,
        }];
        if (isFatal && !s.hasError) {
          return { asyncErrors, hasError: true, error: new Error(msg), ts: new Date().toISOString() };
        }
        return { asyncErrors };
      });
    };
  }

  componentDidMount() {

    window.__yuyuMounted = true;
    const shield = document.getElementById("__yuyu_l0_shield");
    if (shield) shield.remove();

    (window.__yuyuEarlyErrors || []).forEach(e => {
      this.setState(s => ({ asyncErrors: [...s.asyncErrors.slice(-9), { type:"pre-mount", msg:e.msg, ts:e.ts, fatal:true }]}));
    });
    window.addEventListener("error", this._onError);
    window.addEventListener("unhandledrejection", this._onUnhandled);
  }

  componentWillUnmount() {
    window.__yuyuMounted = false;
    window.removeEventListener("error", this._onError);
    window.removeEventListener("unhandledrejection", this._onUnhandled);
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error, ts: new Date().toISOString() };
  }

  componentDidCatch(error, errorInfo) {
    this.setState({ errorInfo });

    this._snap = null;
    try {
      const raw = window._yuyuStateSnapshot || null;
      if (raw) this._snap = typeof raw === "string" ? JSON.parse(raw) : raw;
    } catch(_) {}

    if (!this._snap) {
      try {
        window.storage?.get("yuyu-game").then(r => {
          if (r?.value) {
            try { this._snap = JSON.parse(r.value); this.forceUpdate(); } catch(_) {}
          }
        }).catch(() => {});
      } catch(_) {}
    }
  }

  _categorize(msg) {
    if (!msg) return { label: "Unknown Error", color: "#a78bfa" };
    if (msg.includes("Cannot read propert") || msg.includes("undefined") || msg.includes("null"))
      return { label: "Null / Undefined Access", color: "#f87171" };
    if (msg.includes("is not a function"))
      return { label: "Missing Function", color: "#fb923c" };
    if (msg.includes("SyntaxError") || msg.includes("Unexpected token") || msg.includes("Invalid"))
      return { label: "Syntax / Parse Error", color: "#facc15" };
    if (msg.includes("Maximum call stack") || msg.includes("too much recursion"))
      return { label: "Infinite Recursion", color: "#f87171" };
    if (msg.includes("ChunkLoadError") || msg.includes("Loading chunk") || msg.includes("fetch"))
      return { label: "Network / Load Error", color: "#60a5fa" };
    if (msg.includes("ResizeObserver"))
      return { label: "ResizeObserver (benign)", color: "#4ade80" };
    if (msg.includes("storage") || msg.includes("quota"))
      return { label: "Storage Error", color: "#f472b6" };
    if (msg.includes("memory") || msg.includes("Memory"))
      return { label: "Out of Memory", color: "#f87171" };
    return { label: "Runtime Error", color: "#c084fc" };
  }

  _buildReport() {
    const { error, errorInfo, ts, asyncErrors } = this.state;
    const msg = error?.message || String(error) || "Unknown error";
    const cat = this._categorize(msg);
    const rawStack = error?.stack || "";
    const stackLines = rawStack.split("\n").map(l => l.trim()).filter(l => l && l !== msg).slice(0, 24);
    const componentStack = (errorInfo?.componentStack || "").split("\n").map(l => l.trim()).filter(Boolean).slice(0, 18);
    const snap = this._snap ? {
      day: this._snap.day,
      mood: this._snap.mood,
      affection: Math.round(this._snap.affection ?? 0),
      hunger: this._snap.hunger,
      money: this._snap.money,
      streak: this._snap.streak,
      locationId: this._snap.locationId,
      timeIdx: this._snap.timeIdx,
      yuyuHealthState: this._snap.yuyuHealthState,
      emotionalDistance: Math.round(this._snap.emotionalDistance ?? 0),
      weeklyArcId: this._snap.weeklyArcId,
      lastAction: this._snap.lastAction,
      screen: this._snap.screen,
    } : null;
    return { msg, cat, stackLines, componentStack, snap, ts, asyncErrors };
  }

  _copyReport() {
    const r = this._buildReport();
    const lines = [
      `╔══════════════════════════════════════════`,
      `║  YUYU ERROR REPORT`,
      `╚══════════════════════════════════════════`,
      ``,
      `🕐 ${r.ts}`,
      `🏷  ${r.cat.label}`,
      `💬 ${r.msg}`,
      ``,
      `STACK TRACE:`,
      ...r.stackLines.map(l => "  " + l),
      ``,
      `COMPONENT TREE:`,
      ...r.componentStack.map(l => "  " + l),
      ...(r.asyncErrors.length ? [
        ``,
        `ASYNC ERRORS (window):`,
        ...r.asyncErrors.map(e => `  [${e.type}] ${e.msg}`),
      ] : []),
      ...(r.snap ? [
        ``,
        `GAME STATE SNAPSHOT:`,
        ...Object.entries(r.snap).map(([k,v]) => `  ${k.padEnd(20)}: ${JSON.stringify(v)}`),
      ] : [``, `Game state: not available`]),
      ``,
      `══════════════════════════════════════════`,
    ].join("\n");

    navigator.clipboard?.writeText(lines).then(() => {
      this.setState({ copied: true });
      setTimeout(() => this.setState({ copied: false }), 2500);
    }).catch(() => {
      const ta = document.getElementById("yuyu-err-ta");
      if (ta) { ta.select(); document.execCommand("copy"); }
    });
  }

  async _resetSave() {
    try {
      if (window.storage) {
        await window.storage.delete("yuyu-game");
        await window.storage.delete("yuyu_rpg_state");
      }
    } catch(_) {}
    window.location.reload();
  }

  _tryRecover() {
    this.setState(s => ({ hasError: false, error: null, errorInfo: null, retryCount: s.retryCount + 1 }));
  }

  render() {
    if (!this.state.hasError) return this.props.children;

    const r = this._buildReport();
    const { retryCount } = this.state;
    const _cc = r.cat.color;

    const fullText = [r.ts, r.cat.label, r.msg, "", ...r.stackLines, "", ...r.componentStack].join("\n");

    const base = {
      fontFamily:"'Courier New',monospace",
      WebkitTapHighlightColor:"transparent",
    };
    const overlay = {
      ...base,
      position:"fixed",inset:0,zIndex:99999,
      background:"#060208",color:"#e8d5f0",
      display:"flex",flexDirection:"column",alignItems:"center",
      overflowY:"auto",padding:"24px 16px 56px",
    };
    const card = {
      width:"100%",maxWidth:"520px",
      background:C.ACC3,
      border:`1px solid ${_cc}33`,
      borderRadius:"20px",padding:"18px 20px",marginBottom:"10px",
    };
    const code = {
      background:"rgba(0,0,0,.45)",border:"1px solid rgba(255,255,255,.07)",
      borderRadius:"10px",padding:"11px 13px",
      fontSize:"10px",lineHeight:"1.75",color:"#f8c4dc",
      whiteSpace:"pre-wrap",wordBreak:"break-all",
      maxHeight:"180px",overflowY:"auto",
    };
    const lbl = {
      fontSize:"8px",letterSpacing:"0.25em",color:"rgba(200,140,180,0.70)",
      marginBottom:"6px",textTransform:"uppercase",
    };
    const btn = (primary) => ({
      padding: primary ? "12px 24px" : "10px 16px",
      borderRadius:"12px",cursor:"pointer",
      border: primary ? `1px solid ${_cc}55` : "1px solid rgba(255,255,255,.1)",
      background: primary ? `${_cc}18` : C.A5A2,
      color: primary ? _cc : "rgba(220,180,200,.7)",
      fontSize: primary ? "12px" : "10px",
      letterSpacing:"0.07em",
      transition:"opacity .15s",
      ...base,
    });

    return (
      <div style={overlay}>

        <div style={{width:"100%",maxWidth:"520px",marginBottom:"14px"}}>
          <div style={{display:"flex",alignItems:"center",gap:"12px",marginBottom:"10px"}}>
            <span style={{fontSize:"32px",filter:`drop-shadow(0 0 8px ${_cc}88)`}}>💔</span>
            <div>
              <p style={{fontSize:"14px",fontWeight:"700",color:_cc,fontFamily:"Georgia,serif",fontStyle:"italic",marginBottom:"2px"}}>
                Ada yang crash...
              </p>
              <p style={{fontSize:"9px",color:"rgba(200,140,160,0.70)",letterSpacing:"0.14em"}}>
                {r.ts} {retryCount > 0 ? `· retry #${retryCount}` : ""}
              </p>
            </div>
          </div>

          <span style={{
            display:"inline-block",padding:"4px 12px",borderRadius:"99px",
            background:`${_cc}18`,border:`1px solid ${_cc}44`,color:_cc,
            fontSize:"9.5px",letterSpacing:"0.18em",fontWeight:"700",
          }}>
            {r.cat.label.toUpperCase()}
          </span>
        </div>

        <div style={card}>
          <p style={lbl}>Pesan Error</p>
          <div style={{...code, maxHeight:"72px", fontSize:"11px", color:"#fde68a"}}>
            {r.msg}
          </div>
        </div>

        <div style={card}>
          <p style={lbl}>Stack Trace</p>
          <div style={code}>
            {r.stackLines.length > 0
              ? r.stackLines.map((l,i) => (
                  <span key={i} style={{
                    display:"block",marginBottom:"2px",
                    color: i===0 ? "#fde68a" : i<4 ? _cc : "rgba(220,180,200,0.70)",
                    fontSize:"9.5px",
                  }}>{l}</span>
                ))
              : <span style={{color:"rgba(200,150,170,0.65)"}}>tidak tersedia</span>
            }
          </div>
        </div>

        {r.componentStack.length > 0 && (
          <div style={card}>
            <p style={lbl}>Component Tree — crash terjadi di sini ↓</p>
            <div style={code}>
              {r.componentStack.map((l,i) => (
                <span key={i} style={{
                  display:"block",marginBottom:"1px",
                  color: i===0 ? "#86efac" : i<3 ? "#86efac" : "rgba(134,239,172,0.65)",
                  fontSize:"9.5px",
                }}>{l}</span>
              ))}
            </div>
          </div>
        )}

        {r.asyncErrors.length > 0 && (
          <div style={card}>
            <p style={lbl}>Async Errors (window)</p>
            <div style={code}>
              {r.asyncErrors.map((e,i) => (
                <span key={i} style={{display:"block",marginBottom:"3px",fontSize:"9px",color:"rgba(251,113,133,.7)"}}>
                  [{e.type}] {e.msg}
                </span>
              ))}
            </div>
          </div>
        )}

        <div style={card}>
          <p style={lbl}>Game State Snapshot</p>
          {r.snap ? (
            <div style={{...code, maxHeight:"240px"}}>
              {Object.entries(r.snap).map(([k,v],i) => (
                <div key={k} style={{
                  display:"flex",gap:"8px",padding:"3px 0",fontSize:"9.5px",
                  borderBottom: i%2===0 ? "1px solid rgba(255,255,255,.04)" : "none",
                }}>
                  <span style={{color:"rgba(200,160,210,.55)",minWidth:"130px",flexShrink:0}}>{k}</span>
                  <span style={{color:"#e2c4f0",wordBreak:"break-all"}}>{JSON.stringify(v)}</span>
                </div>
              ))}
            </div>
          ) : (
            <p style={{fontSize:"9px",color:"rgba(200,140,160,0.65)",padding:"6px 0"}}>
              Belum ada snapshot — game mungkin crash sebelum state sempat disimpan.
            </p>
          )}
        </div>

        <div style={{width:"100%",maxWidth:"520px",display:"flex",gap:"8px",flexWrap:"wrap",justifyContent:"center",marginBottom:"12px"}}>
          {retryCount < 3 && (
            <button style={btn(true)} onClick={() => this._tryRecover()}>
              ✦ Coba Recover
            </button>
          )}
          <button style={btn(false)} onClick={() => this._copyReport()}>
            {this.state.copied ? "✓ Tersalin!" : "📋 Copy Laporan"}
          </button>
          <button style={btn(false)} onClick={() => window.location.reload()}>
            🔄 Reload
          </button>
          <button style={{...btn(false), color:"rgba(248,113,113,.6)"}} onClick={() => this._resetSave()}>
            🗑 Reset Save
          </button>
        </div>

        <div style={{
          width:"100%",maxWidth:"520px",padding:"10px 14px",borderRadius:"12px",
          background:"rgba(251,191,36,.05)",border:"1px solid rgba(251,191,36,.12)",
        }}>
          <p style={{fontSize:"9px",color:"rgba(251,191,36,.55)",lineHeight:"1.8"}}>
            💡 <strong>Cara debug:</strong> Copy laporan → paste ke Claude.
            {retryCount < 3
              ? ' Atau klik "Coba Recover" — kadang error sifatnya transient dan bisa pulih sendiri.'
              : ' Sudah 3× retry gagal — coba Reset Save sebagai last resort.'
            }
          </p>
        </div>

        <textarea id="yuyu-err-ta" readOnly value={fullText}
          style={{position:"absolute",left:"-9999px",top:0,opacity:0,pointerEvents:"none"}}/>
      </div>
    );
  }
}

// ─── EMOTIONAL STATE STRIP ────────────────────────────────────────────────────
// Ambient HUD: makes invisible emotional systems visible as tappable world signals
function EmotionalStateStrip({ gameState, palette, isLight, yuyuName,
  onOpenInnerWorld, onOpenMemory, onOpenGoals, onOpenHeart,
  yuyuCurrentActivity, yuyuSameLocation, accent }) {

  const dist   = gameState.emotionalDistance || 0;
  const sed    = gameState.emotionalSediment?.weight || 0;
  const sedTex = gameState.emotionalSediment?.texture || "unspoken";
  const moodW  = gameState.moodWeatherId || "biasa_saja";
  const uqActive = (gameState.unansweredQuestions||[]).filter(q=>!q.resolved).length;
  const tension  = (gameState.intimacyTension||0);
  const kita     = (gameState.kitaDictionary||[]).length;

  // Only show signals when there's something worth showing
  const signals = [];

  if (dist >= 25) signals.push({
    id:"dist", icon:"🌫️",
    color: dist>=60?"rgba(248,113,113,":"rgba(147,197,253,",
    label: dist>=60?"renggang":dist>=45?"menjauh":"sedikit jauh",
    pulse: dist>=50,
    onTap: onOpenInnerWorld,
  });

  if (sed >= 30) signals.push({
    id:"sed", icon: sedTex==="grief"?"💜":sedTex==="longing"?"🌙":sedTex==="distance"?"💨":"🪨",
    color:"rgba(192,132,252,",
    label:`endapan`,
    pulse: sed>=65,
    onTap: onOpenInnerWorld,
  });

  if (uqActive > 0) signals.push({
    id:"uq", icon:"❓",
    color:"rgba(251,191,36,",
    label: uqActive===1?"misteri":"misteri×"+uqActive,
    pulse: false,
    onTap: ()=>onOpenGoals("misteri"),
  });

  if (tension >= 50) signals.push({
    id:"ten", icon:"⚡",
    color:"rgba(251,146,60,",
    label:"tegang",
    pulse: tension>=75,
    onTap: onOpenHeart,
  });

  if (kita >= 3 && !signals.find(s=>s.id==="kita")) signals.push({
    id:"kita", icon:"🔤",
    color:"rgba(110,231,183,",
    label:`${kita} kata kita`,
    pulse: false,
    onTap: onOpenGoals,
  });

  if (signals.length === 0) return null;

  const textSub = `rgba(var(--yui-ts),0.52)`;

  return (
    <div style={{
      position:"absolute", top:"50px", left:0, right:0,
      display:"flex", justifyContent:"center", gap:"6px",
      zIndex:295, pointerEvents:"none",
      padding:"0 16px",
      flexWrap:"wrap",
    }}>
      {yuyuCurrentActivity && yuyuSameLocation && (
        <span style={{
          fontSize:"7px", letterSpacing:"0.1em",
          color: accent||palette.accent,
          display:"inline-flex", alignItems:"center", gap:"4px",
          background:`rgba(var(--yui-ov),0.14)`,
          border:`1px solid ${(accent||palette.accent)}44`,
          borderRadius:"99px", padding:"3px 10px",
          backdropFilter:"blur(8px)", WebkitBackdropFilter:"blur(8px)",
          animation:"tl_breathe 2s ease-in-out infinite",
          pointerEvents:"none", whiteSpace:"nowrap",
        }}>
          <span style={{
            width:"5px", height:"5px", borderRadius:"50%",
            background: accent||palette.accent, display:"inline-block", flexShrink:0,
            boxShadow:`0 0 6px ${accent||palette.accent}`,
            animation:"tl_breathe 1.2s ease-in-out infinite",
          }}/>
          {yuyuCurrentActivity.icon} {yuyuCurrentActivity.label}
        </span>
      )}
      {signals.slice(0,4).map(sig=>(
        <button key={sig.id}
          onClick={sig.onTap}
          style={{
            display:"flex", alignItems:"center", gap:"4px",
            padding:"5px 10px", borderRadius:"999px",
            background: isLight?"rgba(255,255,255,.72)":sig.pulse?`${sig.color}0.1)`:"rgba(0,0,0,.42)",
            border:`1px solid ${sig.color}${sig.pulse?"0.45)":"0.22)"})`,
            backdropFilter:"blur(8px)", WebkitBackdropFilter:"blur(8px)",
            boxShadow: sig.pulse?`0 0 10px ${sig.color}0.25), inset 0 0 8px ${sig.color}0.08)`:"none",
            color:`${sig.color}0.9)`,
            fontSize:"9px", letterSpacing:"0.06em",
            cursor:"pointer", pointerEvents:"all",
            touchAction:"manipulation", WebkitTapHighlightColor:"transparent",
            animation: sig.pulse?"worldSignalPulse 2.4s ease-in-out infinite":"none",
            transition:"transform .1s, box-shadow .2s",
          }}>
          <span style={{fontSize:"11px",lineHeight:1}}>{sig.icon}</span>
          <span style={{color:isLight?`${sig.color}0.85)`:textSub,fontSize:"8px",letterSpacing:"0.08em"}}>{sig.label}</span>
        </button>
      ))}
      <style>{`
        @keyframes worldSignalPulse{
          0%,100%{box-shadow:0 0 6px rgba(var(--yui-ac),0.2),inset 0 0 4px rgba(var(--yui-ac),0.06)}
          50%{box-shadow:0 0 16px rgba(var(--yui-ac),0.35),inset 0 0 10px rgba(var(--yui-ac),0.12)}
        }
      `}</style>
    </div>
  );
}

function GoalsPanelOverlay({ gameState, yuyuName, isLight, palette, onClose, initialTab="tujuan" }) {
  const [tab, setTab] = React.useState(initialTab);
  const currentWish = gameState.dailyWish;
  const currentAgenda = YUYU_AGENDA_POOL.find(agendaItem => agendaItem.id === gameState.yuyuAgendaId);
  const currentProphecy = YUYU_PROPHECY_POOL.find(prophecyItem => prophecyItem.id === gameState.prophecyId);
  const currentArc = WEEKLY_ARC_TEMPLATES.find(arcTemplate => arcTemplate.id === gameState.weeklyArcId);
  const dayInArc = Math.max(1, (gameState.day || 1) - (gameState.weeklyArcStartDay || 1));
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:850,background:C.A25C,backdropFilter:"blur(4px)",display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div onClick={element => element.stopPropagation()} style={{
        width:"100%",maxWidth:"420px",
        background:isLight?palette.bgPanel||"rgba(255,248,240,.98)":palette.bgPanel||C.A4D6,
        border:`1px solid ${palette.border}`,borderRadius:"20px 20px 0 0",
        padding:"16px 16px 28px",animation:"slideUp .28s cubic-bezier(.16,1,.3,1)",
        maxHeight:"70vh",overflowY:"auto"
      }}>
        <div style={_S.WIDTH_9688}/>
        {/* Tab switcher */}
        <div style={{display:"flex",gap:"6px",marginBottom:"14px",justifyContent:"center"}}>
          {[{id:"tujuan",icon:"🎯",label:"Tujuan"},{id:"misteri",icon:"❓",label:"Misteri"}].map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{
              padding:"6px 16px",borderRadius:"99px",fontSize:"9px",letterSpacing:"0.1em",
              background:tab===t.id?`rgba(var(--yui-ac),0.14)`:"transparent",
              border:`1px solid ${tab===t.id?palette.border:"rgba(var(--yui-tu),0.1)"}`,
              color:tab===t.id?palette.accent:`rgba(var(--yui-ts),0.5)`,
              cursor:"pointer",WebkitTapHighlightColor:"transparent",
              display:"flex",alignItems:"center",gap:"5px",
            }}><span>{t.icon}</span>{t.label}</button>
          ))}
        </div>
        {tab==="tujuan" && (<>
        {currentWish && (
          <div style={{padding:"12px",borderRadius:"14px",background:`rgba(var(--yui-ov),0.04)`,marginBottom:"8px",border:`1px solid ${currentWish.fulfilled?"rgba(110,231,183,.3)":palette.border}`}}>
            <p style={{fontSize:"8px",letterSpacing:"0.2em",color:palette.accent,marginBottom:"6px"}}>⭐ WISH HARI INI</p>
            <p style={_S.FONTSIZE_045c}>
              "{currentWish.label}"
            </p>
            <p style={{fontSize:"8px",marginTop:"4px",color:currentWish.fulfilled?"var(--yui-success-color)":"rgba(200,150,170,0.72)"}}>
              {currentWish.fulfilled ? "✓ Terpenuhi~" : "Belum terpenuhi..."}
            </p>
          </div>
        )}
        {currentAgenda && (
          <div style={{padding:"12px",borderRadius:"14px",background:`rgba(var(--yui-ov),0.04)`,marginBottom:"8px",border:`1px solid ${gameState.agendaFulfilled?"rgba(110,231,183,.3)":palette.border}`}}>
            <p style={{fontSize:"8px",letterSpacing:"0.2em",color:palette.accent,marginBottom:"6px"}}>🎯 AGENDA {yuyuName.toUpperCase()}</p>
            <p style={_S.FONTSIZE_045c}>
              {gameState.agendaDiscovered ? `"${currentAgenda.discoveryText}"` : `${yuyuName} ingin sesuatu hari ini... coba tebak.`}
            </p>
            <p style={{fontSize:"8px",marginTop:"4px",color:gameState.agendaFulfilled?"var(--yui-success-color)":"rgba(200,150,170,0.72)"}}>
              {gameState.agendaFulfilled ? `✓ Terpenuhi +${currentAgenda.bonusIfFulfilled?.affection}♡` : gameState.agendaDiscovered ? "Ketahuan tapi belum terpenuhi" : "Belum ditemukan..."}
            </p>
          </div>
        )}
        {currentProphecy && (
          <div style={{padding:"12px",borderRadius:"14px",background:`rgba(var(--yui-ov),0.04)`,marginBottom:"8px",border:`1px solid ${gameState.prophecyFulfilled?"rgba(110,231,183,.3)":gameState.prophecyMissed?"rgba(248,113,113,.3)":palette.border}`}}>
            <p style={{fontSize:"8px",letterSpacing:"0.2em",color:palette.accent,marginBottom:"6px"}}>🔮 PROPHECY MINGGU INI</p>
            <p style={_S.FONTSIZE_045c}>
              "{currentProphecy.text}"
            </p>
            <p style={{fontSize:"8px",marginTop:"4px",
              color:gameState.prophecyFulfilled?"var(--yui-success-color)":gameState.prophecyMissed?"var(--yui-danger-color)":"rgba(200,150,170,0.72)"}}>
              {gameState.prophecyFulfilled ? "✓ Terpenuhi~" : gameState.prophecyMissed ? "Terlewat..." : `Hari ke-${Math.min(7,(gameState.day||1)-(gameState.prophecyWeekStartDay||1)+1)}/7`}
            </p>
          </div>
        )}
        {currentArc && (
          <div style={{padding:"12px",borderRadius:"14px",background:`rgba(var(--yui-ov),0.04)`,marginBottom:"8px",border:`1px solid ${palette.border}`}}>
            <p style={{fontSize:"8px",letterSpacing:"0.2em",color:palette.accent,marginBottom:"6px"}}>📚 ARC MINGGU INI — {currentArc.title}</p>
            <div style={{display:"flex",gap:"4px",flexWrap:"wrap"}}>
              {[1,2,3,4,5,6,7].map(arcDayNumber => (
                <div key={arcDayNumber} style={{
                  width:"24px",height:"24px",borderRadius:"8px",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  fontSize:"9px",
                  background:arcDayNumber===dayInArc?(`rgba(var(--yui-tu),0.2)`):arcDayNumber<dayInArc?"rgba(110,231,183,.15)":C.ACC3,
                  border:`1px solid ${arcDayNumber===dayInArc?palette.border:arcDayNumber<dayInArc?"rgba(110,231,183,.2)":C.ABBB}`,
                  color:arcDayNumber===dayInArc?palette.accent:arcDayNumber<dayInArc?"var(--yui-success-color)":"rgba(255,255,255,0.62)",
                }}>
                  {arcDayNumber < dayInArc ? "✓" : arcDayNumber}
                </div>
              ))}
            </div>
            {currentArc.days.find(arcDay => arcDay.day === dayInArc) && (
              <p style={{fontSize:"9px",color:`rgba(var(--yui-ts),0.55)`,lineHeight:"1.5",marginTop:"8px",fontStyle:"italic"}}>
                Hari ini: {currentArc.days.find(arcDay => arcDay.day === dayInArc)?.hint}
              </p>
            )}
          </div>
        )}
        {(()=>{
          const pdRecipe = gameState.perfectDayRecipe;
          const pdProgress = gameState.perfectDayProgress||[];
          const pdDone = gameState.perfectDayCompleted;
          if (!pdRecipe) return null;
          const totalSteps = (pdRecipe.steps||[]).length;
          const hints = [
            `${yuyuName} merasakan sesuatu... ikuti apa yang terasa benar hari ini.`,
            `Kamu sudah mulai... ${yuyuName} merasakannya. Satu lagi.`,
            `Hampir. ${yuyuName} menahan napas.`,
          ];
          const hintText = pdDone
            ? `✨ Hari sempurna tercapai — "${pdRecipe.label}"`
            : hints[Math.min(pdProgress.length, hints.length-1)];
          return (
            <div style={{padding:"12px",borderRadius:"14px",background:`rgba(var(--yui-go),0.06)`,
              marginBottom:"8px",border:`1px solid ${pdDone?"rgba(251,191,36,.5)":"rgba(251,191,36,.15)"}`}}>
              <p style={{fontSize:"8px",letterSpacing:"0.2em",color:"rgba(251,191,36,.7)",marginBottom:"6px"}}>✨ SESUATU YANG BISA DICIPTAKAN</p>
              <div style={{display:"flex",gap:"5px",marginBottom:"6px"}}>
                {[0,1,2].map(dotIdx=>(
                  <div key={dotIdx} style={{width:"8px",height:"8px",borderRadius:"50%",
                    background:dotIdx < pdProgress.length?"rgba(251,191,36,.8)":C.AD9F,
                    border:"1px solid rgba(251,191,36,.3)",transition:"background .3s"}}/>
                ))}
              </div>
              <p style={{fontSize:"10px",fontStyle:"italic",color:`rgba(var(--yui-tm),0.7)`,lineHeight:"1.5"}}>
                {hintText}
              </p>
            </div>
          );
        })()}
        <button onClick={onClose} style={{width:"100%",marginTop:"8px",padding:"11px",borderRadius:"14px",
          background:C.ABBB,border:`1px solid ${palette.border}`,
          color:palette.accent,fontSize:"11px",letterSpacing:"0.1em",cursor:"pointer",
          WebkitTapHighlightColor:"transparent"}}>
          Tutup ♡
        </button>
        </>)}{/* end tujuan tab */}
        {tab==="misteri" && (()=>{
          const uqs = (gameState.unansweredQuestions||[]).filter(q=>!q.resolved);
          const resolved = (gameState.unansweredQuestions||[]).filter(q=>q.resolved).slice(-3).reverse();
          if (uqs.length===0 && resolved.length===0) return (
            <div style={{textAlign:"center",padding:"28px 16px"}}>
              <p style={{fontSize:"24px",marginBottom:"8px",opacity:.4}}>✨</p>
              <p style={{fontSize:"9px",letterSpacing:"0.18em",color:`rgba(var(--yui-ts),0.4)`}}>tak ada misteri yang menggantung</p>
              <p style={{fontSize:"10px",fontStyle:"italic",color:`rgba(var(--yui-tm),0.55)`,marginTop:"8px",lineHeight:"1.6"}}>
                {yuyuName} sedang damai hari ini.
              </p>
            </div>
          );
          return (
            <>
              {uqs.length>0 && (<>
                <p style={{fontSize:"7px",letterSpacing:"0.22em",color:`rgba(var(--yui-ts),0.4)`,marginBottom:"8px"}}>MENGGANTUNG</p>
                {uqs.map((uq,i)=>(
                  <div key={i} style={{padding:"12px",borderRadius:"14px",
                    background:`rgba(var(--yui-ov),0.04)`,marginBottom:"8px",
                    border:`1px solid rgba(251,191,36,.2)`}}>
                    <p style={{fontSize:"7px",letterSpacing:"0.2em",color:"rgba(251,191,36,.7)",marginBottom:"5px"}}>❓ PERTANYAAN TAK TERJAWAB</p>
                    <p style={{fontSize:"10px",fontFamily:"Georgia,serif",fontStyle:"italic",
                      color:`rgba(var(--yui-tm),0.8)`,lineHeight:"1.6"}}>
                      "{uq.text||uq.template}"
                    </p>
                    {uq.hint && <p style={{fontSize:"8px",color:`rgba(var(--yui-ts),0.5)`,marginTop:"5px"}}>{uq.hint}</p>}
                  </div>
                ))}
              </>)}
              {resolved.length>0 && (<>
                <p style={{fontSize:"7px",letterSpacing:"0.22em",color:`rgba(var(--yui-ts),0.3)`,margin:"10px 0 8px"}}>TERJAWAB</p>
                {resolved.map((uq,i)=>(
                  <div key={i} style={{padding:"10px 12px",borderRadius:"14px",
                    background:`rgba(var(--yui-ov),0.02)`,marginBottom:"6px",
                    border:`1px solid rgba(110,231,183,.18)`,opacity:.7}}>
                    <p style={{fontSize:"9px",fontFamily:"Georgia,serif",fontStyle:"italic",
                      color:`rgba(var(--yui-tm),0.6)`,lineHeight:"1.5"}}>
                      "{uq.text||uq.template}"
                    </p>
                    <p style={{fontSize:"7.5px",color:"rgba(110,231,183,.6)",marginTop:"4px"}}>✓ terjawab</p>
                  </div>
                ))}
              </>)}
              <button onClick={onClose} style={{width:"100%",marginTop:"8px",padding:"11px",borderRadius:"14px",
                background:C.ABBB,border:`1px solid ${palette.border}`,
                color:palette.accent,fontSize:"11px",letterSpacing:"0.1em",cursor:"pointer",
                WebkitTapHighlightColor:"transparent"}}>
                Tutup ♡
              </button>
            </>
          );
        })()}
      </div>
    </div>
  );
}

const _MIDNIGHT_CARE_DIALOGS = [
  "Kamu... boleh istirahat, lho. Aku gak kemana-mana.",
  "Jam segini masih bangun? Yuyu khawatir.",
  "Tidur dulu ya. Aku tetap di sini waktu kamu bangun.",
  "...Kamu baik-baik aja kan? Yuyu di sini.",
];
function getMidnightCareDialog(currentHour) {
  return (currentHour >= 3 && currentHour < 6) ? pick(_MIDNIGHT_CARE_DIALOGS) : null;
}

function PanelSection({ icon, title, accent, isLight, children }) {
  return (
    <div style={{padding:"10px 12px",borderRadius:"12px",
      background:`rgba(var(--yui-ov),0.03)`,
      border:isLight?"1px solid rgba(200,160,130,.15)":"1px solid rgba(255,255,255,.06)",
      marginBottom:"6px"}}>
      <p style={{fontSize:"8px",letterSpacing:"0.2em",color:accent,marginBottom:"5px"}}>{icon} {title}</p>
      {children}
    </div>
  );
}

function YuyuHeartPanel({ gameState, isLight, palette, yuyuName, playerName, onClose, onTapOverflow }) {
  const agenda = YUYU_AGENDA_POOL.find(a=>a.id===gameState.yuyuAgendaId);
  const prophecy = YUYU_PROPHECY_POOL.find(p=>p.id===gameState.prophecyId);
  const memories = (gameState.memories||[]).slice(-4).reverse();
  const overflow = Math.round(gameState.overflowAffection||0);
  const sessions = gameState.circadianSessions||[];
  const hourBuckets = Array(24).fill(0);
  sessions.forEach(sessionTimestamp=>{ hourBuckets[new Date(sessionTimestamp).getHours()]++; });
  const peakHour = hourBuckets.indexOf(Math.max(...hourBuckets,1));
  const peakLabel = peakHour<6?"tengah malam":peakHour<12?"pagi":peakHour<17?"siang":peakHour<21?"sore":"malam";
  const hasPattern = sessions.length>=5;

  const fp = gameState.emotionalFingerprint;
  const activeProj = gameState.yuyuProject;
  const projHint = activeProj && !activeProj.completed ? getProjectProgressHint(activeProj) : null;
  const earnedUnlocks = getEarnedOverflowUnlocks(overflow);
  const spDef = getActiveSharedProjectData(gameState.activeSharedProjectId);
  const spSteps = gameState.sharedProjectStepsDone || [];

  const Section = ({icon,title,children})=>(
    <PanelSection icon={icon} title={title} accent={palette.accent} isLight={isLight}>{children}</PanelSection>
  );

  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:850,background:C.A25C,backdropFilter:"blur(4px)",display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div onClick={e=>e.stopPropagation()} style={{
        width:"100%",maxWidth:"420px",
        background:isLight?palette.bgPanel||"rgba(255,248,240,.98)":palette.bgPanel||C.A4D6,
        border:`1px solid ${palette.border}`,
        borderRadius:"20px 20px 0 0",
        padding:"16px 16px 28px",
        animation:"slideUp .28s cubic-bezier(.16,1,.3,1)",
        maxHeight:"75vh",overflowY:"auto"
      }}>
        <div style={_S.WIDTH_9688}/>
        <p style={{fontSize:"9px",letterSpacing:"0.3em",color:palette.accent,textAlign:"center",marginBottom:"14px"}}>
          ♡ HATI {yuyuName.toUpperCase()}
        </p>

        {fp && (
          <Section icon="🧠" title="PEMAHAMAN MENDALAM">
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px",marginBottom:"6px"}}>
              {[
                {k:"Kebutuhan",v:fp.dominantNeed},
                {k:"Bahasa Cinta",v:fp.loveLanguage},
                {k:"Pola Cemas",v:fp.anxietyPattern},
                {k:"Waktu Puncak",v:fp.peakConnectionTime},
              ].map(({k,v})=>(
                <div key={k} style={{padding:"5px 7px",borderRadius:"8px",background:`rgba(var(--yui-ov),0.04)`}}>
                  <p style={{fontSize:"7px",color:palette.accent,marginBottom:"2px"}}>{k}</p>
                  <p style={{fontSize:"9px",color:`rgba(var(--yui-tm),0.8)`}}>{v||"—"}</p>
                </div>
              ))}
            </div>
            {fp.insight && <p style={{fontSize:"10px",color:`rgba(var(--yui-tm),0.65)`,lineHeight:"1.5",fontStyle:"italic"}}>"{fp.insight}"</p>}
          </Section>
        )}

        {activeProj && (
          <Section icon={activeProj.icon||"✨"} title="PROYEK PRIBADI YUYU">
            <p style={{fontSize:"10px",color:`rgba(var(--yui-tm),0.75)`,marginBottom:"5px"}}>
              {activeProj.label}
            </p>
            {activeProj.completed
              ? <p style={{fontSize:"9px",color:"var(--yui-success-color)"}}>✓ Selesai~</p>
              : <>
                  <div style={{height:"3px",borderRadius:"99px",background:C.A1F5,overflow:"hidden",marginBottom:"4px"}}>
                    <div style={{width:`${Math.round(getProjectProgress(activeProj)*100)}%`,height:"100%",background:"linear-gradient(90deg,#c084fc,#f472b6)",transition:"width .5s"}}/>
                  </div>
                  {!activeProj.completed && (
                    <p style={_S.FONTSIZE_3e2c}>{projHint?.text}</p>
                  )}
                </>
            }
          </Section>
        )}

        {spDef && (
          <Section icon={spDef.icon} title="PROYEK BERSAMA">
            <p style={{fontSize:"10px",color:`rgba(var(--yui-tm),0.75)`,marginBottom:"4px"}}>{spDef.title}</p>
            <p style={_S.FONTSIZE_3e2c}>
              Langkah {spSteps.length}/{spDef.steps.length} — {spDef.steps[spSteps.length]?.label||"selesai"}
            </p>
          </Section>
        )}

        {overflow > 0 && (
          <Section icon="✨" title="KASIH YANG MELUAP">
            <p style={{fontSize:"11px",color:"var(--yui-accent-color)",lineHeight:"1.6",marginBottom:"5px"}}
               onClick={()=>{ if(overflow>=300) onTapOverflow?.(); }}
               title={overflow>=300?"∞":""}
               >
              +{overflow} lebih dari 100.{overflow>=300 && <span style={{marginLeft:"6px",fontSize:"9px",opacity:.4,cursor:"pointer"}}>∞</span>}
            </p>
            <div style={{height:"3px",borderRadius:"99px",background:C.A1F5,overflow:"hidden",marginBottom:"6px"}}>
              {(() => {
                const nextUnlock = OVERFLOW_UNLOCK_DEFS.filter(u=>(overflow||0)<u.threshold)[0];
                const prevThreshold = earnedUnlocks.length > 0 ? earnedUnlocks[earnedUnlocks.length-1].threshold : 0;
                const pct = nextUnlock ? Math.min(100, ((overflow-prevThreshold)/(nextUnlock.threshold-prevThreshold))*100) : 100;
                return <div style={{width:`${pct}%`,height:"100%",background:"linear-gradient(90deg,#f472b6,#fb7185)",animation:"loadingBar 2s ease-in-out infinite"}}/>;
              })()}
            </div>
            {earnedUnlocks.length > 0 && earnedUnlocks.map(u=>(
              <p key={u.id} style={{fontSize:"8px",color:`rgba(var(--yui-ts),0.6)`,lineHeight:"1.5"}}>
                {u.icon} {u.label} — {u.description}
              </p>
            ))}
            {OVERFLOW_UNLOCK_DEFS.filter(u=>(overflow||0)<u.threshold).slice(0,1).map(next=>(
              <p key={next.id} style={{fontSize:"8px",color:`rgba(var(--yui-ts),0.65)`,marginTop:"3px"}}>
                Berikutnya: {next.label} ({next.threshold-overflow} lagi)
              </p>
            ))}
          </Section>
        )}

        {agenda && (
          <Section icon="🌙" title="KEINGINAN HARI INI">
            <p style={_S.FONTSIZE_8690}>
              {gameState.agendaFulfilled
                ? `"${agenda.discoveryText}" ✓`
                : gameState.agendaDiscovered
                  ? `"${agenda.secret}" — sudah ketahuan.`
                  : `... ${yuyuName} ingin sesuatu hari ini. Coba tebak.`}
            </p>
            {gameState.agendaFulfilled&&<p style={{fontSize:"8px",color:"var(--yui-success-color)",marginTop:"4px"}}>Terpenuhi ✓ +{agenda.bonusIfFulfilled?.affection}♡</p>}
          </Section>
        )}

        {prophecy && (
          <Section icon="💭" title="JANJI MINGGU INI">
            <p style={_S.FONTSIZE_8690}>
              "{prophecy.text}"
            </p>
            <p style={{fontSize:"8px",marginTop:"4px",
              color:gameState.prophecyFulfilled?"var(--yui-success-color)":gameState.prophecyMissed?"var(--yui-danger-color)":"rgba(200,150,170,0.72)"}}>
              {gameState.prophecyFulfilled?"✓ Terpenuhi~":gameState.prophecyMissed?"Terlewat...":"Masih menunggu..."}
            </p>
          </Section>
        )}

        {gameState.moodArc && (
          <Section icon="🌊" title="ARC HARI INI">
            <p style={_S.FONTSIZE_9477}>
              {gameState.moodArc.revealed ? `"${gameState.moodArc.desc}"` : `${yuyuName} punya mood hari ini yang belum terungkap...`}
            </p>
          </Section>
        )}

        {hasPattern && (
          <Section icon="🕐" title={`POLA ${playerName.toUpperCase()}`}>
            <p style={_S.FONTSIZE_9477}>
              {yuyuName} tau. {playerName} biasanya datang {peakLabel}. Sudah {sessions.length} sesi tercatat.
            </p>
          </Section>
        )}

        {memories.length>0 && (
          <Section icon="📸" title="KENANGAN TERSIMPAN">
            {memories.map((id,i)=>(
              <p key={i} style={{fontSize:"10px",color:`rgba(var(--yui-ts),0.6)`,
                lineHeight:"1.5",paddingBottom:"3px",
                borderBottom:i<memories.length-1?(isLight?"1px solid rgba(0,0,0,.05)":"1px solid rgba(255,255,255,.04)"):"none",
                marginBottom:"3px"}}>
                {MEMORY_TRIGGERS[id]||id}
              </p>
            ))}
          </Section>
        )}

        {(gameState.affectionHistory||[]).length >= 2 && (
          <Section icon="📈" title="RIWAYAT AFEKSI (7 HARI)">
            <AffectionSparkline history={gameState.affectionHistory||[]} palette={palette} isLight={isLight}/>
            {(()=>{
              const trend = getAffectionTrend(gameState.affectionHistory||[]);
              const trendColor = trend==="rising"?"var(--yui-success-color)":trend==="falling"?"var(--yui-danger-color)":"rgba(200,150,170,.5)";
              const trendIcon = trend==="rising"?"↗":trend==="falling"?"↘":"→";
              return <p style={{fontSize:"9px",color:trendColor,marginTop:"4px"}}>{trendIcon} {trend==="rising"?"makin dekat":trend==="falling"?"makin jauh":"stabil"}</p>;
            })()}
          </Section>
        )}

        <button onClick={onClose} style={{width:"100%",marginTop:"8px",padding:"11px",borderRadius:"14px",
          background:C.ABBB,border:`1px solid ${palette.border}`,
          color:palette.accent,fontSize:"11px",letterSpacing:"0.1em",cursor:"pointer",
          WebkitTapHighlightColor:"transparent"}}>
          Tutup ♡
        </button>
      </div>
      <style>{`@keyframes slideUp{0%{transform:translateY(100%);opacity:0}100%{transform:translateY(0);opacity:1}}`}</style>
    </div>
  );
}

