const NOTIF_PRIORITY_MAP = {
  perfectday:5, bad:4, achievement:4, streak:3, peak:3, breakthrough:3, kita:3,
  wish:3, arc:2, quest:2, project:2, prophecy:2, ritual:2, health:2, emotion:2,
  reward:2, thread:2, weather:2, distance:2,
  money:1, spend:1, system:1, info:0, offline:2,
};

function useUnifiedNotifQueue() {
  const [queue, setQueue] = useState([]);
  const [stack, setStack] = useState([]);
  const [log, setLog] = useState([]);
  const timerRefs = useRef({});
  // Batch buffer: collect notifs fired within 80ms of each other, then dedup+prioritize
  const batchBufRef = useRef([]);
  const batchTimerRef = useRef(null);

  const dismiss = useCallback((id) => {
    clearTimeout(timerRefs.current[id]);
    delete timerRefs.current[id];
    setStack(prev => prev.filter(n => n.id !== id));
  }, []);

  const flushBatch = useCallback(() => {
    const batch = batchBufRef.current;
    batchBufRef.current = [];
    if (!batch.length) return;
    // Sort by priority desc, then deduplicate by type (keep highest per type)
    const seen = new Set();
    const deduped = batch
      .sort((a,b) => b.priority - a.priority)
      .filter(e => {
        // Always show unique messages; dedupe same type+msg combos
        const key = `${e.type}:${e.msg.slice(0,30)}`;
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .slice(0, 3); // Max 3 from a single action burst
    // First fires immediately, rest get staggered delays
    deduped.forEach((entry, i) => {
      const delay = i === 0 ? 0 : i * 900;
      setTimeout(() => {
        setLog(prev => [entry, ...prev].slice(0, 60));
        setQueue(prev => [...prev, entry].sort((a,b) => b.priority - a.priority));
      }, delay);
    });
  }, []);

  const push = useCallback((msg, type="info", extra={}) => {
    const id = `notif_${Date.now()}_${Math.random().toString(36).slice(2)}`;
    const def = NOTIF_TYPES[type] || NOTIF_TYPES.info;
    const entry = { id, msg, type, extra, priority: NOTIF_PRIORITY_MAP[type]??0, def, ts: Date.now() };
    batchBufRef.current.push(entry);
    clearTimeout(batchTimerRef.current);
    batchTimerRef.current = setTimeout(flushBatch, 80);
  }, [flushBatch]);

  useEffect(() => {
    if (queue.length > 0 && stack.length < 3) {
      const [next, ...rest] = queue;
      const dur = next.extra?.rich ? (next.extra.duration || 6000) : (next.def.duration || 3000);
      setQueue(rest);
      setStack(prev => [{ ...next, enteredAt: Date.now(), totalDur: dur }, ...prev].slice(0, 3));
      timerRefs.current[next.id] = setTimeout(() => dismiss(next.id), dur);
    }
  }, [queue, stack, dismiss]);

  return { stack, push, dismiss, log };
}

// ── Komponen notifikasi modern — semua dalam satu ──
function UnifiedNotifLayer({ stack, dismiss, isLight }) {
  if (!stack || stack.length === 0) return null;
  const ITALIC_TYPES = ["emotion","peak","thread","kita","ritual","breakthrough","prophecy","catchup","project","arc","wish"];
  const SERIF_TYPES  = ["emotion","peak","thread","kita","ritual","breakthrough","prophecy","catchup","project","arc"];
  return (
    <div style={{
      position:"fixed", bottom:"340px", left:"50%", transform:"translateX(-50%)",
      zIndex:990, width:"calc(100% - 22px)", maxWidth:"360px",
      pointerEvents:"none", height:0,
    }}>
      {[...stack].reverse().map((notif, ridx) => {
        const idx    = stack.length - 1 - ridx;   // 0 = front (topmost)
        const def    = notif.def || NOTIF_TYPES.info;
        const isRich = notif.extra?.rich;
        const isFront = idx === 0;
        const scale   = 1 - idx * 0.055;
        const moveY   = -(idx * 9);
        const opacity = 1 - idx * 0.26;

        // Progress bar via CSS animation (negative delay = start mid-animation)
        const totalDur  = notif.totalDur || def.duration || 3000;
        const elapsed   = Date.now() - (notif.enteredAt || Date.now());
        const animDelay = `-${Math.min(elapsed, totalDur)}ms`;

        const accentRaw = def.accent || "rgba(180,160,210,.6)";
        // Derive solid accent from rgba string for the bar fill
        const accentSolid = accentRaw.replace(/,[\d.]+\)$/, ",1)");

        return (
          <div key={notif.id}
            onClick={isFront ? () => dismiss(notif.id) : undefined}
            style={{
              position:"absolute", bottom:0, left:0, right:0,
              borderRadius:"18px",
              background: isLight
                ? "rgba(255,253,251,.97)"
                : def.bg,
              border:`1px solid ${isLight ? "rgba(200,160,140,.18)" : accentRaw.replace(/,[\d.]+\)$/, ",.28)")}`,
              backdropFilter:"blur(30px)", WebkitBackdropFilter:"blur(30px)",
              boxShadow: isFront
                ? `0 6px 28px rgba(0,0,0,.32), inset 0 1px 0 rgba(255,255,255,.06)`
                : `0 2px 10px rgba(0,0,0,.15)`,
              pointerEvents: isFront ? "auto" : "none",
              cursor: isFront ? "pointer" : "default",
              transform: `translateY(${moveY}px) scale(${scale})`,
              transformOrigin: "bottom center",
              opacity,
              transition: isFront ? "none" : "transform .3s cubic-bezier(.16,1,.3,1), opacity .3s ease",
              animation: isFront ? "nf_in .38s cubic-bezier(.16,1,.3,1)" : "none",
              zIndex: 10 - idx,
              overflow:"hidden",
              display:"flex", flexDirection:"column",
            }}>

            {/* Left accent bar */}
            <div style={{
              position:"absolute", left:0, top:0, bottom:0, width:"3px",
              background:`linear-gradient(180deg, ${accentSolid} 0%, ${accentRaw} 100%)`,
              borderRadius:"18px 0 0 18px",
              opacity: isFront ? 0.8 : 0.35,
            }}/>

            {/* Content */}
            <div style={{padding: isRich ? "11px 13px 10px 17px" : "9px 12px 9px 17px"}}>
              {/* Label row */}
              {(def.label || isFront) && (
                <div style={{
                  display:"flex", alignItems:"center", justifyContent:"space-between",
                  marginBottom: isRich ? "7px" : "3px",
                }}>
                  {def.label && (
                    <span style={{
                      fontSize:"7px", letterSpacing:"0.26em", fontWeight:600,
                      color: isLight ? "rgba(80,30,50,.5)" : def.color,
                      opacity:.82, lineHeight:1,
                    }}>{def.label}</span>
                  )}
                  {isFront && (
                    <span style={{
                      fontSize:"8px", lineHeight:1,
                      color: isLight ? "rgba(100,60,80,.3)" : "rgba(255,255,255,.18)",
                      marginLeft:"auto",
                    }}>✕</span>
                  )}
                </div>
              )}

              {/* Rich layout (perfectday, dll) */}
              {isRich ? (
                <div style={{display:"flex", gap:"10px", alignItems:"flex-start"}}>
                  {notif.extra?.icon && (
                    <div style={{
                      width:"36px", height:"36px", borderRadius:"11px", flexShrink:0,
                      background: accentRaw.replace(/,[\d.]+\)$/, ",.12)"),
                      border:`1px solid ${accentRaw.replace(/,[\d.]+\)$/, ",.3)")}`,
                      display:"flex", alignItems:"center", justifyContent:"center",
                      fontSize:"19px",
                    }}>{notif.extra.icon}</div>
                  )}
                  <div style={{flex:1, minWidth:0}}>
                    {notif.extra?.title && (
                      <p style={{
                        fontSize:"8.5px", fontWeight:600, letterSpacing:"0.09em",
                        color: isLight ? "rgba(60,20,40,.88)" : def.color,
                        marginBottom:"4px", lineHeight:1.2,
                      }}>{notif.extra.title}</p>
                    )}
                    <p style={{
                      fontSize:"11px", fontFamily:"Georgia,serif", fontStyle:"italic",
                      color: isLight ? "rgba(30,10,20,.84)" : "rgba(253,232,236,.9)",
                      lineHeight:"1.65",
                    }}>{notif.extra?.text || notif.msg}</p>
                    {notif.extra?.sub && (
                      <p style={{
                        fontSize:"8px", marginTop:"3px",
                        color:"rgba(var(--yui-ts),0.52)",
                      }}>{notif.extra.sub}</p>
                    )}
                  </div>
                </div>
              ) : (
                /* Simple layout */
                <>
                  <p style={{
                    fontSize: ["emotion","peak","kita","arc"].includes(notif.type) ? "11px" : "10.5px",
                    fontFamily: SERIF_TYPES.includes(notif.type) ? "Georgia,serif" : "inherit",
                    fontStyle: ITALIC_TYPES.includes(notif.type) ? "italic" : "normal",
                    color: isLight ? "rgba(40,10,20,.82)" : (def.color || "rgba(230,200,215,.85)"),
                    lineHeight:"1.52",
                  }}>{notif.msg}</p>
                  {notif.extra?.sub && (
                    <p style={{fontSize:"8.5px", color:"rgba(var(--yui-ts),0.65)", marginTop:"2px"}}>
                      {notif.extra.sub}
                    </p>
                  )}
                </>
              )}
            </div>

            {/* Progress bar — CSS animation, hanya di card terdepan */}
            {isFront && (
              <div style={{height:"2px", background:"rgba(255,255,255,.04)", flexShrink:0}}>
                <div style={{
                  height:"100%",
                  background:`linear-gradient(90deg, ${accentSolid}, ${accentRaw})`,
                  opacity:.55,
                  transformOrigin:"left center",
                  animation:`nf_bar ${totalDur}ms linear forwards`,
                  animationDelay: animDelay,
                  borderRadius:"0 0 0 18px",
                }}/>
              </div>
            )}
          </div>
        );
      })}
      <style>{`
        @keyframes nf_in {
          0%   { opacity:0; transform:translateY(24px) scale(0.88); }
          58%  { transform:translateY(-3px) scale(1.015); }
          100% { opacity:1; transform:translateY(0) scale(1); }
        }
        @keyframes nf_bar {
          from { transform:scaleX(1); }
          to   { transform:scaleX(0); }
        }
      `}</style>
    </div>
  );
}
UnifiedNotifLayer = React.memo(UnifiedNotifLayer);

function useTypewriter(text, speed=18, mood="biasa") {
  const [displayed,setDisplayed]=useState("");
  const [done,setDone]=useState(false);
  const timerRef=useRef(null);
  const idxRef=useRef(0);
  useEffect(()=>{
    idxRef.current=0; setDisplayed(""); setDone(false);
    if(!text){setDone(true);return;}
    const mult={excited:.55,playful:.65,senang:.82,malu:1.35,romantis:1.20,sedih:1.85,rindu:1.70,kangen:1.60,mengantuk:2.00}[mood]??1.0;
    const delay=(c,nc)=>{const b=speed*mult;if(!c)return b;if(c==="…")return b*4.5;if(c==="."&&nc&&nc!==".")return b*2.9;if(c==="."||c==="!"||c==="?")return b*2.6;if(c===",")return b*1.6;if(c==="—")return b*2.3;if(c==="\n")return b*2.1;return b;};
    const tick=()=>{idxRef.current++;const idx=idxRef.current;setDisplayed(text.slice(0,idx));if(idx>=text.length){setDone(true);return;}timerRef.current=setTimeout(tick,delay(text[idx-1],text[idx]));};
    timerRef.current=setTimeout(tick,Math.max(6,speed*0.35));
    return ()=>clearTimeout(timerRef.current);
  },[text,speed,mood]);
  const skip=useCallback(()=>{if(done)return false;clearTimeout(timerRef.current);setDisplayed(text);setDone(true);idxRef.current=text?.length||0;return true;},[text,done]);
  return {displayed,done,skip};
}

function useNotifQueue() {
  const {stack,push:unifiedPush,dismiss,log} = useUnifiedNotifQueue();
  const notification = stack.length > 0 ? stack[stack.length-1] : null;
  const push = useCallback((msg,type="info",extra={}) => {
    unifiedPush(msg, type, extra);
  },[unifiedPush]);
  return {notification, push, dismiss, stack, unifiedPush, log};
}

let floatingIdCounter=0;
function useFloats() {
  const [floats,setFloats]=useState([]);
  const addFloat=useCallback((label,color,x,y)=>{ const floatingId=++floatingIdCounter; setFloats(existingFloats=>[...existingFloats,{id:floatingId,label,color,x,y}]); setTimeout(()=>setFloats(existingFloats=>existingFloats.filter(floatItem=>floatItem.id!==floatingId)),1500); },[]);
  return {floats,addFloat};
}

