// ─────────────────────────────────────────────────────────────
// PROCEDURAL ANIMATION ENGINE — no training data needed
// Spring physics + sum-of-sines noise → organic autonomous motion
// ─────────────────────────────────────────────────────────────

// Critically-damped spring stepper (dt in seconds)
function _springStep(pos, vel, target, stiffness, damping, dt) {
  const f = -stiffness * (pos - target) - damping * vel;
  const newVel = vel + f * dt;
  const newPos = pos + newVel * dt;
  return [newPos, newVel];
}

// Cheap organic noise: sum of offset sines at different frequencies
function _noiseVal(t, freq1, freq2, freq3, seed) {
  const s = seed || 0;
  return ( Math.sin(t * freq1 + s * 1.3)
         + Math.sin(t * freq2 + s * 2.7) * 0.5
         + Math.sin(t * freq3 + s * 4.1) * 0.25 ) / 1.75;
}

// Target poses per mood: { headTilt, bodyLean, lArmAngle, rArmAngle, lArmLift, rArmLift, headNod, eyeScale }
// headTilt/bodyLean: radians. lArmAngle/rArmAngle: swing fwd/back. lArmLift/rArmLift: lateral raise.
const _MOOD_POSES = {
  biasa:      { headTilt:0,      bodyLean:0,      lArmAngle:0,     rArmAngle:0,     lArmLift:0,     rArmLift:0,     headNod:0,    eyeScale:1    },
  senang:     { headTilt:0.05,   bodyLean:0.03,   lArmAngle:0.18,  rArmAngle:-0.18, lArmLift:0.25,  rArmLift:0.25,  headNod:0.04, eyeScale:1.05 },
  excited:    { headTilt:-0.06,  bodyLean:-0.04,  lArmAngle:0.35,  rArmAngle:-0.35, lArmLift:0.55,  rArmLift:0.55,  headNod:0.08, eyeScale:1.08 },
  sedih:      { headTilt:0.12,   bodyLean:0.06,   lArmAngle:-0.08, rArmAngle:0.08,  lArmLift:-0.05, rArmLift:-0.05, headNod:-0.05,eyeScale:0.88 },
  kangen:     { headTilt:0.08,   bodyLean:0.04,   lArmAngle:-0.05, rArmAngle:0.05,  lArmLift:0.1,   rArmLift:0.05,  headNod:-0.03,eyeScale:0.92 },
  rindu:      { headTilt:0.1,    bodyLean:0.05,   lArmAngle:-0.06, rArmAngle:0.06,  lArmLift:0.08,  rArmLift:0.04,  headNod:-0.04,eyeScale:0.9  },
  romantis:   { headTilt:-0.04,  bodyLean:-0.02,  lArmAngle:0.1,   rArmAngle:-0.08, lArmLift:0.12,  rArmLift:0.1,   headNod:0.02, eyeScale:1.02 },
  malu:       { headTilt:0.18,   bodyLean:0.08,   lArmAngle:-0.12, rArmAngle:0.04,  lArmLift:-0.1,  rArmLift:0.06,  headNod:-0.06,eyeScale:0.85 },
  marah:      { headTilt:-0.08,  bodyLean:-0.05,  lArmAngle:0.22,  rArmAngle:-0.22, lArmLift:0.1,   rArmLift:0.1,   headNod:0.05, eyeScale:1.1  },
  playful:    { headTilt:-0.1,   bodyLean:-0.06,  lArmAngle:0.28,  rArmAngle:-0.1,  lArmLift:0.3,   rArmLift:0.1,   headNod:0.06, eyeScale:1.04 },
  mengantuk:  { headTilt:0.2,    bodyLean:0.12,   lArmAngle:-0.04, rArmAngle:0.04,  lArmLift:-0.15, rArmLift:-0.1,  headNod:-0.1, eyeScale:0.6  },
  lapar:      { headTilt:0.06,   bodyLean:0.03,   lArmAngle:0.05,  rArmAngle:-0.16, lArmLift:0.08,  rArmLift:0.35,  headNod:0.03, eyeScale:0.95 },
};

// One-shot gesture overlays — applied on top of base pose for duration ms
const _GESTURES = {
  nod:        { headNod:0.14,   headTilt:0,      bodyLean:0,      duration:600  },
  wave:       { rArmAngle:-0.6, rArmLift:0.7,    bodyLean:-0.04,  duration:900  },
  hug_self:   { lArmAngle:-0.2, rArmAngle:0.2,   lArmLift:0.4,    rArmLift:0.4, bodyLean:0.05, duration:1200 },
  look_aside: { headTilt:-0.22, bodyLean:-0.03,  duration:800  },
  shrug:      { lArmLift:0.45,  rArmLift:0.45,   headTilt:0.06,   duration:900  },
  bounce:     { headNod:0.18,   bodyLean:0.05,   lArmLift:0.2,    rArmLift:0.2,  duration:500  },
  reach:      { rArmAngle:-0.4, rArmLift:0.5,    bodyLean:-0.06,  duration:700  },
};

// Idle noise amplitudes per mood
const _IDLE_AMP = {
  biasa:0.5, senang:0.7, excited:1.2, sedih:0.2, kangen:0.3, rindu:0.3,
  romantis:0.55, malu:0.25, marah:0.85, playful:1.0, mengantuk:0.15, lapar:0.6,
};

function useYuyuMotion(mood="biasa", affection=50, idleSeconds=0, gestureSignal=null) {
  // Joint state: each is [pos, vel]
  const joints = useRef({
    headTilt:  [0,0], bodyLean:  [0,0],
    lArmAngle: [0,0], rArmAngle: [0,0],
    lArmLift:  [0,0], rArmLift:  [0,0],
    headNod:   [0,0], eyeScale:  [1,0],
    breathY:   [0,0],
  });
  const rafRef     = useRef(null);
  const tRef       = useRef(0);
  const gestureRef = useRef(null); // { overlay, expiresAt }
  const [frame, setFrame] = useState(0); // force re-render

  // When gestureSignal changes, start a one-shot gesture
  useEffect(()=>{
    if (!gestureSignal) return;
    const g = _GESTURES[gestureSignal];
    if (!g) return;
    gestureRef.current = { overlay: g, expiresAt: Date.now() + g.duration };
  }, [gestureSignal]);

  useEffect(()=>{
    let last = performance.now();
    const tick = (now) => {
      const dt = Math.min((now - last) / 1000, 0.05);
      last = now;
      tRef.current += dt;
      const t = tRef.current;
      const j = joints.current;

      const basePose = _MOOD_POSES[mood] || _MOOD_POSES.biasa;
      const amp  = (_IDLE_AMP[mood] ?? 0.5) * (1 + Math.min(idleSeconds, 300) / 600);

      // Expire gesture
      if (gestureRef.current && Date.now() > gestureRef.current.expiresAt) {
        gestureRef.current = null;
      }
      const gest = gestureRef.current?.overlay || {};

      // Compute noise-based idle offsets (different seed per joint)
      const breathOff = _noiseVal(t, 0.18, 0.07, 0.03, 1) * 0.004;
      const idleOffsets = {
        headTilt:  _noiseVal(t, 0.13, 0.07, 0.04, 2) * 0.035 * amp,
        bodyLean:  _noiseVal(t, 0.09, 0.05, 0.03, 3) * 0.018 * amp,
        lArmAngle: _noiseVal(t, 0.11, 0.06, 0.04, 4) * 0.025 * amp,
        rArmAngle: _noiseVal(t, 0.10, 0.07, 0.03, 5) * 0.025 * amp,
        lArmLift:  _noiseVal(t, 0.08, 0.04, 0.02, 6) * 0.02  * amp,
        rArmLift:  _noiseVal(t, 0.09, 0.05, 0.03, 7) * 0.02  * amp,
        headNod:   _noiseVal(t, 0.07, 0.04, 0.02, 8) * 0.028 * amp,
        eyeScale:  0,
        breathY:   breathOff,
      };

      // Spring each joint toward (basePose + idleOffset + gesture overlay)
      const STIFF = 18, DAMP = 7;
      for (const k of Object.keys(j)) {
        const base = basePose[k] ?? (k==="eyeScale"?1:0);
        const target = base + (idleOffsets[k]||0) + (gest[k]||0);
        const [np, nv] = _springStep(j[k][0], j[k][1], target, STIFF, DAMP, dt);
        j[k] = [np, nv];
      }

      setFrame(f => f+1);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [mood, affection, idleSeconds]);

  const j = joints.current;
  return {
    headTilt:  j.headTilt[0],
    bodyLean:  j.bodyLean[0],
    lArmAngle: j.lArmAngle[0],
    rArmAngle: j.rArmAngle[0],
    lArmLift:  j.lArmLift[0],
    rArmLift:  j.rArmLift[0],
    headNod:   j.headNod[0],
    eyeScale:  j.eyeScale[0],
    breathY:   j.breathY[0],
  };
}

// Wrapper: adds autonomous motion to YuyuFigure, driven by game state
function YuyuFigureAnimated({ cx, cy, sz, bodyColor, hairColor, skirtColor, night, extra, outfit, mood, hideFeet,
  affection=50, idleSeconds=0, gestureSignal=null }) {
  const motion = useYuyuMotion(mood, affection, idleSeconds, gestureSignal);
  return (
    <YuyuFigure
      cx={cx} cy={cy} sz={sz} bodyColor={bodyColor} hairColor={hairColor}
      skirtColor={skirtColor} night={night} extra={extra} outfit={outfit}
      mood={mood} hideFeet={hideFeet} motion={motion}
    />
  );
}

function YuyuFigure({ cx=150, cy=320, sz=50, bodyColor="#ffd7e0", hairColor="#1a0814", skirtColor="#e91e8c", night=false, extra=null, outfit="dress", mood="biasa", hideFeet=false, motion=null }) {
  // Unpack motion joints (fall back to zero if not animated)
  const headTilt  = motion?.headTilt  || 0;
  const bodyLean  = motion?.bodyLean  || 0;
  const lArmAngle = motion?.lArmAngle || 0;
  const rArmAngle = motion?.rArmAngle || 0;
  const lArmLift  = motion?.lArmLift  || 0;
  const rArmLift  = motion?.rArmLift  || 0;
  const headNod   = motion?.headNod   || 0;
  const breathY   = motion?.breathY   || 0;

  // Apply body lean as a group transform pivot at bodyY
  const bodyY = cy;
  const headX = cx + headTilt * sz * 0.6; // lateral head shift from tilt
  const headY = cy - sz * 0.95 + headNod * sz * 0.4 + breathY * sz; // nod shifts headY

  // Arm endpoint computation from angle+lift
  const _armEnd = (side, angle, lift) => {
    const base = side === "l" ? cx - sz*0.3 : cx + sz*0.3;
    const dx = Math.sin(angle + lift * 0.5) * sz * 0.42;
    const dy = Math.cos(Math.abs(lift)) * sz * 0.38 - lift * sz * 0.32;
    return { x: base + (side==="l"?-dx:dx), y: bodyY + sz*0.12 + dy };
  };
  const lArm = _armEnd("l", lArmAngle, lArmLift);
  const rArm = _armEnd("r", rArmAngle, rArmLift);
  const lArmCx = cx - sz*0.3 + (lArm.x - (cx-sz*0.3))*0.45;
  const lArmCy = bodyY - sz*0.05 - lArmLift * sz * 0.18;
  const rArmCx = cx + sz*0.3 + (rArm.x - (cx+sz*0.3))*0.45;
  const rArmCy = bodyY - sz*0.05 - rArmLift * sz * 0.18;

  const shoeC = night?"#3a0d4a":"#880e4f";
  const moodEyes = (m) => {
    const eyeWidth=sz*0.07, eyeHeight=sz*0.09, leftEyeX=headX-sz*0.13, rightEyeX=headX+sz*0.13, eyeY=headY+sz*0.24;
    switch(m) {
      case "senang": case "excited":
        return (<>
          <path d={`M${leftEyeX-eyeWidth} ${eyeY} Q${leftEyeX} ${eyeY-eyeHeight*1.2} ${leftEyeX+eyeWidth} ${eyeY}`} stroke="#1a0814" strokeWidth={sz*0.025} fill="#1a0814"/>
          <path d={`M${rightEyeX-eyeWidth} ${eyeY} Q${rightEyeX} ${eyeY-eyeHeight*1.2} ${rightEyeX+eyeWidth} ${eyeY}`} stroke="#1a0814" strokeWidth={sz*0.025} fill="#1a0814"/>
        </>);
      case "mengantuk":
        return (<>
          <ellipse cx={leftEyeX} cy={eyeY+eyeHeight*0.1} rx={eyeWidth} ry={eyeHeight*0.45} fill="#1a0814"/>
          <ellipse cx={rightEyeX} cy={eyeY+eyeHeight*0.1} rx={eyeWidth} ry={eyeHeight*0.45} fill="#1a0814"/>
          <path d={`M${leftEyeX-eyeWidth*1.3} ${eyeY-eyeHeight*0.35} Q${leftEyeX} ${eyeY-eyeHeight*0.75} ${leftEyeX+eyeWidth*1.3} ${eyeY-eyeHeight*0.35}`} stroke="#1a0814" strokeWidth={sz*0.022} fill="none"/>
          <path d={`M${rightEyeX-eyeWidth*1.3} ${eyeY-eyeHeight*0.35} Q${rightEyeX} ${eyeY-eyeHeight*0.75} ${rightEyeX+eyeWidth*1.3} ${eyeY-eyeHeight*0.35}`} stroke="#1a0814" strokeWidth={sz*0.022} fill="none"/>
        </>);
      case "malu":
        return (<>
          <path d={`M${leftEyeX-eyeWidth} ${eyeY-eyeHeight*0.2} Q${leftEyeX} ${eyeY+eyeHeight*0.8} ${leftEyeX+eyeWidth} ${eyeY-eyeHeight*0.2}`} stroke="#1a0814" strokeWidth={sz*0.025} fill="rgba(26,8,20,.15)"/>
          <path d={`M${rightEyeX-eyeWidth} ${eyeY-eyeHeight*0.2} Q${rightEyeX} ${eyeY+eyeHeight*0.8} ${rightEyeX+eyeWidth} ${eyeY-eyeHeight*0.2}`} stroke="#1a0814" strokeWidth={sz*0.025} fill="rgba(26,8,20,.15)"/>
          <path d={`M${leftEyeX-eyeWidth*1.3} ${eyeY-eyeHeight*0.45} Q${leftEyeX} ${eyeY-eyeHeight*0.85} ${leftEyeX+eyeWidth*1.3} ${eyeY-eyeHeight*0.45}`} stroke="#1a0814" strokeWidth={sz*0.02} fill="none"/>
          <path d={`M${rightEyeX-eyeWidth*1.3} ${eyeY-eyeHeight*0.45} Q${rightEyeX} ${eyeY-eyeHeight*0.85} ${rightEyeX+eyeWidth*1.3} ${eyeY-eyeHeight*0.45}`} stroke="#1a0814" strokeWidth={sz*0.02} fill="none"/>
        </>);
      case "sakit":
        return (<>
          <path d={`M${leftEyeX-eyeWidth} ${eyeY-eyeHeight*0.3} L${leftEyeX+eyeWidth} ${eyeY+eyeHeight*0.3}`} stroke="#1a0814" strokeWidth={sz*0.03} strokeLinecap="round"/>
          <path d={`M${leftEyeX-eyeWidth} ${eyeY+eyeHeight*0.3} L${leftEyeX+eyeWidth} ${eyeY-eyeHeight*0.3}`} stroke="#1a0814" strokeWidth={sz*0.03} strokeLinecap="round"/>
          <path d={`M${rightEyeX-eyeWidth} ${eyeY-eyeHeight*0.3} L${rightEyeX+eyeWidth} ${eyeY+eyeHeight*0.3}`} stroke="#1a0814" strokeWidth={sz*0.03} strokeLinecap="round"/>
          <path d={`M${rightEyeX-eyeWidth} ${eyeY+eyeHeight*0.3} L${rightEyeX+eyeWidth} ${eyeY-eyeHeight*0.3}`} stroke="#1a0814" strokeWidth={sz*0.03} strokeLinecap="round"/>
        </>);
      case "rindu": case "kangen":
        return (<>
          <ellipse cx={leftEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight} fill="#1a0814"/>
          <ellipse cx={rightEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight} fill="#1a0814"/>
          <circle cx={leftEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.025} fill="white" opacity="0.9"/>
          <circle cx={rightEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.025} fill="white" opacity="0.9"/>
          <ellipse cx={leftEyeX+sz*0.01} cy={eyeY+eyeHeight*0.7} rx={sz*0.025} ry={sz*0.018} fill="rgba(100,160,255,.7)"/>
          <ellipse cx={rightEyeX+sz*0.01} cy={eyeY+eyeHeight*0.7} rx={sz*0.025} ry={sz*0.018} fill="rgba(100,160,255,.7)"/>
        </>);
      case "lapar":
        return (<>
          <ellipse cx={leftEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight*0.9} fill="#1a0814"/>
          <ellipse cx={rightEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight*0.9} fill="#1a0814"/>
          <circle cx={leftEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.022} fill="white" opacity="0.9"/>
          <circle cx={rightEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.022} fill="white" opacity="0.9"/>
          <path d={`M${leftEyeX-eyeWidth*1.2} ${eyeY-eyeHeight*0.5} Q${leftEyeX} ${eyeY-eyeHeight*1.1} ${leftEyeX+eyeWidth*1.2} ${eyeY-eyeHeight*0.5}`} stroke="#c2185b" strokeWidth={sz*0.018} fill="none"/>
          <path d={`M${rightEyeX-eyeWidth*1.2} ${eyeY-eyeHeight*0.5} Q${rightEyeX} ${eyeY-eyeHeight*1.1} ${rightEyeX+eyeWidth*1.2} ${eyeY-eyeHeight*0.5}`} stroke="#c2185b" strokeWidth={sz*0.018} fill="none"/>
        </>);
      case "playful":
        return (<>
          <path d={`M${leftEyeX-eyeWidth} ${eyeY} Q${leftEyeX} ${eyeY-eyeHeight*1.2} ${leftEyeX+eyeWidth} ${eyeY}`} fill="#1a0814"/>
          <ellipse cx={rightEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight} fill="#1a0814"/>
          <circle cx={rightEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.022} fill="white" opacity="0.9"/>
        </>);
      default:
        return (<>
          <ellipse cx={leftEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight} fill="#1a0814"/>
          <ellipse cx={rightEyeX} cy={eyeY} rx={eyeWidth} ry={eyeHeight} fill="#1a0814"/>
          <circle cx={leftEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.025} fill="white" opacity="0.9"/>
          <circle cx={rightEyeX-sz*0.02} cy={eyeY-sz*0.025} r={sz*0.025} fill="white" opacity="0.9"/>
        </>);
    }
  };
  const moodMouth = (m) => {
    const mouthX=headX, mouthY=headY+sz*0.47;
    switch(m) {
      case "senang": case "excited":
        return <path d={`M${mouthX-sz*0.13} ${mouthY-sz*0.01} Q${mouthX} ${mouthY+sz*0.1} ${mouthX+sz*0.13} ${mouthY-sz*0.01}`} stroke="#c2185b" strokeWidth={sz*0.045} fill="rgba(194,24,91,.12)" strokeLinecap="round"/>;
      case "lapar":
        return <path d={`M${mouthX-sz*0.1} ${mouthY} Q${mouthX} ${mouthY+sz*0.12} ${mouthX+sz*0.1} ${mouthY}`} stroke="#c2185b" strokeWidth={sz*0.04} fill="rgba(194,24,91,.1)" strokeLinecap="round"/>;
      case "sakit": case "kangen": case "rindu":
        return <path d={`M${mouthX-sz*0.1} ${mouthY+sz*0.04} Q${mouthX} ${mouthY-sz*0.04} ${mouthX+sz*0.1} ${mouthY+sz*0.04}`} stroke="#c2185b" strokeWidth={sz*0.035} fill="none" strokeLinecap="round"/>;
      case "mengantuk":
        return <ellipse cx={mouthX} cy={mouthY+sz*0.01} rx={sz*0.06} ry={sz*0.025} fill="rgba(194,24,91,.35)"/>;
      default:
        return <path d={`M${mouthX-sz*0.1} ${mouthY} Q${mouthX} ${mouthY+sz*0.07} ${mouthX+sz*0.1} ${mouthY}`} stroke="#c2185b" strokeWidth={sz*0.04} fill="none" strokeLinecap="round"/>;
    }
  };
  const cheekOpacity = ["malu","senang","excited","playful"].includes(mood) ? 0.55 : 0.3;
  const renderOutfit = () => {
    if (outfit==="apron") return (<>
      <rect x={cx-sz*0.3} y={bodyY-sz*0.18} width={sz*0.6} height={sz*0.28} rx={sz*0.14} fill={bodyColor}/>
      <rect x={cx-sz*0.32} y={bodyY-sz*0.1} width={sz*0.64} height={sz*0.52} rx={sz*0.16} fill={skirtColor} opacity="0.92"/>
      <rect x={cx-sz*0.18} y={bodyY-sz*0.12} width={sz*0.36} height={sz*0.5} rx={sz*0.08} fill="rgba(255,255,255,.82)"/>
      <path d={`M${cx-sz*0.06} ${bodyY-sz*0.14} L${cx-sz*0.06} ${bodyY-sz*0.28} L${cx+sz*0.06} ${bodyY-sz*0.28} L${cx+sz*0.06} ${bodyY-sz*0.14}`} stroke="rgba(255,255,255,.7)" strokeWidth={sz*0.03} fill="none"/>
      <path d={`M${cx-sz*0.32} ${bodyY+sz*0.32} Q${cx-sz*0.5} ${bodyY+sz*0.62} ${cx-sz*0.28} ${bodyY+sz*0.72} Q${cx} ${bodyY+sz*0.78} ${cx+sz*0.28} ${bodyY+sz*0.72} Q${cx+sz*0.5} ${bodyY+sz*0.62} ${cx+sz*0.32} ${bodyY+sz*0.32} Z`} fill={skirtColor} opacity="0.88"/>
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.62} ${bodyY+sz*0.12} ${cx-sz*0.52} ${bodyY+sz*0.38}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.62} ${bodyY+sz*0.12} ${cx+sz*0.52} ${bodyY+sz*0.38}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
    </>);
    if (outfit==="pajama") return (<>
      <rect x={cx-sz*0.3} y={bodyY-sz*0.18} width={sz*0.6} height={sz*0.28} rx={sz*0.14} fill={skirtColor}/>
      <rect x={cx-sz*0.32} y={bodyY-sz*0.1} width={sz*0.64} height={sz*0.7} rx={sz*0.16} fill={skirtColor} opacity="0.88"/>
      <path d={`M${cx-sz*0.08} ${bodyY-sz*0.18} L${cx-sz*0.08} ${bodyY+sz*0.3}`} stroke={C.A454} strokeWidth={sz*0.03} strokeDasharray={`${sz*0.06} ${sz*0.04}`}/>
      {[0,1,2].map(i=><circle key={i} cx={cx} cy={bodyY-sz*0.08+i*sz*0.15} r={sz*0.025} fill="rgba(255,255,255,.5)"/>)}
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.62} ${bodyY+sz*0.12} ${cx-sz*0.52} ${bodyY+sz*0.55}`} stroke={skirtColor} strokeWidth={sz*0.2} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.62} ${bodyY+sz*0.12} ${cx+sz*0.52} ${bodyY+sz*0.55}`} stroke={skirtColor} strokeWidth={sz*0.2} fill="none" strokeLinecap="round"/>
      <rect x={cx-sz*0.16} y={bodyY+sz*0.62} width={sz*0.14} height={sz*0.52} rx={sz*0.07} fill={skirtColor} opacity="0.9"/>
      <rect x={cx+sz*0.02} y={bodyY+sz*0.62} width={sz*0.14} height={sz*0.52} rx={sz*0.07} fill={skirtColor} opacity="0.9"/>
    </>);
    if (outfit==="swimsuit") return (<>
      <rect x={cx-sz*0.26} y={bodyY-sz*0.18} width={sz*0.52} height={sz*0.38} rx={sz*0.13} fill={skirtColor}/>
      <path d={`M${cx-sz*0.26} ${bodyY+sz*0.14} Q${cx-sz*0.3} ${bodyY+sz*0.38} ${cx-sz*0.2} ${bodyY+sz*0.46} L${cx-sz*0.04} ${bodyY+sz*0.2} Z`} fill={skirtColor} opacity="0.9"/>
      <path d={`M${cx+sz*0.26} ${bodyY+sz*0.14} Q${cx+sz*0.3} ${bodyY+sz*0.38} ${cx+sz*0.2} ${bodyY+sz*0.46} L${cx+sz*0.04} ${bodyY+sz*0.2} Z`} fill={skirtColor} opacity="0.9"/>
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.58} ${bodyY+sz*0.1} ${cx-sz*0.5} ${bodyY+sz*0.32}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.58} ${bodyY+sz*0.1} ${cx+sz*0.5} ${bodyY+sz*0.32}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx-sz*0.04} ${bodyY+sz*0.2} L${cx-sz*0.06} ${bodyY+sz*0.7}`} stroke={bodyColor} strokeWidth={sz*0.17} strokeLinecap="round"/>
      <path d={`M${cx+sz*0.04} ${bodyY+sz*0.2} L${cx+sz*0.06} ${bodyY+sz*0.7}`} stroke={bodyColor} strokeWidth={sz*0.17} strokeLinecap="round"/>
    </>);
    if (outfit==="towel") return (<>
      <rect x={cx-sz*0.3} y={bodyY-sz*0.22} width={sz*0.6} height={sz*0.72} rx={sz*0.12} fill="rgba(255,255,255,.88)" stroke="rgba(0,188,212,.3)" strokeWidth={sz*0.02}/>
      <path d={`M${cx-sz*0.06} ${bodyY-sz*0.22} Q${cx} ${bodyY-sz*0.12} ${cx+sz*0.06} ${bodyY-sz*0.22}`} stroke="rgba(0,188,212,.5)" strokeWidth={sz*0.03} fill="none"/>
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.55} ${bodyY+sz*0.05} ${cx-sz*0.46} ${bodyY+sz*0.25}`} stroke="rgba(255,255,255,.88)" strokeWidth={sz*0.16} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.55} ${bodyY+sz*0.05} ${cx+sz*0.46} ${bodyY+sz*0.25}`} stroke="rgba(255,255,255,.88)" strokeWidth={sz*0.16} fill="none" strokeLinecap="round"/>
      <path d={`M${cx-sz*0.04} ${bodyY+sz*0.46} L${cx-sz*0.05} ${bodyY+sz*0.82}`} stroke={bodyColor} strokeWidth={sz*0.16} strokeLinecap="round"/>
      <path d={`M${cx+sz*0.04} ${bodyY+sz*0.46} L${cx+sz*0.05} ${bodyY+sz*0.82}`} stroke={bodyColor} strokeWidth={sz*0.16} strokeLinecap="round"/>
    </>);
    if (outfit==="cafe") return (<>
      <rect x={cx-sz*0.3} y={bodyY-sz*0.18} width={sz*0.6} height={sz*0.28} rx={sz*0.14} fill="#fff8f0"/>
      <rect x={cx-sz*0.32} y={bodyY-sz*0.1} width={sz*0.64} height={sz*0.52} rx={sz*0.16} fill="#3e2723" opacity="0.85"/>
      <rect x={cx-sz*0.22} y={bodyY-sz*0.14} width={sz*0.44} height={sz*0.52} rx={sz*0.08} fill="#fff8f0" opacity="0.88"/>
      <path d={`M${cx-sz*0.08} ${bodyY-sz*0.14} L${cx-sz*0.08} ${bodyY+sz*0.3}`} stroke="#3e2723" strokeWidth={sz*0.025} opacity="0.4"/>
      <path d={`M${cx+sz*0.08} ${bodyY-sz*0.14} L${cx+sz*0.08} ${bodyY+sz*0.3}`} stroke="#3e2723" strokeWidth={sz*0.025} opacity="0.4"/>
      <path d={`M${cx-sz*0.32} ${bodyY+sz*0.32} Q${cx-sz*0.5} ${bodyY+sz*0.62} ${cx-sz*0.28} ${bodyY+sz*0.72} Q${cx} ${bodyY+sz*0.78} ${cx+sz*0.28} ${bodyY+sz*0.72} Q${cx+sz*0.5} ${bodyY+sz*0.62} ${cx+sz*0.32} ${bodyY+sz*0.32} Z`} fill="#3e2723" opacity="0.82"/>
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.62} ${bodyY+sz*0.12} ${cx-sz*0.52} ${bodyY+sz*0.38}`} stroke="#fff8f0" strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.62} ${bodyY+sz*0.12} ${cx+sz*0.52} ${bodyY+sz*0.38}`} stroke="#fff8f0" strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
    </>);
    return (<>
      <rect x={cx-sz*0.32} y={bodyY-sz*0.1} width={sz*0.64} height={sz*0.52} rx={sz*0.16} fill={skirtColor} opacity="0.92"/>
      <rect x={cx-sz*0.3} y={bodyY-sz*0.18} width={sz*0.6} height={sz*0.28} rx={sz*0.14} fill={bodyColor}/>
      <path d={`M${cx-sz*0.3} ${bodyY-sz*0.1} Q${cx-sz*0.62} ${bodyY+sz*0.12} ${cx-sz*0.52} ${bodyY+sz*0.38}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.3} ${bodyY-sz*0.1} Q${cx+sz*0.62} ${bodyY+sz*0.12} ${cx+sz*0.52} ${bodyY+sz*0.38}`} stroke={bodyColor} strokeWidth={sz*0.18} fill="none" strokeLinecap="round"/>
      <path d={`M${cx-sz*0.32} ${bodyY+sz*0.32} Q${cx-sz*0.5} ${bodyY+sz*0.62} ${cx-sz*0.28} ${bodyY+sz*0.72} Q${cx} ${bodyY+sz*0.78} ${cx+sz*0.28} ${bodyY+sz*0.72} Q${cx+sz*0.5} ${bodyY+sz*0.62} ${cx+sz*0.32} ${bodyY+sz*0.32} Z`} fill={skirtColor} opacity="0.88"/>
    </>);
  };
  // Body lean pivot transform
  const leanDeg = bodyLean * (180 / Math.PI);
  return (
    <g transform={`rotate(${leanDeg} ${cx} ${cy+sz*0.2})`}>
      {/* Shadow */}
      <ellipse cx={cx} cy={cy+sz*0.55} rx={sz*0.9} ry={sz*0.28} fill="rgba(244,143,177,.15)"/>

      {/* Animated arms drawn BEHIND body */}
      <path d={`M${cx-sz*0.28} ${bodyY-sz*0.05} Q${lArmCx} ${lArmCy} ${lArm.x} ${lArm.y}`}
        stroke={bodyColor} strokeWidth={sz*0.17} fill="none" strokeLinecap="round"/>
      <path d={`M${cx+sz*0.28} ${bodyY-sz*0.05} Q${rArmCx} ${rArmCy} ${rArm.x} ${rArm.y}`}
        stroke={bodyColor} strokeWidth={sz*0.17} fill="none" strokeLinecap="round"/>

      {/* Hair back */}
      <ellipse cx={headX} cy={headY+sz*0.08} rx={sz*0.52} ry={sz*0.62} fill={hairColor}/>
      <path d={`M${headX-sz*0.46} ${headY+sz*0.1} Q${headX-sz*0.62} ${headY+sz*0.5} ${headX-sz*0.44} ${headY+sz*0.9}`} stroke={hairColor} strokeWidth={sz*0.14} fill="none" strokeLinecap="round"/>
      <path d={`M${headX+sz*0.46} ${headY+sz*0.1} Q${headX+sz*0.62} ${headY+sz*0.5} ${headX+sz*0.44} ${headY+sz*0.9}`} stroke={hairColor} strokeWidth={sz*0.14} fill="none" strokeLinecap="round"/>

      {/* Neck */}
      <rect x={cx-sz*0.1} y={headY+sz*0.68} width={sz*0.2} height={sz*0.22} rx={sz*0.06} fill={bodyColor}/>

      {/* Body/outfit */}
      {renderOutfit()}

      {/* Feet */}
      {!hideFeet&&outfit!=="pajama"&&outfit!=="swimsuit"&&<>
        <path d={`M${cx-sz*0.14} ${bodyY+sz*0.7} L${cx-sz*0.12} ${bodyY+sz*1.05}`} stroke={bodyColor} strokeWidth={sz*0.16} strokeLinecap="round"/>
        <path d={`M${cx+sz*0.14} ${bodyY+sz*0.7} L${cx+sz*0.12} ${bodyY+sz*1.05}`} stroke={bodyColor} strokeWidth={sz*0.16} strokeLinecap="round"/>
        <ellipse cx={cx-sz*0.13} cy={bodyY+sz*1.09} rx={sz*0.14} ry={sz*0.07} fill={shoeC}/>
        <ellipse cx={cx+sz*0.13} cy={bodyY+sz*1.09} rx={sz*0.14} ry={sz*0.07} fill={shoeC}/>
      </>}
      {!hideFeet&&outfit==="pajama"&&<>
        <ellipse cx={cx-sz*0.16} cy={bodyY+sz*1.14} rx={sz*0.13} ry={sz*0.065} fill={skirtColor} opacity="0.7"/>
        <ellipse cx={cx+sz*0.02} cy={bodyY+sz*1.14} rx={sz*0.13} ry={sz*0.065} fill={skirtColor} opacity="0.7"/>
      </>}

      {/* Face */}
      <ellipse cx={headX} cy={headY+sz*0.3} rx={sz*0.36} ry={sz*0.42} fill={bodyColor}/>
      <path d={`M${headX-sz*0.38} ${headY-sz*0.1} Q${headX-sz*0.3} ${headY-sz*0.38} ${headX} ${headY-sz*0.42} Q${headX+sz*0.3} ${headY-sz*0.38} ${headX+sz*0.38} ${headY-sz*0.1}`} fill={hairColor}/>
      <path d={`M${headX-sz*0.38} ${headY-sz*0.1} Q${headX-sz*0.44} ${headY+sz*0.04} ${headX-sz*0.34} ${headY+sz*0.12}`} fill={hairColor}/>
      <path d={`M${headX+sz*0.38} ${headY-sz*0.1} Q${headX+sz*0.44} ${headY+sz*0.04} ${headX+sz*0.34} ${headY+sz*0.12}`} fill={hairColor}/>
      {moodEyes(mood)}
      <ellipse cx={headX-sz*0.26} cy={headY+sz*0.36} rx={sz*0.1} ry={sz*0.06} fill="rgba(255,130,150,.42)" opacity={cheekOpacity}/>
      <ellipse cx={headX+sz*0.26} cy={headY+sz*0.36} rx={sz*0.1} ry={sz*0.06} fill="rgba(255,130,150,.42)" opacity={cheekOpacity}/>
      {moodMouth(mood)}
      <circle cx={headX+sz*0.28} cy={headY-sz*0.08} r={sz*0.07} fill="#fb7185"/>
      <circle cx={headX+sz*0.28} cy={headY-sz*0.08} r={sz*0.04} fill="#fce4ec"/>
      {extra && <text x={headX+sz*0.44} y={headY-sz*0.28} fontSize={sz*0.38} textAnchor="middle">{extra}</text>}
    </g>
  );
}

function SvgFlower({ cx, cy, radius=8, color="#f48fb1", petals=5, centerColor="#fff176", opacity=1 }) {
  const petalPoints = Array.from({length:petals},(_,petalIndex)=>{
    const angle = (petalIndex/petals)*Math.PI*2 - Math.PI/2;
    const midAngle = ((petalIndex+0.5)/petals)*Math.PI*2 - Math.PI/2;
    return { px:cx+Math.cos(angle)*radius, py:cy+Math.sin(angle)*radius,
             mx:cx+Math.cos(midAngle)*radius*0.45, my:cy+Math.sin(midAngle)*radius*0.45 };
  });
  return (
    <g opacity={opacity}>
      {petalPoints.map((petalPoint,petalIndex)=>{
        const previousPetal = petalPoints[(petalIndex-1+petals)%petals];
        return <path key={petalIndex}
          d={`M${cx} ${cy} Q${previousPetal.mx} ${previousPetal.my} ${petalPoint.px} ${petalPoint.py} Q${petalPoint.mx} ${petalPoint.my} ${cx} ${cy}`}
          fill={color}/>;
      })}
      <circle cx={cx} cy={cy} r={radius*0.32} fill={centerColor}/>
    </g>
  );
}

