function getABtnTheme(flags, light) {
  const {wishMatch,isRitual,pending,special} = flags;
  const bg = wishMatch
  ? (light?"linear-gradient(160deg,rgba(168,85,247,.18),rgba(139,92,246,.1))":"linear-gradient(160deg,rgba(80,20,120,.5),rgba(60,10,100,.4))")
  : isRitual
  ? (light?"linear-gradient(160deg,rgba(251,191,36,.22),rgba(251,191,36,.1))":"linear-gradient(160deg,rgba(55,38,4,.85),rgba(32,22,2,.75))")
  : pending
  ? (light?"linear-gradient(160deg,rgba(200,40,80,.22),rgba(180,30,70,.12))":"linear-gradient(160deg,rgba(150,20,55,.8),rgba(110,10,45,.7))")
  : special
  ? (light?"linear-gradient(160deg,rgba(255,248,235,.95),rgba(255,244,225,.98))":"linear-gradient(160deg,rgba(42,26,4,.7),rgba(26,16,2,.6))")
  : (light?"rgba(255,252,248,.9)":"linear-gradient(160deg,rgba(20,6,26,.62),rgba(12,2,16,.54))");
  const bd = wishMatch?"rgba(168,85,247,.45)"
  :isRitual?"rgba(251,191,36,.45)"
  :pending?(light?"rgba(200,50,90,.32)":"rgba(251,113,133,.6)")
  :special?(light?"rgba(180,140,20,.2)":"rgba(200,160,30,.3)")
  :(light?C.AF80:C.A1F5);
  const tc = light
  ? pending?"#c62851":special?"#7a5800":wishMatch?"#6d28d9":isRitual?"#92400e":"rgba(55,18,35,.82)"
  : pending?"var(--yui-accent-color)":special?"var(--yui-gold-color)":wishMatch?"#c084fc":isRitual?"var(--yui-gold-color)":"rgba(253,232,236,.8)";
  const glow = isRitual?"0 0 14px rgba(251,191,36,.2),inset 0 1px 0 rgba(251,191,36,.1)"
  :wishMatch?"0 0 14px rgba(168,85,247,.22),inset 0 1px 0 rgba(255,255,255,.07)"
  :pending?(light?"0 4px 12px rgba(180,80,100,.22)":"0 0 16px rgba(251,113,133,.22)")
  :(light?"0 2px 8px rgba(140,80,80,.07)":"0 1px 5px rgba(0,0,0,.35)");
  return {bg, bd, tc, glow};
}

function ABtn({icon,label,onClick,disabled,special=false,pending,light=false,wishMatch=false,accentColor="var(--yui-accent-color)",ritualDot="",isRitual=false}) {
  const ref=useRef(null);
  const [pressed,setPressed]=React.useState(false);

  const {bg,bd,tc,glow} = getABtnTheme({wishMatch,isRitual,pending,special}, light);

  return (
    <button ref={ref}
      onClick={()=>{if(!disabled){setPressed(true);setTimeout(()=>setPressed(false),120);onClick(ref.current);}}}
      disabled={disabled}
      style={{
        display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:"5px",
        padding:"10px 6px 9px",borderRadius:"18px",minHeight:"72px",width:"100%",
        border:`1px solid ${bd}`,background:bg,boxShadow:glow,
        transform:pressed?"scale(0.88)":pending?"scale(0.94)":"scale(1)",
        transition:"transform .1s cubic-bezier(.16,1,.3,1), opacity .12s, box-shadow .2s",
        opacity:disabled?0.28:1,cursor:disabled?"default":"pointer",
        touchAction:"manipulation",WebkitTapHighlightColor:"transparent",
        boxSizing:"border-box",position:"relative",
        backdropFilter:pending||wishMatch?"blur(2px)":"none",
      }}>
      {wishMatch&&<span style={{position:"absolute",top:"4px",right:"5px",fontSize:"7px",opacity:0.95,filter:"drop-shadow(0 0 3px rgba(168,85,247,.5))"}}>⭐</span>}
      {ritualDot&&<span style={{position:"absolute",top:"4px",left:"5px",fontSize:"6.5px",color:"rgba(251,191,36,.85)",letterSpacing:"-1px",lineHeight:1}}>{ritualDot}</span>}
      {pending&&<div style={{position:"absolute",inset:0,borderRadius:"16px",background:"rgba(251,113,133,.03)",animation:"tl_breathe 1.8s ease-in-out infinite",pointerEvents:"none"}}/>}
      <span style={{fontSize:"26px",lineHeight:1,display:"block",
        filter:isRitual?"drop-shadow(0 0 5px rgba(251,191,36,.35))":wishMatch?"drop-shadow(0 0 5px rgba(168,85,247,.35))":pending?"drop-shadow(0 0 4px rgba(251,113,133,.3))":"none",
        transition:"transform .1s",transform:pressed?"scale(0.85)":"scale(1)"}}>{icon}</span>
      <span style={{fontSize:"11px",lineHeight:"1.3",textAlign:"center",color:tc,
        letterSpacing:"0.01em",wordBreak:"break-word",padding:"0 4px",maxWidth:"100%",fontWeight:500}}>{label}</span>
    </button>
  );
}

