function rollRivalEvent(day, lastRivalDay, mood) {
  if (day - (lastRivalDay||0) < 5) return null;
  if (Math.random() > 0.25) return null;
  const badMoods = ["marah","cemas","bimbang"];
  const pool = badMoods.includes(mood) ? RIVAL_EVENTS : RIVAL_EVENTS.slice(0,2);
  return pool[Math.floor(Math.random()*pool.length)];
}

