function rollPlaylist(mood) {
  const moodMap={senang:"manis",sedih:"melankoli",rindu:"rindu",tenang:"tenang",marah:"melankoli",cemas:"melankoli",romantis:"manis",bimbang:"melankoli",bermain:"manis",lelah:"tenang",malu:"manis",kangen:"rindu",mengantuk:"tenang",playful:"manis"};
  const target=moodMap[mood]||"manis";
  const pool=PLAYLIST_POOL.filter(s=>s.mood===target);
  const shuffled=[...pool].sort(()=>Math.random()-0.5);
  return shuffled.slice(0,6);
}

