    tab:       "rgba(255,250,242,.82)",
    tabBorder: "rgba(200,160,130,.2)",
    tabActive: "rgba(180,60,80,.82)",
    tabActiveText: "#fff",
    tabText:   "rgba(80,40,30,.65)",
    fab:       "rgba(255,252,245,.88)",
    fabActive: "rgba(180,60,80,.9)",
    fabBorder: "rgba(200,160,130,.22)",
    fabText:   "rgba(80,40,30,.5)",
    card:      "rgba(255,252,248,.85)",
