  // ── SWIPE FROM TOP TO OPEN MENU ──────────────────────────────────
  const _swipeRef = useRef({active:false, startY:0, startX:0});
  const _handleSwipeTouchStart = useCallback((e) => {
    const t = e.touches[0];
    if (t.clientY > 48) return;
    _swipeRef.current = { active:true, startY:t.clientY, startX:t.clientX };
  }, []);
  const _handleSwipeTouchEnd = useCallback((e) => {
    if (!_swipeRef.current.active) return;
    _swipeRef.current.active = false;
    const t = e.changedTouches[0];
    const dy = t.clientY - _swipeRef.current.startY;
    const dx = Math.abs(t.clientX - _swipeRef.current.startX);
    if (dy > 52 && dx < 60) setShowMoreMenu(true);
  }, [setShowMoreMenu]);

