const _ST_NODE_MAP = Object.fromEntries(_ST_NODES.map(n=>[n.id,n]));
const _ST_STARS = Array.from({length:48},(_,i)=>({
  x:((i*173.1+50)%820)+40,y:((i*97.3+30)%560)+20,
  r:0.3+(i%4)*0.35, delay:(i*0.37)%4, dur:2+(i%3)*1.2
}));
function _stBez(x1,y1,x2,y2){
  const mx=(x1+x2)/2,my=(y1+y2)/2,dx=x2-x1,dy=y2-y1;
  const len=Math.sqrt(dx*dx+dy*dy),bend=Math.min(len*0.35,55);
  const px=-dy/len*bend,py=dx/len*bend;
  return `M${x1},${y1} C${mx+px},${my+py} ${mx+px},${my+py} ${x2},${y2}`;
}


